    // ── Zero-rooms gate: check for rooms before loading portal ─────────────────
    (async function checkZeroRoomsGate() {
      try {
        var rooms = await fetchRoomList(true);
        // Only show the "Create Your First Room" gate when the church truly has
        // zero rooms (using the unfiltered total from the API), not when a TD user
        // simply has no rooms assigned to them.
        var churchHasZeroRooms = _totalRoomCount === 0 || (rooms.length === 0 && _totalRoomCount === -1);
        if (churchHasZeroRooms && rooms._fetched) {
          var gate = document.getElementById('zero-rooms-gate');
          if (gate) gate.style.display = 'flex';
          return; // Don't load overview until a room is created
        }
        // Auto-select first room if none in URL
        if (!_selectedRoomId && rooms.length > 0) {
          _selectedRoomId = rooms[0].id;
        }
      } catch { /* fall through to load overview anyway */ }
      loadOverview();
      startOverviewPoll();
    })();
    loadBilling(); // populates billing banner on all pages

    // ── Live Rundown ────────────────────────────────────────────────────────────
    var _rundownState = null; // state for the currently-viewed room session
    var _rundownStatsByRoom = {}; // { roomId: state } — all active live sessions
    // Cache of companion actions keyed by itemId, loaded when plan is known
    var _companionActionsCache = {}; // { [itemId]: Action[] }
    var _companionActionsPlanId = null; // planId for which cache was loaded
    var _rundownPlans = [];
    var _rundownLoadError = null;
    var _rundownSelectedPlanId = null;
    var _rundownSelectedPlan = null;
    var _rundownLiveTracking = true; // auto-scroll to active cue in editor during live mode
    var _rundownFilterRoom = '';
    var _rundownFilterStatus = '';
    var _rundownSortBy = 'date';
    var _rundownSearchQuery = '';
    var _rundownSessionStorageKey = 'tally.rundown.stationKey.' + CHURCH_ID;
    var _rundownStationNameStorageKey = 'tally.rundown.stationName.' + CHURCH_ID;
    var _rundownSessionId = null;
    var _rundownPresenceDisplayName = '';
    var _rundownPresenceEditors = [];
    var _rundownCollaboratorRoster = [];
    var _rundownPresenceHeartbeatTimer = null;
    var _rundownPresenceHeartbeatMs = 30000;
    var _rundownPresenceStaleAfterMs = 5 * 60 * 1000;
    var _rundownRoomMap = {}; // roomId → roomName
    // Custom columns state
    var _rundownColumns = [];    // [{ id, name, department, sortOrder, type, options }]
    var _rundownColumnValues = {}; // { itemId_colId: value }
    var _rundownTimingCache = null; // { items, timingData }
    // Attachments state — keyed by itemId
    var _rundownAttachments = {}; // { itemId: [{ id, filename, mimetype, size }] }
    // Phase 9: edit locks, rehearsal, revision history
    var _rundownEditLocks = {}; // { itemId: { sessionId, displayName, lockedAt } }
    var _rundownActiveRehearsalRun = null; // { id, planId, runNumber, startedAt, itemTimings }
    var _rundownRehearsalItemStart = null; // timestamp when current rehearsal item started
    var _rundownRehearsalCurrentIndex = 0;
    var _rundownRehearsalTimings = []; // [{ itemId, title, plannedDuration, actualDuration }]
    var _rundownUndoStack = []; // Phase 11: undo stack (max 20 entries) — { type, desc, undo(), redo() }
    var _rundownRedoStack = []; // Phase 11: redo stack
    var _rundownChecklistData = {}; // { itemId: [{ id, label, checked, ... }] }
    var _rundownSelectedItemId = null; // Highlighted row for keyboard navigation
    var _rundownChecklistExpanded = {}; // { itemId: true } — expanded checklist panels

    // ── Status display config ────────────────────────────────────────────────
    var RUNDOWN_STATUS_LABELS = { draft: 'Draft', rehearsal: 'Rehearsal', show_ready: 'Ready', live: 'Live', archived: 'Archived' };
    var RUNDOWN_STATUS_TOOLTIPS = {
      draft: 'Draft — still being built, not shared yet',
      rehearsal: 'Rehearsal — ready for team walk-through',
      show_ready: 'Ready — finalized and waiting for service',
      live: 'Live — currently running during service',
      archived: 'Archived — service completed, kept for reference'
    };
    var RUNDOWN_STATUS_ORDER = ['live', 'show_ready', 'rehearsal', 'draft', 'archived'];
    var RUNDOWN_PRESENCE_COLORS = ['#FF6B6B','#4ECDC4','#45B7D1','#96CEB4','#FFEAA7','#DDA0DD','#98D8C8','#F7DC6F'];
    var RUNDOWN_COLUMN_TYPE_LABELS = { text: 'Text', dropdown: 'Dropdown' };
    var RUNDOWN_COLUMN_BINDING_LABELS = {
      'atem.program_input': 'ATEM Program',
      'atem.preview_input': 'ATEM Preview',
      'propresenter.presentation': 'ProPresenter',
      'encoder.status': 'Encoder Status',
      'stream.live': 'Stream Live',
    };

    function _rundownStorageGet(key) {
      try {
        return window.localStorage ? window.localStorage.getItem(key) : null;
      } catch (e) {
        return null;
      }
    }

    function _rundownStorageSet(key, value) {
      try {
        if (!window.localStorage) return;
        if (value) window.localStorage.setItem(key, value);
        else window.localStorage.removeItem(key);
      } catch (e) {}
    }

    function _rundownDefaultStationName() {
      var tdName = window._tdSession && window._tdSession.name ? String(window._tdSession.name).trim() : '';
      return tdName || 'TD Station';
    }

    function _rundownNormalizeStationKey(value) {
      var normalized = String(value || '')
        .trim()
        .toLowerCase()
        .replace(/[^a-z0-9._-]+/g, '-')
        .replace(/^-+|-+$/g, '')
        .slice(0, 48);
      return normalized;
    }

    function _rundownEnsureStationIdentity() {
      if (_rundownSessionId && _rundownPresenceDisplayName) return;
      var storedKey = _rundownNormalizeStationKey(_rundownStorageGet(_rundownSessionStorageKey));
      var storedName = String(_rundownStorageGet(_rundownStationNameStorageKey) || '').trim();
      if (!storedKey) storedKey = 'rd-' + Math.random().toString(36).slice(2, 10);
      if (!storedName) storedName = _rundownDefaultStationName();
      _rundownSessionId = storedKey;
      _rundownPresenceDisplayName = storedName;
      _rundownStorageSet(_rundownSessionStorageKey, storedKey);
      _rundownStorageSet(_rundownStationNameStorageKey, storedName);
    }

    _rundownEnsureStationIdentity();

    function _normalizeRundownColumnType(type) {
      return type === 'dropdown' ? 'dropdown' : 'text';
    }

    function _getRundownColumnOptions(column) {
      return Array.isArray(column && column.options)
        ? column.options.map(function(opt) { return String(opt || '').trim(); }).filter(Boolean)
        : [];
    }

    function _normalizeRundownCompareValue(value) {
      return String(value || '')
        .toLowerCase()
        .replace(/&nbsp;/g, ' ')
        .replace(/[^a-z0-9]+/g, ' ')
        .trim();
    }

    function loadRundownPage() {
      // Fetch all active sessions, then show the one for the selected room
      console.log('[rundown] loadRundownPage, CHURCH_ID:', CHURCH_ID);
      api('GET', '/api/churches/' + CHURCH_ID + '/live-rundown/state?all=1').then(function(data) {
        _rundownStatsByRoom = {};
        if (data && data.sessions && data.sessions.length > 0) {
          for (var i = 0; i < data.sessions.length; i++) {
            var entry = data.sessions[i];
            _rundownStatsByRoom[entry.roomId || ''] = entry.state;
          }
        }
        // Show session for the current room (or default '')
        var roomKey = _selectedRoomId || '';
        var roomState = _rundownStatsByRoom[roomKey] || null;
        if (roomState) {
          _rundownState = roomState;
          if (roomState.planId && roomState.planId !== _companionActionsPlanId) {
            loadCompanionActionsCache(roomState.planId);
          }
          showRundownView('active');
          renderRundownActive(roomState);
        } else {
          _rundownState = null;
          loadRundownManager();
        }
      }).catch(function() {
        _rundownState = null;
        _rundownStatsByRoom = {};
        loadRundownManager();
      });
    }

    function showRundownView(view) {
      var manager = document.getElementById('rundown-manager');
      var active = document.getElementById('rundown-active');
      var noSession = document.getElementById('rundown-no-session');
      var delta = document.getElementById('rundown-schedule-delta');
      var newBtn = document.getElementById('btn-rundown-new');
      var importBtn = document.getElementById('btn-rundown-import');
      var templatesModal = document.getElementById('rundown-templates-modal');
      var editor = document.getElementById('rundown-editor');
      var pageHeader = document.querySelector('#page-rundown > .page-header');
      if (manager) manager.style.display = 'none';
      if (active) active.style.display = 'none';
      if (noSession) noSession.style.display = 'none';
      if (delta) delta.style.display = 'none';
      if (newBtn) newBtn.style.display = 'none';
      if (importBtn) importBtn.style.display = 'none';
      if (templatesModal) templatesModal.style.display = 'none';
      if (editor) editor.style.display = 'none';
      if (view === 'active') {
        if (active) active.style.display = '';
        if (pageHeader) pageHeader.style.display = '';
      } else if (view === 'manager') {
        if (manager) manager.style.display = '';
        if (newBtn) newBtn.style.display = '';
        if (importBtn) importBtn.style.display = 'inline-flex';
        if (pageHeader) pageHeader.style.display = '';
      } else if (view === 'templates') {
        if (templatesModal) templatesModal.style.display = '';
        if (newBtn) newBtn.style.display = '';
        if (pageHeader) pageHeader.style.display = '';
      } else if (view === 'editor') {
        if (editor) editor.style.display = '';
        if (pageHeader) pageHeader.style.display = 'none';
      }
    }

    // ── Full-screen editor navigation ─────────────────────────────────────────
    function rundownBackToDashboard() {
      // Close team sidebar if open
      var sidebar = document.getElementById('rundown-team-sidebar');
      if (sidebar) sidebar.style.display = 'none';
      // Unsubscribe from editing session
      if (_rundownSubscribedPlanId) {
        _rundownUnsubscribePlan(_rundownSubscribedPlanId);
      }
      _rundownSelectedPlanId = null;
      _rundownSelectedPlan = null;
      _rundownCloseCollaborators();
      // Update hash without triggering popstate
      _rundownSkipHashChange = true;
      history.pushState({ rundownView: 'dashboard' }, '', window.location.pathname + window.location.search + '#rundown');
      _rundownSkipHashChange = false;
      loadRundownManager();
    }

    var _rundownSkipHashChange = false;

    function _rundownOpenEditorHash(planId) {
      _rundownSkipHashChange = true;
      history.pushState({ rundownView: 'editor', planId: planId }, '', window.location.pathname + window.location.search + '#rundown-plan-' + planId);
      _rundownSkipHashChange = false;
    }

    // Handle browser back/forward for editor state
    window.addEventListener('popstate', function(e) {
      if (_rundownSkipHashChange) return;
      var hash = window.location.hash;
      if (hash && hash.indexOf('#rundown-plan-') === 0) {
        var planId = hash.replace('#rundown-plan-', '');
        if (planId && planId !== _rundownSelectedPlanId) {
          rundownSelectPlan(planId, 'manual');
        }
      } else if (hash === '#rundown' || (e.state && e.state.rundownView === 'dashboard')) {
        if (_rundownSelectedPlanId) {
          rundownBackToDashboard();
        }
      }
    });

    // On page load, check hash for restoring editor state
    function _rundownCheckHashOnLoad() {
      var hash = window.location.hash;
      if (hash && hash.indexOf('#rundown-plan-') === 0) {
        var planId = hash.replace('#rundown-plan-', '');
        if (planId) {
          // Navigate to rundown page and open editor
          var navBtn = document.querySelector('[data-page="rundown"]');
          if (navBtn) showPage('rundown', navBtn);
          setTimeout(function() { rundownSelectPlan(planId, 'manual'); }, 200);
          return true;
        }
      }
      return false;
    }

    // ── Team panel toggle ─────────────────────────────────────────────────────
    function rundownToggleTeamPanel() {
      var sidebar = document.getElementById('rundown-team-sidebar');
      if (!sidebar) return;
      if (sidebar.style.display === 'none' || !sidebar.style.display) {
        sidebar.style.display = '';
        _rundownRenderTeamMembers();
      } else {
        sidebar.style.display = 'none';
      }
    }

    function _rundownRenderTeamMembers() {
      var container = document.getElementById('rundown-team-members');
      if (!container) return;
      var merged = _rundownMergedCollaborators();
      if (!merged.length) {
        container.innerHTML = '<div style="padding:12px;font-size:12px;color:#556270;text-align:center">No team members yet</div>';
        return;
      }
      var html = '';
      merged.forEach(function(entry, index) {
        var key = entry.collaboratorKey || '';
        var name = entry.displayName || key || 'Unnamed';
        var isSelf = key === _rundownSessionId;
        var role = entry.role || 'editor';
        var status = entry.status || 'offline';
        var isOnline = status === 'active';
        var initials = name.split(' ').map(function(part) { return part[0] || ''; }).join('').slice(0, 2).toUpperCase() || 'TD';
        var bgColor = RUNDOWN_PRESENCE_COLORS[index % RUNDOWN_PRESENCE_COLORS.length];
        var roleLabel = role === 'owner' ? 'Owner' : role === 'viewer' ? 'Viewer' : 'Editor';
        html += '<div class="rundown-team-member">';
        html += '<div class="rundown-team-member-avatar" style="background:' + bgColor + '">' + escapeHtml(initials);
        html += '<span class="' + (isOnline ? 'online-dot' : 'offline-dot') + '"></span>';
        html += '</div>';
        html += '<div class="rundown-team-member-info">';
        html += '<div class="rundown-team-member-name">' + escapeHtml(name) + (isSelf ? ' (you)' : '') + '</div>';
        html += '<div class="rundown-team-member-role">' + roleLabel + '</div>';
        html += '</div>';
        html += '</div>';
      });
      container.innerHTML = html;
    }

    // Attach filter/sort event listeners (once)
    (function() {
      var searchEl = document.getElementById('rundown-search');
      if (searchEl) searchEl.addEventListener('input', function() { rundownSearchInput(); });
      var roomEl = document.getElementById('rundown-filter-room');
      if (roomEl) roomEl.addEventListener('change', function() { rundownFilterChange(); });
      var statusEl = document.getElementById('rundown-filter-status');
      if (statusEl) statusEl.addEventListener('change', function() { rundownFilterChange(); });
      var sortEl = document.getElementById('rundown-sort');
      if (sortEl) sortEl.addEventListener('change', function() { rundownSortChange(); });
      var statusSel = document.getElementById('rundown-editor-status-select');
      if (statusSel) statusSel.addEventListener('change', function() { rundownChangeStatus(); });
    })();

    function loadRundownManager() {
      showRundownView('manager');
      // Unsubscribe from any editing session when returning to dashboard
      if (_rundownSubscribedPlanId) {
        _rundownUnsubscribePlan(_rundownSubscribedPlanId);
      }
      _rundownCloseCollaborators();
      // Close team sidebar if open
      var teamSidebar = document.getElementById('rundown-team-sidebar');
      if (teamSidebar) teamSidebar.style.display = 'none';
      // Load rooms for filter dropdown and room name display
      fetchRoomList().then(function(rooms) {
        _rundownRoomMap = {};
        var sel = document.getElementById('rundown-filter-room');
        if (sel) {
          var val = sel.value;
          sel.innerHTML = '<option value="">All Rooms</option>';
          for (var i = 0; i < rooms.length; i++) {
            _rundownRoomMap[rooms[i].id] = rooms[i].name;
            sel.innerHTML += '<option value="' + rooms[i].id + '"' + (val === rooms[i].id ? ' selected' : '') + '>' + escapeHtml(rooms[i].name) + '</option>';
          }
        }
      });
      _rundownFetchPlans(0);
    }

    function _rundownFetchPlans(attempt) {
      console.log('[rundown] fetchPlans attempt', attempt, 'churchId:', CHURCH_ID);
      api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans').then(function(data) {
        console.log('[rundown] fetchPlans success, plans:', (data && data.plans || []).length);
        _rundownLoadError = null;
        _rundownPlans = (data && data.plans) || [];
        // 4.7: Auto-archive plans 24h past service date
        _rundownPlans.forEach(function(p) { _rundownAutoTransitionStatus(p); });
        renderRundownDashboard();
        // 4.2: Show onboarding if no plans exist
        _rundownCheckFirstRunOnboarding();
      }).catch(function(err) {
        console.error('[rundown] fetchPlans error attempt', attempt, ':', err && err.message, err);
        // Server returns 503 with retryable:true while still starting up
        if (err && err.retryable && attempt < 5) {
          var delay = Math.min(1000 * Math.pow(2, attempt), 8000);
          setTimeout(function() { _rundownFetchPlans(attempt + 1); }, delay);
          return;
        }
        _rundownPlans = [];
        _rundownLoadError = (err && err.message) || 'Failed to load rundowns';
        renderRundownDashboard();
      });
    }

    // ── 4.2 First-run onboarding flow ────────────────────────────────────────
    function _rundownCheckFirstRunOnboarding() {
      var nonTemplate = _rundownPlans.filter(function(p) { return !p.isTemplate; });
      var dismissed = localStorage.getItem('tally.rundown.onboarding.dismissed.' + CHURCH_ID);
      if (nonTemplate.length > 0 || dismissed === 'true') {
        _rundownHideOnboarding();
        return;
      }
      _rundownShowOnboarding();
    }

    function _rundownShowOnboarding() {
      var existing = document.getElementById('rundown-onboarding-overlay');
      if (existing) { existing.style.display = 'flex'; return; }
      var overlay = document.createElement('div');
      overlay.id = 'rundown-onboarding-overlay';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:9998;background:rgba(0,0,0,0.82);display:flex;align-items:center;justify-content:center;backdrop-filter:blur(6px)';
      overlay.innerHTML = '<div style="background:#0a1610;border:1px solid #0d3320;border-radius:18px;padding:36px 40px;max-width:480px;width:92%;text-align:center">'
        + '<div style="margin-bottom:16px"><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="#00E676" width="48" height="48"><path stroke-linecap="round" stroke-linejoin="round" d="M3.75 12h16.5m-16.5 3.75h16.5M3.75 19.5h16.5M5.625 4.5h12.75a1.875 1.875 0 0 1 0 3.75H5.625a1.875 1.875 0 0 1 0-3.75Z"/></svg></div>'
        + '<div style="font-size:22px;font-weight:800;color:#F0F2F4;margin-bottom:8px">Welcome to Service Plans</div>'
        + '<div style="font-size:14px;color:#8B9DAF;line-height:1.6;margin-bottom:24px">Build a plan for your service with items, timing, and team assignments. Share live views with your tech team and volunteers.</div>'
        + '<div style="display:flex;flex-direction:column;gap:10px;text-align:left;margin-bottom:28px;padding:16px;background:rgba(255,255,255,0.03);border-radius:12px;border:1px solid rgba(255,255,255,0.06)">'
        + '<div style="display:flex;align-items:flex-start;gap:10px"><span style="color:#00E676;font-weight:700;font-size:16px;line-height:1">1</span><div><div style="font-size:13px;font-weight:700;color:#F0F2F4">Create a plan</div><div style="font-size:12px;color:#8B9DAF">Give it a name, date, and optional room.</div></div></div>'
        + '<div style="display:flex;align-items:flex-start;gap:10px"><span style="color:#00E676;font-weight:700;font-size:16px;line-height:1">2</span><div><div style="font-size:13px;font-weight:700;color:#F0F2F4">Add items</div><div style="font-size:12px;color:#8B9DAF">Songs, sermons, transitions — build your service order.</div></div></div>'
        + '<div style="display:flex;align-items:flex-start;gap:10px"><span style="color:#00E676;font-weight:700;font-size:16px;line-height:1">3</span><div><div style="font-size:13px;font-weight:700;color:#F0F2F4">Share and go live</div><div style="font-size:12px;color:#8B9DAF">Copy a link for your team, then start live mode on Sunday.</div></div></div>'
        + '</div>'
        + '<div style="display:flex;gap:10px;justify-content:center">'
        + '<button id="rundown-onboarding-skip" style="background:none;border:1px solid rgba(255,255,255,0.1);color:#8B9DAF;border-radius:8px;padding:10px 20px;font-size:13px;cursor:pointer">Skip</button>'
        + '<button id="rundown-onboarding-start" style="background:#00E676;border:none;color:#060D08;border-radius:8px;padding:10px 24px;font-size:13px;font-weight:700;cursor:pointer">Create First Plan</button>'
        + '</div>'
        + '</div>';
      document.body.appendChild(overlay);
      document.getElementById('rundown-onboarding-skip').addEventListener('click', function() {
        localStorage.setItem('tally.rundown.onboarding.dismissed.' + CHURCH_ID, 'true');
        _rundownHideOnboarding();
      });
      document.getElementById('rundown-onboarding-start').addEventListener('click', function() {
        localStorage.setItem('tally.rundown.onboarding.dismissed.' + CHURCH_ID, 'true');
        _rundownHideOnboarding();
        // Trigger the new plan modal
        if (typeof rundownAddPlan === 'function') rundownAddPlan();
      });
    }

    function _rundownHideOnboarding() {
      var el = document.getElementById('rundown-onboarding-overlay');
      if (el) el.style.display = 'none';
    }

    function _rundownFilteredPlans() {
      var plans = _rundownPlans.filter(function(p) { return !p.isTemplate; });
      if (_rundownFilterRoom) plans = plans.filter(function(p) { return p.roomId === _rundownFilterRoom; });
      if (_rundownFilterStatus) plans = plans.filter(function(p) { return p.status === _rundownFilterStatus; });
      if (_rundownSearchQuery) {
        var q = _rundownSearchQuery.toLowerCase();
        plans = plans.filter(function(p) { return p.title.toLowerCase().indexOf(q) >= 0; });
      }
      // Sort
      if (_rundownSortBy === 'name') {
        plans.sort(function(a, b) { return a.title.localeCompare(b.title); });
      } else if (_rundownSortBy === 'updated') {
        plans.sort(function(a, b) { return (b.updatedAt || 0) - (a.updatedAt || 0); });
      } else {
        // date (default): upcoming first, then by created
        plans.sort(function(a, b) {
          if (a.serviceDate && b.serviceDate) return b.serviceDate.localeCompare(a.serviceDate);
          if (a.serviceDate) return -1;
          if (b.serviceDate) return 1;
          return (b.updatedAt || 0) - (a.updatedAt || 0);
        });
      }
      return plans;
    }

    function renderRundownDashboard() {
      var container = document.getElementById('rundown-dashboard');
      if (!container) return;
      var plans = _rundownFilteredPlans();

      if (plans.length === 0 && !_rundownFilterRoom && !_rundownFilterStatus && !_rundownSearchQuery) {
        // Show error banner instead of "Create First Rundown" when plans failed to load
        if (_rundownLoadError) {
          container.innerHTML = '<div style="color:#FF5252;text-align:center;padding:40px;font-size:13px">'
            + '<div style="font-size:16px;font-weight:700;margin-bottom:8px">Failed to load rundowns</div>'
            + '<div style="color:#8B9DAF;margin-bottom:16px">' + escapeHtml(_rundownLoadError) + '</div>'
            + '<button onclick="_rundownLoadError=null;_rundownFetchPlans(0)" style="background:#00E676;color:#0a1610;border:none;padding:8px 20px;border-radius:6px;cursor:pointer;font-weight:600">Retry</button>'
            + '</div>';
          return;
        }
        var emptyHtml = '<div class="rundown-empty-state">';
        emptyHtml += '<div class="rundown-empty-icon"><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" d="M3.75 12h16.5m-16.5 3.75h16.5M3.75 19.5h16.5M5.625 4.5h12.75a1.875 1.875 0 0 1 0 3.75H5.625a1.875 1.875 0 0 1 0-3.75Z"/></svg></div>';
        emptyHtml += '<div class="rundown-empty-title">Create Your First Rundown</div>';
        emptyHtml += '<div class="rundown-empty-subtitle">Build a service plan with timed items, assign team members, and run it live during your service.</div>';
        emptyHtml += '<div style="display:flex;gap:10px;justify-content:center;align-items:center;margin-bottom:16px">';
        emptyHtml += '<button class="rundown-empty-cta" data-action="rundownNew" style="margin-bottom:0"><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor"><path d="M10.75 4.75a.75.75 0 0 0-1.5 0v4.5h-4.5a.75.75 0 0 0 0 1.5h4.5v4.5a.75.75 0 0 0 1.5 0v-4.5h4.5a.75.75 0 0 0 0-1.5h-4.5v-4.5Z"/></svg> New Rundown</button>';
        emptyHtml += '<button class="rundown-empty-cta rundown-empty-cta-secondary" data-action="rundownImportFromDocument" style="margin-bottom:0"><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" width="16" height="16"><path d="M10.75 2.75a.75.75 0 0 0-1.5 0v8.614L6.295 8.235a.75.75 0 1 0-1.09 1.03l4.25 4.5a.75.75 0 0 0 1.09 0l4.25-4.5a.75.75 0 0 0-1.09-1.03l-2.955 3.129V2.75Z"/><path d="M3.5 12.75a.75.75 0 0 0-1.5 0v2.5A2.75 2.75 0 0 0 4.75 18h10.5A2.75 2.75 0 0 0 18 15.25v-2.5a.75.75 0 0 0-1.5 0v2.5c0 .69-.56 1.25-1.25 1.25H4.75c-.69 0-1.25-.56-1.25-1.25v-2.5Z"/></svg> Import from Document</button>';
        emptyHtml += '</div>';
        // Show built-in templates
        emptyHtml += '<div style="font-size:12px;font-weight:700;color:#8B9DAF;text-transform:uppercase;letter-spacing:0.8px;margin-bottom:8px">Or start from a template</div>';
        emptyHtml += '<div class="rundown-template-grid">';
        for (var ti = 0; ti < RUNDOWN_BUILTIN_TEMPLATES.length; ti++) {
          var tpl = RUNDOWN_BUILTIN_TEMPLATES[ti];
          var tplItems = tpl.items.filter(function(x) { return x.itemType !== 'section'; });
          var tplDur = tpl.items.reduce(function(s, x) { return s + (x.lengthSeconds || 0); }, 0);
          var tplDurStr = Math.floor(tplDur / 60) + 'm';
          emptyHtml += '<div class="rundown-template-card" data-action="rundownCreateFromBuiltinTemplate" data-template-index="' + ti + '">';
          emptyHtml += '<div class="rundown-template-card-title">' + escapeHtml(tpl.name) + '</div>';
          emptyHtml += '<div class="rundown-template-card-meta">' + tplItems.length + ' items · ' + tplDurStr + '</div>';
          emptyHtml += '<div class="rundown-template-card-items">';
          for (var tj = 0; tj < tpl.items.length && tj < 6; tj++) {
            var tpItem = tpl.items[tj];
            if (tpItem.itemType === 'section') continue;
            var chipBg = tpItem.color ? tpItem.color + '22' : 'rgba(255,255,255,0.06)';
            var chipColor = tpItem.color || '#8B9DAF';
            emptyHtml += '<span class="rundown-template-chip" style="background:' + chipBg + ';color:' + chipColor + '">' + escapeHtml(tpItem.title) + '</span>';
          }
          if (tplItems.length > 6) emptyHtml += '<span class="rundown-template-chip" style="background:rgba(255,255,255,0.06);color:#556270">+' + (tplItems.length - 6) + ' more</span>';
          emptyHtml += '</div></div>';
        }
        emptyHtml += '</div></div>';
        container.innerHTML = emptyHtml;
        return;
      }

      if (plans.length === 0) {
        container.innerHTML = '<div style="color:#556270;text-align:center;padding:40px;font-size:13px">No rundowns match your filters.</div>';
        return;
      }

      // Group by status
      var grouped = {};
      for (var i = 0; i < plans.length; i++) {
        var st = plans[i].status || 'draft';
        if (!grouped[st]) grouped[st] = [];
        grouped[st].push(plans[i]);
      }

      var html = '';
      for (var s = 0; s < RUNDOWN_STATUS_ORDER.length; s++) {
        var statusKey = RUNDOWN_STATUS_ORDER[s];
        var group = grouped[statusKey];
        if (!group || group.length === 0) continue;

        html += '<div class="rundown-status-group">';
        html += '<div class="rundown-status-group-header"><span class="rundown-status-badge status-' + statusKey + '">' + escapeHtml(RUNDOWN_STATUS_LABELS[statusKey]) + '</span><span class="rundown-group-count">' + group.length + '</span></div>';
        html += '<div class="rundown-card-grid">';

        for (var j = 0; j < group.length; j++) {
          var p = group[j];
          html += _renderRundownCard(p);
        }

        html += '</div></div>';
      }

      container.innerHTML = html;
    }

    function _renderRundownCard(p) {
      var roomName = p.roomId && _rundownRoomMap[p.roomId] ? _rundownRoomMap[p.roomId] : '';
      var dur = p.totalDuration || 0;
      var durStr = dur > 0 ? Math.floor(dur / 60) + 'm' : '';
      var dateStr = p.serviceDate || '';
      var updatedStr = p.updatedAt ? _rundownRelativeTime(p.updatedAt) : '';
      var liveClass = p.status === 'live' ? ' is-live' : '';
      var sourceLabel = p.source === 'pco' ? '<span style="font-size:10px;color:#42A5F5;background:rgba(66,165,245,0.1);padding:1px 5px;border-radius:3px;margin-left:4px">PCO</span>' : '';

      var html = '<div class="rundown-dash-card' + liveClass + '" data-action="rundownSelectPlan" data-plan-id="' + p.id + '" data-plan-source="' + (p.source || 'manual') + '">';
      html += '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px">';
      html += '<div class="card-title">' + escapeHtml(p.title) + sourceLabel + '</div>';
      html += '<span class="rundown-status-badge status-' + (p.status || 'draft') + '">' + escapeHtml(RUNDOWN_STATUS_LABELS[p.status] || 'Draft') + '</span>';
      html += '</div>';

      html += '<div class="card-meta">';
      if (dateStr) html += '<span>' + escapeHtml(dateStr) + '</span>';
      if (roomName) html += '<span>' + escapeHtml(roomName) + '</span>';
      html += '<span>' + p.itemCount + ' items</span>';
      if (durStr) html += '<span>' + durStr + '</span>';
      if (p.activeEditors > 0) {
        html += '<span class="rundown-editors-badge">' + SVG.users + ' ' + p.activeEditors + ' editing</span>';
      }
      html += '</div>';

      if (updatedStr) {
        html += '<div style="font-size:11px;color:#3A4556;margin-top:4px">Edited ' + escapeHtml(updatedStr) + '</div>';
      }

      // Quick actions
      if (p.source !== 'pco') {
        html += '<div class="card-actions">';
        html += '<button data-action="rundownCardEdit" data-plan-id="' + p.id + '">Edit</button>';
        html += '<button data-action="rundownCardDuplicate" data-plan-id="' + p.id + '">Duplicate</button>';
        html += '<button data-action="rundownCardStatusMenu" data-plan-id="' + p.id + '">Status</button>';
        if (p.status !== 'archived') {
          html += '<button data-action="rundownCardArchive" data-plan-id="' + p.id + '">Archive</button>';
        }
        html += '<button class="action-delete" data-action="rundownCardDelete" data-plan-id="' + p.id + '">Delete</button>';
        html += '</div>';
      }

      html += '</div>';
      return html;
    }

    function _rundownRelativeTime(ts) {
      var diff = Date.now() - ts;
      if (diff < 60000) return 'just now';
      if (diff < 3600000) return Math.floor(diff / 60000) + 'm ago';
      if (diff < 86400000) return Math.floor(diff / 3600000) + 'h ago';
      if (diff < 604800000) return Math.floor(diff / 86400000) + 'd ago';
      return new Date(ts).toLocaleDateString();
    }

    // ── Dashboard filter/sort handlers ────────────────────────────────────────
    function rundownSearchInput() {
      _rundownSearchQuery = (document.getElementById('rundown-search') || {}).value || '';
      renderRundownDashboard();
    }
    function rundownFilterChange() {
      _rundownFilterRoom = (document.getElementById('rundown-filter-room') || {}).value || '';
      _rundownFilterStatus = (document.getElementById('rundown-filter-status') || {}).value || '';
      renderRundownDashboard();
    }
    function rundownSortChange() {
      _rundownSortBy = (document.getElementById('rundown-sort') || {}).value || 'date';
      renderRundownDashboard();
    }

    // ── Card quick actions ──────────────────────────────────────────────────
    function rundownCardEdit(planId) {
      rundownSelectPlan(planId, 'manual');
    }
    function rundownCardDuplicate(planId) {
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/duplicate').then(function(plan) {
        toast('Rundown duplicated');
        loadRundownManager();
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }
    function rundownCardArchive(planId) {
      api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/status', { status: 'archived' }).then(function() {
        toast('Archived');
        loadRundownManager();
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }
    function rundownCardDelete(planId) {
      styledConfirm('Delete Rundown', 'Delete this rundown? This cannot be undone.').then(function(ok) {
        if (!ok) return;
        api('DELETE', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId).then(function() {
          toast('Rundown deleted');
          if (_rundownSelectedPlanId === planId) {
            _rundownSelectedPlan = null;
            _rundownSelectedPlanId = null;
            var editor = document.getElementById('rundown-editor');
            if (editor) editor.style.display = 'none';
          }
          loadRundownManager();
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }
    function rundownCardStatusMenu(planId) {
      var plan = _rundownPlans.find(function(p) { return p.id === planId; });
      if (!plan) return;
      var statuses = ['draft', 'rehearsal', 'show_ready', 'live', 'archived'];
      var labels = statuses.map(function(s) { return RUNDOWN_STATUS_LABELS[s]; });
      // Simple prompt-based status picker
      styledPrompt('Change Status', 'Enter status: draft, rehearsal, show_ready, live, archived', plan.status || 'draft').then(function(val) {
        if (!val || !val.trim()) return;
        val = val.trim().toLowerCase();
        if (statuses.indexOf(val) < 0) { toast('Invalid status', true); return; }
        api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/status', { status: val }).then(function() {
          toast('Status updated');
          loadRundownManager();
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    // ── Status change from editor ───────────────────────────────────────────
    function rundownChangeStatus() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      var sel = document.getElementById('rundown-editor-status-select');
      if (!sel) return;
      var newStatus = sel.value;
      api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/status', { status: newStatus }).then(function(plan) {
        _rundownSelectedPlan = plan;
        var statusBadge = document.getElementById('rundown-editor-status-badge');
        if (statusBadge) {
          statusBadge.textContent = RUNDOWN_STATUS_LABELS[plan.status] || 'Draft';
          statusBadge.className = 'rundown-status-badge status-' + plan.status;
        }
        toast('Status: ' + (RUNDOWN_STATUS_LABELS[plan.status] || plan.status));
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    // ── Presence tracking (collaborative editing) ───────────────────────────
    var _rundownSubscribedPlanId = null;

    function _rundownRoleLabel(role) {
      if (role === 'owner') return 'Owner';
      if (role === 'viewer') return 'Viewer';
      return 'Editor';
    }

    function _rundownStatusLabel(status) {
      if (status === 'revoked') return 'Revoked';
      if (status === 'offline') return 'Offline';
      return 'Active';
    }

    function _rundownActivePresenceList() {
      return (_rundownPresenceEditors || []).filter(function(entry) {
        return entry && entry.status === 'active' && !entry.isStale;
      });
    }

    function _rundownMergedCollaborators() {
      var byKey = {};
      (_rundownCollaboratorRoster || []).forEach(function(entry) {
        if (!entry || !entry.collaboratorKey) return;
        byKey[entry.collaboratorKey] = Object.assign({}, entry);
      });
      (_rundownPresenceEditors || []).forEach(function(entry) {
        if (!entry || !entry.sessionId) return;
        var key = entry.sessionId;
        var existing = byKey[key] || {};
        byKey[key] = Object.assign({}, existing, {
          collaboratorKey: key,
          displayName: entry.displayName || entry.userName || existing.displayName || '',
          role: entry.role || existing.role || 'editor',
          status: entry.status || existing.status || 'active',
          joinedAt: entry.joinedAt || existing.joinedAt || null,
          lastSeenAt: entry.lastSeenAt || existing.lastSeenAt || null,
          leftAt: entry.leftAt || existing.leftAt || null,
          isStale: !!entry.isStale,
          isLiveSession: true,
        });
      });
      return Object.keys(byKey).map(function(key) {
        return byKey[key];
      }).sort(function(a, b) {
        var roleRank = { owner: 0, editor: 1, viewer: 2 };
        var statusRank = { active: 0, offline: 1, revoked: 2 };
        var aRole = roleRank[a.role] != null ? roleRank[a.role] : 3;
        var bRole = roleRank[b.role] != null ? roleRank[b.role] : 3;
        if (aRole !== bRole) return aRole - bRole;
        var aStatus = statusRank[a.status] != null ? statusRank[a.status] : 3;
        var bStatus = statusRank[b.status] != null ? statusRank[b.status] : 3;
        if (aStatus !== bStatus) return aStatus - bStatus;
        return String(a.displayName || a.collaboratorKey || '').localeCompare(String(b.displayName || b.collaboratorKey || ''));
      });
    }

    function _rundownFindCollaborator(key) {
      var merged = _rundownMergedCollaborators();
      for (var i = 0; i < merged.length; i++) {
        if (merged[i].collaboratorKey === key) return merged[i];
      }
      return null;
    }

    function _rundownUpdateCollaboratorButtons() {
      var activeCount = _rundownActivePresenceList().length;
      document.querySelectorAll('[data-action="rundownCollaborators"]').forEach(function(btn) {
        if (!btn.dataset.defaultLabel) btn.dataset.defaultLabel = (btn.textContent || 'Team').trim();
        btn.textContent = activeCount > 1 ? btn.dataset.defaultLabel + ' (' + activeCount + ')' : btn.dataset.defaultLabel;
      });
    }

    function _rundownFillStationIdentityForm() {
      _rundownEnsureStationIdentity();
      var nameInput = document.getElementById('rundown-station-name');
      var keyInput = document.getElementById('rundown-station-key');
      var roleEl = document.getElementById('rundown-collaborators-self-role');
      var selfEntry = _rundownFindCollaborator(_rundownSessionId);
      if (nameInput) nameInput.value = _rundownPresenceDisplayName || _rundownDefaultStationName();
      if (keyInput) keyInput.value = _rundownSessionId || '';
      if (roleEl) {
        if (selfEntry) {
          roleEl.textContent = _rundownRoleLabel(selfEntry.role) + ' · ' + _rundownStatusLabel(selfEntry.status);
        } else {
          roleEl.textContent = 'Editor · Ready to join';
        }
      }
    }

    function _rundownRenderCollaboratorList() {
      var listEl = document.getElementById('rundown-collaborators-list');
      var summaryEl = document.getElementById('rundown-collaborators-summary');
      if (!listEl) return;
      var merged = _rundownMergedCollaborators();
      var activeCount = _rundownActivePresenceList().length;
      var owners = merged.filter(function(entry) { return entry.role === 'owner' && entry.status !== 'revoked'; }).length;
      var editors = merged.filter(function(entry) { return entry.role === 'editor' && entry.status !== 'revoked'; }).length;
      var viewers = merged.filter(function(entry) { return entry.role === 'viewer' && entry.status !== 'revoked'; }).length;
      if (summaryEl) {
        summaryEl.textContent = activeCount + ' active · ' + owners + ' owner · ' + editors + ' editor · ' + viewers + ' viewer';
      }
      _rundownFillStationIdentityForm();
      _rundownUpdateCollaboratorButtons();
      if (!merged.length) {
        listEl.innerHTML = '<div style="padding:20px;border-radius:14px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07);font-size:13px;color:#8B9DAF;text-align:center">No team devices yet. Save this device or add an operator device to get started.</div>';
        return;
      }
      var html = '';
      merged.forEach(function(entry, index) {
        var key = entry.collaboratorKey || '';
        var name = entry.displayName || key || 'Unnamed device';
        var isSelf = key === _rundownSessionId;
        var role = entry.role || 'editor';
        var status = entry.status || 'active';
        var statusTone = status === 'active' ? '#00E676' : (status === 'revoked' ? '#FF8A80' : '#8B9DAF');
        var statusBg = status === 'active' ? 'rgba(0,230,118,0.12)' : (status === 'revoked' ? 'rgba(255,138,128,0.10)' : 'rgba(139,157,175,0.12)');
        var lastSeen = entry.lastSeenAt ? _rundownRelativeTime(entry.lastSeenAt) : 'never';
        html += ''
          + '<div style="padding:14px 16px;border-radius:14px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07)">'
            + '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;flex-wrap:wrap">'
              + '<div style="min-width:0;flex:1">'
                + '<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">'
                  + '<div class="presence-avatar" style="background:' + RUNDOWN_PRESENCE_COLORS[index % RUNDOWN_PRESENCE_COLORS.length] + ';flex:0 0 auto" title="' + escapeHtml(name) + '">' + escapeHtml(name.split(' ').map(function(part) { return part[0] || ''; }).join('').slice(0, 2).toUpperCase() || 'TD') + '</div>'
                  + '<div style="font-size:14px;font-weight:700;color:#F0F2F4;min-width:0">' + escapeHtml(name) + (isSelf ? ' <span style="font-size:11px;color:#8B9DAF;font-weight:600">(This station)</span>' : '') + '</div>'
                + '</div>'
                + '<div style="margin-top:8px;font-family:ui-monospace,monospace;font-size:12px;color:#556270;word-break:break-all">' + escapeHtml(key) + '</div>'
                + '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:10px">'
                  + '<span style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;padding:3px 8px;border-radius:999px;background:rgba(66,165,245,0.10);color:#81D4FA">' + escapeHtml(_rundownRoleLabel(role)) + '</span>'
                  + '<span style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;padding:3px 8px;border-radius:999px;background:' + statusBg + ';color:' + statusTone + '">' + escapeHtml(_rundownStatusLabel(status)) + '</span>'
                  + '<span style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;padding:3px 8px;border-radius:999px;background:rgba(255,255,255,0.05);color:#8B9DAF">' + (status === 'active' ? 'Seen now' : 'Last seen ' + escapeHtml(lastSeen)) + '</span>'
                + '</div>'
              + '</div>'
              + '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">'
                + '<select data-rundown-collaborator-role="' + escapeHtml(key) + '" style="background:rgba(255,255,255,0.06);color:#F0F2F4;border:1px solid rgba(255,255,255,0.1);border-radius:8px;padding:8px 10px;font-size:12px;color-scheme:dark">'
                  + '<option value="owner"' + (role === 'owner' ? ' selected' : '') + '>Owner</option>'
                  + '<option value="editor"' + (role === 'editor' ? ' selected' : '') + '>Editor</option>'
                  + '<option value="viewer"' + (role === 'viewer' ? ' selected' : '') + '>Viewer</option>'
                + '</select>'
                + '<button class="btn-secondary" data-action="rundownCollaboratorSave" data-collaborator-key="' + escapeHtml(key) + '" style="font-size:12px;padding:6px 12px">Save Role</button>'
                + '<button class="btn-secondary" data-action="rundownCollaboratorCopyKey" data-collaborator-key="' + escapeHtml(key) + '" style="font-size:12px;padding:6px 12px">Copy Key</button>'
                + (
                  isSelf
                    ? ''
                    : status === 'revoked'
                      ? '<button class="btn-secondary" data-action="rundownCollaboratorRestore" data-collaborator-key="' + escapeHtml(key) + '" style="font-size:12px;padding:6px 12px">Restore</button>'
                      : '<button class="btn-secondary" data-action="rundownCollaboratorRevoke" data-collaborator-key="' + escapeHtml(key) + '" style="font-size:12px;padding:6px 12px;color:#FF8A80">Revoke</button>'
                )
              + '</div>'
            + '</div>'
          + '</div>';
      });
      listEl.innerHTML = html;
    }

    function _rundownLoadCollaborators(planId) {
      if (!planId) return Promise.resolve([]);
      return api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/collaborators').then(function(data) {
        _rundownCollaboratorRoster = (data && data.collaborators) || [];
        if (data && data.staleAfterMs) _rundownPresenceStaleAfterMs = data.staleAfterMs;
        _rundownRenderCollaboratorList();
        return _rundownCollaboratorRoster;
      }).catch(function() {
        _rundownCollaboratorRoster = [];
        _rundownRenderCollaboratorList();
        return [];
      });
    }

    function _rundownStopPresenceHeartbeat() {
      if (_rundownPresenceHeartbeatTimer) {
        clearInterval(_rundownPresenceHeartbeatTimer);
        _rundownPresenceHeartbeatTimer = null;
      }
    }

    function _rundownStartPresenceHeartbeat(intervalMs) {
      _rundownStopPresenceHeartbeat();
      if (intervalMs) _rundownPresenceHeartbeatMs = intervalMs;
      if (!_rundownSubscribedPlanId) return;
      _rundownPresenceHeartbeatTimer = setInterval(function() {
        if (!_rundownSubscribedPlanId) return;
        api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSubscribedPlanId + '/heartbeat', {
          sessionId: _rundownSessionId,
          userName: _rundownPresenceDisplayName,
        }).then(function(data) {
          if (data && data.collaborators) _rundownPresenceEditors = data.collaborators;
          if (data && data.heartbeatIntervalMs) _rundownPresenceHeartbeatMs = data.heartbeatIntervalMs;
          if (data && data.staleAfterMs) _rundownPresenceStaleAfterMs = data.staleAfterMs;
          _renderPresenceBar();
          _rundownRenderCollaboratorList();
        }).catch(function() {});
      }, Math.max(15000, (_rundownPresenceHeartbeatMs || 30000) - 5000));
    }

    function _rundownSubscribePlan(planId) {
      if (_rundownSubscribedPlanId && _rundownSubscribedPlanId !== planId) {
        _rundownUnsubscribePlan(_rundownSubscribedPlanId);
      }
      _rundownEnsureStationIdentity();
      _rundownSubscribedPlanId = planId;
      _rundownLoadCollaborators(planId);
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/subscribe', {
        userName: _rundownPresenceDisplayName,
        sessionId: _rundownSessionId,
      }).then(function(data) {
        if (data && data.collaborators) _rundownPresenceEditors = data.collaborators;
        else if (data && data.editors) _rundownPresenceEditors = data.editors;
        if (data && data.heartbeatIntervalMs) _rundownPresenceHeartbeatMs = data.heartbeatIntervalMs;
        if (data && data.staleAfterMs) _rundownPresenceStaleAfterMs = data.staleAfterMs;
        _renderPresenceBar();
        _rundownRenderCollaboratorList();
        _rundownStartPresenceHeartbeat(_rundownPresenceHeartbeatMs);
      }).catch(function() {});
    }

    function _rundownUnsubscribePlan(planId, sessionIdOverride) {
      if (!planId) return;
      _rundownStopPresenceHeartbeat();
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/unsubscribe', {
        sessionId: sessionIdOverride || _rundownSessionId,
      }).catch(function() {});
      _rundownSubscribedPlanId = null;
      _rundownPresenceEditors = [];
      _rundownCollaboratorRoster = [];
      _renderPresenceBar();
      _rundownRenderCollaboratorList();
    }

    function _renderPresenceBar() {
      var bar = document.getElementById('rundown-presence-bar');
      var avatarsEl = document.getElementById('rundown-presence-avatars');
      var textEl = document.getElementById('rundown-presence-text');
      if (!bar || !avatarsEl || !textEl) return;
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') {
        bar.style.display = 'none';
        avatarsEl.innerHTML = '';
        textEl.textContent = '';
        return;
      }
      var activeEntries = _rundownActivePresenceList();
      var editors = activeEntries.filter(function(entry) { return entry.role !== 'viewer'; }).length;
      var viewers = activeEntries.filter(function(entry) { return entry.role === 'viewer'; }).length;
      var avatarHtml = '';
      activeEntries.slice(0, 5).forEach(function(entry, index) {
        var name = entry.displayName || entry.userName || 'TD';
        var initials = name.split(' ').map(function(part) { return part[0] || ''; }).join('').slice(0, 2).toUpperCase() || 'TD';
        avatarHtml += '<div class="presence-avatar" style="background:' + RUNDOWN_PRESENCE_COLORS[index % RUNDOWN_PRESENCE_COLORS.length] + '" title="' + escapeHtml(name) + '">' + escapeHtml(initials) + '</div>';
      });
      avatarsEl.innerHTML = avatarHtml;
      if (!activeEntries.length) {
        textEl.textContent = 'No active devices yet. Open this rundown on another device to build your team board.';
      } else if (activeEntries.length === 1) {
        textEl.textContent = 'Only this device is active right now. Add operator devices or view-only devices for a fuller setup.';
      } else {
        textEl.textContent = activeEntries.length + ' devices active · ' + editors + ' editing · ' + viewers + ' viewing';
      }
      bar.style.display = 'flex';
      bar.classList.toggle('has-editors', activeEntries.length > 1);
      _rundownUpdateCollaboratorButtons();
      // Also update team sidebar if visible
      var teamSidebar = document.getElementById('rundown-team-sidebar');
      if (teamSidebar && teamSidebar.style.display !== 'none') {
        _rundownRenderTeamMembers();
      }
    }

    function rundownCollaborators() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      var backdrop = document.getElementById('modal-rundown-collaborators');
      if (!backdrop) return;
      _rundownFillStationIdentityForm();
      _rundownLoadCollaborators(_rundownSelectedPlan.id);
      _rundownRenderCollaboratorList();
      backdrop.classList.add('open');
    }

    function _rundownCloseCollaborators() {
      var backdrop = document.getElementById('modal-rundown-collaborators');
      if (backdrop) backdrop.classList.remove('open');
    }

    function rundownSaveStationIdentity() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      var nameInput = document.getElementById('rundown-station-name');
      var keyInput = document.getElementById('rundown-station-key');
      var nextName = String(nameInput && nameInput.value || '').trim() || _rundownDefaultStationName();
      var nextKey = _rundownNormalizeStationKey(keyInput && keyInput.value);
      if (!nextKey) {
        toast('Device key is required', true);
        return;
      }
      var previousKey = _rundownSessionId;
      _rundownPresenceDisplayName = nextName;
      _rundownSessionId = nextKey;
      _rundownStorageSet(_rundownSessionStorageKey, nextKey);
      _rundownStorageSet(_rundownStationNameStorageKey, nextName);
      _rundownFillStationIdentityForm();
      _rundownRenderCollaboratorList();
      if (_rundownSubscribedPlanId) {
        if (previousKey && previousKey !== nextKey) _rundownUnsubscribePlan(_rundownSubscribedPlanId, previousKey);
        _rundownSubscribePlan(_rundownSelectedPlan.id);
      }
      toast('Station saved');
    }

    function rundownCopyStationKey(buttonEl, key) {
      var targetKey = key || _rundownSessionId;
      if (!targetKey) return;
      _rundownCopyTextToClipboard(targetKey, buttonEl, 'Copy Key');
    }

    function rundownAddCollaborator() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      var keyInput = document.getElementById('rundown-collaborator-key');
      var nameInput = document.getElementById('rundown-collaborator-name');
      var roleSelect = document.getElementById('rundown-collaborator-role');
      var collaboratorKey = _rundownNormalizeStationKey(keyInput && keyInput.value);
      var displayName = String(nameInput && nameInput.value || '').trim();
      var role = String(roleSelect && roleSelect.value || 'editor');
      if (!collaboratorKey) {
        toast('Team station key is required', true);
        return;
      }
      var liveEntry = _rundownFindCollaborator(collaboratorKey);
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/collaborators', {
        collaboratorKey: collaboratorKey,
        displayName: displayName || (liveEntry && liveEntry.displayName) || collaboratorKey,
        role: role,
        status: liveEntry && liveEntry.status === 'active' ? 'active' : 'offline',
      }).then(function(data) {
        _rundownCollaboratorRoster = (data && data.collaborators) || _rundownCollaboratorRoster;
        if (keyInput) keyInput.value = '';
        if (nameInput) nameInput.value = '';
        if (roleSelect) roleSelect.value = 'editor';
        _rundownRenderCollaboratorList();
        toast('Team access saved');
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function rundownSaveCollaboratorRole(collaboratorKey) {
      if (!_rundownSelectedPlan || !_rundownSelectedPlan.id || !collaboratorKey) return;
      var roleSelect = null;
      document.querySelectorAll('[data-rundown-collaborator-role]').forEach(function(selectEl) {
        if (!roleSelect && selectEl.dataset.rundownCollaboratorRole === collaboratorKey) roleSelect = selectEl;
      });
      var entry = _rundownFindCollaborator(collaboratorKey) || {};
      var role = roleSelect ? roleSelect.value : (entry.role || 'editor');
      var method = (_rundownCollaboratorRoster || []).some(function(item) { return item.collaboratorKey === collaboratorKey; }) ? 'PUT' : 'POST';
      var path = method === 'PUT'
        ? '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/collaborators/' + encodeURIComponent(collaboratorKey)
        : '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/collaborators';
      api(method, path, {
        collaboratorKey: collaboratorKey,
        displayName: entry.displayName || collaboratorKey,
        role: role,
        status: entry.status === 'revoked' ? 'active' : (entry.status || 'active'),
      }).then(function(data) {
        _rundownCollaboratorRoster = (data && data.collaborators) || _rundownCollaboratorRoster;
        _rundownRenderCollaboratorList();
        toast('Role updated');
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function rundownRestoreCollaborator(collaboratorKey) {
      if (!_rundownSelectedPlan || !_rundownSelectedPlan.id || !collaboratorKey) return;
      var entry = _rundownFindCollaborator(collaboratorKey) || {};
      api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/collaborators/' + encodeURIComponent(collaboratorKey), {
        displayName: entry.displayName || collaboratorKey,
        role: entry.role || 'editor',
        status: 'offline',
      }).then(function(data) {
        _rundownCollaboratorRoster = (data && data.collaborators) || _rundownCollaboratorRoster;
        _rundownRenderCollaboratorList();
        toast('Access restored');
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function rundownRevokeCollaborator(collaboratorKey) {
      if (!_rundownSelectedPlan || !_rundownSelectedPlan.id || !collaboratorKey || collaboratorKey === _rundownSessionId) return;
      styledConfirm('Revoke Access', 'This station will become view blocked until you restore it.').then(function(ok) {
        if (!ok) return;
        api('DELETE', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/collaborators/' + encodeURIComponent(collaboratorKey)).then(function(data) {
          _rundownCollaboratorRoster = (data && data.collaborators) || _rundownCollaboratorRoster;
          _rundownRenderCollaboratorList();
          toast('Access revoked');
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    // Unsubscribe when navigating away
    window.addEventListener('beforeunload', function() {
      if (_rundownSubscribedPlanId) {
        navigator.sendBeacon('/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSubscribedPlanId + '/unsubscribe',
          new Blob([JSON.stringify({ sessionId: _rundownSessionId })], { type: 'application/json' }));
      }
    });

    // ── Handle collaboration SSE messages ───────────────────────────────────
    function handleRundownCollaboration(data) {
      if (!data || !data.planId) return;

      if (data.type === 'rundown_presence') {
        if (data.planId === _rundownSubscribedPlanId) {
          _rundownPresenceEditors = data.collaborators || data.editors || [];
          if (data.staleAfterMs) _rundownPresenceStaleAfterMs = data.staleAfterMs;
          _renderPresenceBar();
          _rundownRenderCollaboratorList();
        }
        // Update dashboard card editor counts
        var plan = _rundownPlans.find(function(p) { return p.id === data.planId; });
        if (plan) {
          plan.activeEditors = (_rundownPresenceEditors || []).filter(function(entry) { return entry.status === 'active' && !entry.isStale; }).length;
          // Re-render dashboard if visible
          if (document.getElementById('rundown-manager') && document.getElementById('rundown-manager').style.display !== 'none') {
            renderRundownDashboard();
          }
        }
        return;
      }

      // 9.1: Handle edit lock/unlock events
      if (_rundownSelectedPlan && data.planId === _rundownSelectedPlan.id) {
        if (data.type === 'rundown_item_locked') {
          _rundownEditLocks[data.itemId] = { sessionId: data.sessionId, displayName: data.displayName, lockedAt: Date.now() };
          _renderRundownEditLockIndicators();
        } else if (data.type === 'rundown_item_unlocked') {
          delete _rundownEditLocks[data.itemId];
          _renderRundownEditLockIndicators();
        } else if (data.type === 'rundown_plan_locked') {
          _rundownSelectedPlan.lockedBy = data.lockedBy;
          _rundownSelectedPlan.lockedAt = data.lockedAt;
          renderRundownEditor(_rundownSelectedPlan);
          toast('Plan locked for show by ' + (data.lockedBy || 'TD'));
        } else if (data.type === 'rundown_plan_unlocked') {
          _rundownSelectedPlan.lockedBy = null;
          _rundownSelectedPlan.lockedAt = null;
          renderRundownEditor(_rundownSelectedPlan);
          toast('Plan unlocked');
        }
      }

      // If we're editing this plan, apply the live update
      if (_rundownSelectedPlan && data.planId === _rundownSelectedPlan.id) {
        if (data.type === 'rundown_item_updated' && data.itemId && data.item) {
          // 9.1: Show toast if someone else edited an item we might be looking at
          if (data.changedBy && data.changedBy !== _rundownPresenceDisplayName) {
            toast('Item updated by ' + data.changedBy);
          }
          // Update item in local state
          var item = (_rundownSelectedPlan.items || []).find(function(x) { return x.id === data.itemId; });
          if (item) {
            if (data.item.title !== undefined) item.title = data.item.title;
            if (data.item.itemType !== undefined) item.itemType = data.item.itemType;
            if (data.item.lengthSeconds !== undefined) item.lengthSeconds = data.item.lengthSeconds;
            if (data.item.notes !== undefined) item.notes = data.item.notes;
            if (data.item.assignee !== undefined) item.assignee = data.item.assignee;
            if (data.item.directorNotes !== undefined) item.directorNotes = data.item.directorNotes;
            renderRundownEditorItems(_rundownSelectedPlan.items || []);
            // Flash the edited cell
            setTimeout(function() {
              var row = document.querySelector('tr[data-item-id="' + data.itemId + '"]');
              if (row) { row.classList.add('rundown-cell-flash'); setTimeout(function() { row.classList.remove('rundown-cell-flash'); }, 1000); }
            }, 50);
          }
        } else if (data.type === 'rundown_item_added' || data.type === 'rundown_item_deleted' || data.type === 'rundown_item_reordered') {
          // Refetch the full plan for structural changes
          api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id).then(function(plan) {
            _rundownSelectedPlan = plan;
            renderRundownEditor(plan);
          }).catch(function() {});
        } else if (data.type === 'rundown_plan_updated' && data.plan) {
          // Update plan metadata
          if (data.plan.title) _rundownSelectedPlan.title = data.plan.title;
          if (data.plan.status) _rundownSelectedPlan.status = data.plan.status;
          if (data.plan.serviceDate !== undefined) _rundownSelectedPlan.serviceDate = data.plan.serviceDate;
          if (data.plan.roomId !== undefined) _rundownSelectedPlan.roomId = data.plan.roomId;
          if (data.plan.lockedBy !== undefined) _rundownSelectedPlan.lockedBy = data.plan.lockedBy;
          if (data.plan.lockedAt !== undefined) _rundownSelectedPlan.lockedAt = data.plan.lockedAt;
          renderRundownEditor(_rundownSelectedPlan);
        }
      }

      // Also refresh dashboard data for plan list updates
      if (data.type === 'rundown_plan_updated') {
        var dashPlan = _rundownPlans.find(function(p) { return p.id === data.planId; });
        if (dashPlan && data.plan) {
          if (data.plan.title) dashPlan.title = data.plan.title;
          if (data.plan.status) dashPlan.status = data.plan.status;
          if (data.plan.serviceDate !== undefined) dashPlan.serviceDate = data.plan.serviceDate;
          if (data.plan.roomId !== undefined) dashPlan.roomId = data.plan.roomId;
          if (data.plan.updatedAt) dashPlan.updatedAt = data.plan.updatedAt;
          if (document.getElementById('rundown-manager') && document.getElementById('rundown-manager').style.display !== 'none') {
            renderRundownDashboard();
          }
        }
      }
    }

    function rundownSelectPlan(planId, source) {
      _rundownSelectedPlanId = planId;
      // Switch to full-screen editor view
      showRundownView('editor');
      _rundownOpenEditorHash(planId);
      if (source === 'pco') {
        if (_rundownSubscribedPlanId) _rundownUnsubscribePlan(_rundownSubscribedPlanId);
        // PCO plans can be started directly but not edited
        _rundownSelectedPlan = { id: planId, source: 'pco' };
        var p = _rundownPlans.find(function(x) { return x.id === planId; });
        var titleEl = document.getElementById('rundown-editor-title');
        var dateEl = document.getElementById('rundown-editor-date');
        if (titleEl) titleEl.textContent = p ? p.title : 'PCO Plan';
        if (dateEl) dateEl.textContent = p && p.serviceDate ? p.serviceDate : '';
        // Hide edit/share controls for PCO plans
        document.querySelectorAll('[data-action="rundownEditPlan"],[data-action="rundownAddItem"],[data-action="rundownDeletePlan"],[data-action="rundownSaveTemplate"],[data-action="rundownShare"],[data-action="rundownCollaborators"],[data-action="rundownCopyShareLink"]').forEach(function(b) { b.style.display = 'none'; });
        var showModeBtn = document.getElementById('btn-rundown-show-mode');
        if (showModeBtn) showModeBtn.style.display = 'none';
        _updateSharedBadge(false);
        _renderPresenceBar();
        var itemsEl = document.getElementById('rundown-editor-items');
        if (itemsEl) itemsEl.innerHTML = '<div style="color:#556270;text-align:center;padding:16px;font-size:13px">PCO plan items are imported automatically.</div>';
      } else {
        // Load full manual plan with items, columns, and attachments
        api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId).then(function(plan) {
          _rundownSelectedPlan = plan;
          // Load columns and attachments in parallel
          Promise.all([
            api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/columns').catch(function() { return { columns: [], values: [] }; }),
            api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/attachments').catch(function() { return { attachments: [] }; })
          ]).then(function(results) {
            _rundownColumns = (results[0] && results[0].columns) || [];
            // Build value lookup map
            _rundownColumnValues = {};
            var vals = (results[0] && results[0].values) || [];
            for (var v = 0; v < vals.length; v++) {
              _rundownColumnValues[vals[v].itemId + '_' + vals[v].columnId] = vals[v].value;
            }
            // Build attachment lookup by itemId
            _rundownAttachments = {};
            var atts = (results[1] && results[1].attachments) || [];
            for (var a = 0; a < atts.length; a++) {
              if (!_rundownAttachments[atts[a].itemId]) _rundownAttachments[atts[a].itemId] = [];
              _rundownAttachments[atts[a].itemId].push(atts[a]);
            }
            renderRundownEditor(plan);
          });
        });
      }
    }

