    // ── v3 Phase 1: Color picker popup ────────────────────────────────────────
    var _colorPickerActive = null;
    function _openRundownColorPicker(trigger) {
      _closeRundownPopups();
      var itemId = trigger.dataset.itemId;
      var rect = trigger.getBoundingClientRect();
      var item = _rundownSelectedPlan ? (_rundownSelectedPlan.items || []).find(function(x) { return x.id === itemId; }) : null;
      var currentColor = item ? (item.color || '') : '';

      var picker = document.createElement('div');
      picker.className = 'rundown-color-picker open';
      picker.style.position = 'fixed';
      picker.style.left = Math.min(rect.left, window.innerWidth - 240) + 'px';
      picker.style.top = (rect.bottom + 4) + 'px';
      picker.style.zIndex = '200';

      var html = '<div class="rundown-color-picker-grid">';
      for (var ci = 0; ci < RUNDOWN_COLOR_PRESETS.length; ci++) {
        var preset = RUNDOWN_COLOR_PRESETS[ci];
        var isActive = currentColor === preset.color;
        html += '<div style="text-align:center">';
        html += '<div class="rundown-color-swatch' + (isActive ? ' active' : '') + '" data-color="' + preset.color + '" style="background:' + preset.color + '"></div>';
        html += '<div class="rundown-color-swatch-label">' + preset.label + '</div>';
        html += '</div>';
      }
      html += '</div>';
      html += '<div class="rundown-color-custom-row">';
      html += '<input type="color" id="rundown-custom-color" value="' + (currentColor || '#3b82f6') + '">';
      html += '<input type="text" id="rundown-custom-hex" placeholder="#hex" value="' + (currentColor || '') + '" maxlength="7">';
      html += '<button class="rundown-color-clear" data-color="">Clear</button>';
      html += '</div>';
      picker.innerHTML = html;
      document.body.appendChild(picker);
      _colorPickerActive = picker;

      function applyColor(color) {
        _closeRundownPopups();
        if (!_rundownSelectedPlan) return;
        api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + itemId, { color: color || '' }).then(function() {
          api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id).then(function(plan) {
            _rundownSelectedPlan = plan;
            renderRundownEditorItems(plan.items || []);
          });
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      }

      picker.querySelectorAll('.rundown-color-swatch').forEach(function(sw) {
        sw.addEventListener('click', function() { applyColor(sw.dataset.color); });
      });
      picker.querySelector('.rundown-color-clear').addEventListener('click', function() { applyColor(''); });
      var customColorInput = picker.querySelector('#rundown-custom-color');
      var customHexInput = picker.querySelector('#rundown-custom-hex');
      customColorInput.addEventListener('input', function() {
        customHexInput.value = customColorInput.value;
      });
      customColorInput.addEventListener('change', function() { applyColor(customColorInput.value); });
      customHexInput.addEventListener('keydown', function(e) {
        if (e.key === 'Enter' && /^#[0-9a-f]{6}$/i.test(customHexInput.value)) {
          applyColor(customHexInput.value);
        }
      });
      // Close on outside click
      setTimeout(function() {
        document.addEventListener('click', _closeRundownPopupsOnClick, true);
      }, 0);
    }

    // ── v3 Phase 1: Duration picker popup ────────────────────────────────────
    var _durationPickerActive = null;
    function _openRundownDurationPicker(trigger) {
      _closeRundownPopups();
      var itemId = trigger.dataset.itemId;
      var currentSeconds = parseInt(trigger.dataset.seconds, 10) || 0;
      var rect = trigger.getBoundingClientRect();

      var picker = document.createElement('div');
      picker.className = 'rundown-duration-picker open';
      picker.style.position = 'fixed';
      picker.style.left = Math.min(rect.left - 80, window.innerWidth - 260) + 'px';
      picker.style.top = (rect.bottom + 4) + 'px';
      picker.style.zIndex = '200';

      var presets = [30, 60, 120, 180, 300, 600, 900, 1800];
      var presetLabels = ['0:30', '1:00', '2:00', '3:00', '5:00', '10:00', '15:00', '30:00'];
      var html = '<div class="rundown-duration-presets">';
      for (var di = 0; di < presets.length; di++) {
        var isActive = currentSeconds === presets[di];
        html += '<button class="rundown-duration-preset' + (isActive ? ' active' : '') + '" data-seconds="' + presets[di] + '">' + presetLabels[di] + '</button>';
      }
      html += '</div>';
      var curMin = Math.floor(currentSeconds / 60);
      var curSec = currentSeconds % 60;
      var curVal = curMin + ':' + (curSec < 10 ? '0' : '') + curSec;
      html += '<div class="rundown-duration-manual">';
      html += '<input type="text" id="rundown-dur-input" placeholder="MM:SS" value="' + curVal + '">';
      html += '<button class="rundown-duration-preset" id="rundown-dur-apply" style="flex-shrink:0;padding:6px 12px">Set</button>';
      html += '</div>';
      picker.innerHTML = html;
      document.body.appendChild(picker);
      _durationPickerActive = picker;

      function applyDuration(seconds) {
        _closeRundownPopups();
        if (!_rundownSelectedPlan) return;
        api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + itemId, { lengthSeconds: seconds }).then(function() {
          api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id).then(function(plan) {
            _rundownSelectedPlan = plan;
            renderRundownEditorItems(plan.items || []);
          });
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      }

      function parseMMSS(val) {
        var parts = val.split(':');
        if (parts.length === 2) return (parseInt(parts[0], 10) || 0) * 60 + (parseInt(parts[1], 10) || 0);
        if (parts.length === 1) return (parseInt(parts[0], 10) || 0) * 60;
        return 0;
      }

      picker.querySelectorAll('.rundown-duration-preset[data-seconds]').forEach(function(btn) {
        btn.addEventListener('click', function() { applyDuration(parseInt(btn.dataset.seconds, 10)); });
      });
      picker.querySelector('#rundown-dur-apply').addEventListener('click', function() {
        var val = picker.querySelector('#rundown-dur-input').value;
        applyDuration(parseMMSS(val));
      });
      picker.querySelector('#rundown-dur-input').addEventListener('keydown', function(e) {
        if (e.key === 'Enter') { applyDuration(parseMMSS(e.target.value)); }
      });
      setTimeout(function() {
        var inp = picker.querySelector('#rundown-dur-input');
        if (inp) { inp.focus(); inp.select(); }
        document.addEventListener('click', _closeRundownPopupsOnClick, true);
      }, 0);
    }

    // ── v3 Phase 1: Close popups helper ────────────────────────────────────
    function _closeRundownPopups() {
      if (_colorPickerActive) { _colorPickerActive.remove(); _colorPickerActive = null; }
      if (_durationPickerActive) { _durationPickerActive.remove(); _durationPickerActive = null; }
      document.removeEventListener('click', _closeRundownPopupsOnClick, true);
    }
    function _closeRundownPopupsOnClick(e) {
      if (_colorPickerActive && !_colorPickerActive.contains(e.target) && !e.target.closest('[data-action="rundownColorPicker"]')) {
        _closeRundownPopups();
      }
      if (_durationPickerActive && !_durationPickerActive.contains(e.target) && !e.target.closest('[data-action="rundownDurationPicker"]')) {
        _closeRundownPopups();
      }
    }

    // ── v3 Phase 1: Section collapse toggle ────────────────────────────────
    document.addEventListener('click', function(e) {
      var chevron = e.target.closest('.rundown-section-chevron') || e.target.closest('[data-toggle-section]');
      if (chevron) {
        var sectionId = chevron.dataset.toggleSection || chevron.getAttribute('data-toggle-section');
        if (sectionId) {
          _rundownSectionCollapse[sectionId] = !_rundownSectionCollapse[sectionId];
          _saveRundownSectionCollapse();
          if (_rundownSelectedPlan) renderRundownEditorItems(_rundownSelectedPlan.items || []);
        }
      }
    });

    // ── v3 Phase 1: Create from built-in template ─────────────────────────
    function _createFromBuiltinTemplate(index) {
      var tpl = RUNDOWN_BUILTIN_TEMPLATES[index];
      if (!tpl) return;
      _openRundownPlanModal('create', { title: tpl.name, date: new Date().toISOString().slice(0, 10) }).then(function(result) {
        if (!result) return;
        api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans', {
          title: result.title,
          serviceDate: result.date,
          roomId: result.roomId || ''
        }).then(function(plan) {
          // Add template items sequentially
          var chain = Promise.resolve();
          for (var ti = 0; ti < tpl.items.length; ti++) {
            (function(tplItem) {
              chain = chain.then(function() {
                return api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + plan.id + '/items', {
                  title: tplItem.title,
                  itemType: tplItem.itemType,
                  lengthSeconds: tplItem.lengthSeconds || 0,
                  color: tplItem.color || '',
                  notes: '',
                  assignee: ''
                });
              });
            })(tpl.items[ti]);
          }
          chain.then(function() {
            toast('Created from template');
            _rundownSelectedPlanId = plan.id;
            loadRundownManager();
            setTimeout(function() { rundownSelectPlan(plan.id, 'manual'); }, 300);
          });
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    function rundownEditItem(itemId) {
      // Legacy: still kept for modal-based editing if needed
      if (!_rundownSelectedPlan) return;
      var item = (_rundownSelectedPlan.items || []).find(function(x) { return x.id === itemId; });
      if (!item) return;
      _openRundownItemModal('edit', {
        id: item.id,
        title: item.title,
        itemType: item.itemType,
        durationMinutes: item.lengthSeconds > 0 ? parseFloat((item.lengthSeconds / 60).toFixed(1)) : 0,
        notes: item.notes || '',
        parentId: item.parentId || null,
      }).then(function(result) {
        if (!result) return;
        var durSec = Math.round(result.durationMinutes * 60);
        api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + itemId, {
          title: result.title,
          itemType: result.itemType,
          lengthSeconds: durSec > 0 ? durSec : 0,
          notes: result.notes,
          parentId: result.parentId || null,
        }).then(function(plan) {
          _rundownSelectedPlan = plan;
          renderRundownEditor(plan);
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    function rundownDeleteItem(itemId) {
      if (!_rundownSelectedPlan) return;
      styledConfirm('Remove Item', 'Remove this item from the rundown?').then(function(ok) {
        if (!ok) return;
        api('DELETE', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + itemId).then(function(plan) {
          _rundownSelectedPlan = plan;
          renderRundownEditor(plan);
          var idx = _rundownPlans.findIndex(function(p) { return p.id === plan.id; });
          if (idx >= 0) { _rundownPlans[idx].itemCount = plan.items.length; renderRundownDashboard(); }
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    function rundownMoveItem(itemId, direction) {
      if (!_rundownSelectedPlan || !_rundownSelectedPlan.items) return;
      var items = _rundownSelectedPlan.items;
      var idx = items.findIndex(function(x) { return x.id === itemId; });
      if (idx < 0) return;
      var newIdx = direction === 'up' ? idx - 1 : idx + 1;
      if (newIdx < 0 || newIdx >= items.length) return;
      var ids = items.map(function(x) { return x.id; });
      var tmp = ids[idx]; ids[idx] = ids[newIdx]; ids[newIdx] = tmp;
      api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/reorder', { itemIds: ids }).then(function(plan) {
        _rundownSelectedPlan = plan;
        renderRundownEditor(plan);
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    // ── Share / Output Suite ──────────────────────────────────────────────────

    var _rundownShareData = null; // { share: { id, token, url, expiresAt } | null }

    function _rundownNormalizeShareUrl(url) {
      if (!url) return '';
      try {
        return new URL(url, window.location.origin).href;
      } catch (e) {
        return String(url);
      }
    }

    function _rundownBuildModeUrl(baseUrl, mode, extraParams) {
      if (!baseUrl) return '';
      try {
        var url = new URL(baseUrl, window.location.origin);
        if (mode) url.searchParams.set('mode', mode);
        else url.searchParams.delete('mode');
        if (extraParams) {
          Object.keys(extraParams).forEach(function(key) {
            var value = extraParams[key];
            if (value == null || value === '') {
              url.searchParams.delete(key);
              return;
            }
            url.searchParams.set(key, String(value));
          });
        }
        return url.href;
      } catch (e) {
        var raw = String(baseUrl);
        var joiner = raw.indexOf('?') >= 0 ? '&' : '?';
        var params = [];
        if (mode) params.push('mode=' + encodeURIComponent(mode));
        if (extraParams) {
          Object.keys(extraParams).forEach(function(key) {
            var value = extraParams[key];
            if (value == null || value === '') return;
            params.push(encodeURIComponent(key) + '=' + encodeURIComponent(String(value)));
          });
        }
        return params.length ? raw + joiner + params.join('&') : raw;
      }
    }

    function _rundownBuildOperatorOutputUrl(baseUrl, columnId) {
      return _rundownBuildModeUrl(baseUrl, '', { columns: columnId, hideEmpty: '1' });
    }

    function _rundownResolveShareUrls(share) {
      var token = share && share.share_token ? String(share.share_token) : '';
      var publicUrl = _rundownNormalizeShareUrl(share && share.url);
      var timerUrl = _rundownNormalizeShareUrl(share && share.timer_url);
      var showUrl = '';
      if (!publicUrl && token) {
        publicUrl = _rundownNormalizeShareUrl(new URL('/rundown/view/' + token, window.location.origin).href);
      }
      if (!timerUrl && token) {
        timerUrl = _rundownNormalizeShareUrl(new URL('/rundown/timer/' + token, window.location.origin).href);
      }
      if (token) {
        showUrl = _rundownNormalizeShareUrl(new URL('/rundown/show/' + token, window.location.origin).href);
      }
      var prompterUrl = '';
      if (token) {
        prompterUrl = _rundownNormalizeShareUrl(new URL('/rundown/prompter/' + token, window.location.origin).href);
      }
      var readonlyShowUrl = showUrl ? _rundownBuildModeUrl(showUrl, '', { readonly: '1' }) : '';
      return { token: token, publicUrl: publicUrl, timerUrl: timerUrl, showUrl: showUrl, prompterUrl: prompterUrl, readonlyShowUrl: readonlyShowUrl };
    }

    function _rundownShareCopyFeedback(buttonEl, defaultLabel) {
      if (!buttonEl) return;
      var label = defaultLabel || buttonEl.dataset.defaultLabel || buttonEl.textContent || 'Copy Link';
      buttonEl.textContent = 'Copied!';
      setTimeout(function() {
        buttonEl.textContent = label;
      }, 1800);
    }

    function _rundownCopyTextToClipboard(text, buttonEl, defaultLabel) {
      if (!text) return;
      navigator.clipboard.writeText(text).then(function() {
        _rundownShareCopyFeedback(buttonEl, defaultLabel);
      }).catch(function() {
        window.prompt('Copy this link:', text);
      });
    }

    function _rundownOpenUrl(url) {
      if (!url) return;
      window.open(url, '_blank', 'noopener,noreferrer');
    }

    function _rundownBuildOutputCard(opts) {
      if (!opts || !opts.url) return '';
      var title = escapeHtml(opts.title || '');
      var kicker = escapeHtml(opts.kicker || 'Output');
      var desc = opts.description ? '<div style="font-size:12px;color:#8B9DAF;line-height:1.5;margin-top:4px">' + escapeHtml(opts.description) + '</div>' : '';
      var badge = opts.badge ? '<span style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;padding:3px 8px;border-radius:999px;background:' + (opts.badgeBg || 'rgba(0,230,118,0.12)') + ';color:' + (opts.badgeColor || '#00E676') + '">' + escapeHtml(opts.badge) + '</span>' : '';
      var accent = opts.accent || '#00E676';
      return ''
        + '<div style="padding:14px 15px;border-radius:14px;background:linear-gradient(180deg, rgba(255,255,255,0.05), rgba(255,255,255,0.03));border:1px solid rgba(255,255,255,0.08);box-shadow:0 10px 24px rgba(0,0,0,0.12)">'
          + '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px">'
            + '<div style="min-width:0;flex:1">'
              + '<div style="font-size:10px;text-transform:uppercase;letter-spacing:0.8px;font-weight:800;color:' + accent + '">' + kicker + '</div>'
              + '<div style="font-size:15px;font-weight:800;color:#F0F2F4;margin-top:4px">' + title + '</div>'
              + desc
            + '</div>'
            + badge
          + '</div>'
          + '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:12px">'
            + '<button class="btn-primary" style="font-size:12px;padding:6px 14px" data-rundown-output-open="' + escapeHtml(opts.url) + '">Open</button>'
            + '<button class="btn-secondary" style="font-size:12px;padding:6px 14px" data-share-copy-url="' + escapeHtml(opts.url) + '" data-copy-default-label="Copy Link">Copy</button>'
          + '</div>'
          + '<div style="margin-top:10px;font-family:ui-monospace,monospace;font-size:11px;color:#556270;word-break:break-all;line-height:1.4">' + escapeHtml(opts.url) + '</div>'
        + '</div>';
    }

    function _rundownBuildSectionCard(title, copy, cards, accent) {
      var cardHtml = Array.isArray(cards) ? cards.filter(Boolean).join('') : '';
      if (!cardHtml) return '';
      return ''
        + '<div style="padding:14px;border-radius:16px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07)">'
          + '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:10px">'
            + '<div>'
              + '<div style="font-size:11px;text-transform:uppercase;letter-spacing:0.8px;color:#556270;font-weight:800;margin-bottom:5px">' + escapeHtml(title) + '</div>'
              + '<div style="font-size:12px;color:#8B9DAF;line-height:1.45">' + escapeHtml(copy) + '</div>'
            + '</div>'
            + (accent ? '<span style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;padding:2px 8px;border-radius:10px;background:' + accent.bg + ';color:' + accent.fg + '">' + escapeHtml(accent.label) + '</span>' : '')
          + '</div>'
          + '<div style="display:flex;flex-direction:column;gap:10px">' + cardHtml + '</div>'
        + '</div>';
    }

    function _rundownBuildDemoSetup(share) {
      var urls = _rundownResolveShareUrls(share || _rundownShareData || {});
      var planTitle = (_rundownSelectedPlan && _rundownSelectedPlan.title) || 'This rundown';
      var publicUrl = _rundownBuildModeUrl(urls.publicUrl, '', {});
      var compactUrl = _rundownBuildModeUrl(urls.publicUrl, 'compact', {});
      var prompterUrl = _rundownBuildModeUrl(urls.publicUrl, 'prompter', {});
      var timerUrl = _rundownBuildModeUrl(urls.timerUrl, '', {});
      var stageUrl = _rundownBuildModeUrl(urls.timerUrl, 'stage', {});
      var confidenceUrl = _rundownBuildModeUrl(urls.timerUrl, 'confidence', {});
      var note = [
        planTitle + ' sample setup',
        '',
        'Caller / producer laptop:',
        publicUrl || compactUrl || 'No public rundown link yet',
        '',
        'Stage or large text screen:',
        prompterUrl || publicUrl || 'No large text link yet',
        '',
        'Stage display / timer:',
        stageUrl || confidenceUrl || timerUrl || 'No timer link yet',
      ];
      if (_rundownColumns && _rundownColumns.length && publicUrl) {
        var column = _rundownColumns[0];
        note.push('', 'Optional department feed (' + (column.name || column.id) + '):', _rundownBuildOperatorOutputUrl(publicUrl, column.id));
      }
      return {
        publicUrl: publicUrl,
        compactUrl: compactUrl,
        prompterUrl: prompterUrl,
        timerUrl: timerUrl,
        stageUrl: stageUrl,
        confidenceUrl: confidenceUrl,
        note: note.join('\n'),
      };
    }

    function _rundownRenderShareLinks(share) {
      var urls = _rundownResolveShareUrls(share || {});
      var demoSetup = _rundownBuildDemoSetup(share);
      var publicUrl = urls.publicUrl;
      var timerUrl = urls.timerUrl;
      var expiryEl = document.getElementById('rundown-share-expiry');
      var introEl = document.getElementById('rundown-share-intro');
      var outputSuite = document.getElementById('rundown-share-output-suite');
      var operatorWrap = document.getElementById('rundown-share-operator-wrap');
      var operatorLinks = document.getElementById('rundown-share-operator-links');
      var sections = [];
      var timerSections = [];
      var operatorItems = [];
      var hasOperatorLinks = false;

      if (introEl) {
        introEl.textContent = 'Choose how to share your service plan. One link powers read-only public views, countdown timers, and department-specific feeds.';
      }

      if (demoSetup.publicUrl || demoSetup.prompterUrl || demoSetup.stageUrl || demoSetup.timerUrl) {
        sections.push(_rundownBuildSectionCard(
          'Suggested launch order',
          'Use this when you want a polished three-screen setup quickly: one desk view, one large text view, and one timer display.',
          [
            _rundownBuildOutputCard({
              kicker: 'Desk screen',
              title: 'Caller / producer',
              description: 'Best default desk view for the person running items.',
              url: demoSetup.publicUrl || demoSetup.compactUrl,
              badge: 'Step 1',
              badgeBg: 'rgba(0,230,118,0.12)',
              badgeColor: '#00E676',
              accent: '#00E676',
            }),
            _rundownBuildOutputCard({
              kicker: 'Stage display',
              title: 'Large Text screen',
              description: 'Large, stage-friendly item following for presenters or backstage monitors.',
              url: demoSetup.prompterUrl || demoSetup.publicUrl,
              badge: 'Step 2',
              badgeBg: 'rgba(171,71,188,0.10)',
              badgeColor: '#CE93D8',
              accent: '#CE93D8',
            }),
            _rundownBuildOutputCard({
              kicker: 'Stage Display',
              title: 'Detailed timer',
              description: 'Countdown-focused display for speakers and production timing.',
              url: demoSetup.stageUrl || demoSetup.timerUrl,
              badge: 'Step 3',
              badgeBg: 'rgba(255,167,38,0.10)',
              badgeColor: '#FFB74D',
              accent: '#FFB74D',
            })
          ],
          { label: 'Sample Setup', bg: 'rgba(255,255,255,0.05)', fg: '#F0F2F4' }
        ));
      }

      if (urls.showUrl) {
        sections.push(_rundownBuildSectionCard(
          'Live Mode',
          'A dedicated operator view for running live services. Includes large Go/Back controls, live countdown, inline editing, and next-up preview.',
          [
            _rundownBuildOutputCard({
              kicker: 'Operator view',
              title: 'Live Mode',
              description: 'Full item control with start/stop, advance, countdown timers, and quick edits. Built for the tech booth.',
              url: urls.showUrl,
              badge: 'Live control',
              badgeBg: 'rgba(255,167,38,0.10)',
              badgeColor: '#FFB74D',
              accent: '#FFB74D',
            }),
            _rundownBuildOutputCard({
              kicker: 'Follow-along view',
              title: 'Read-Only Live Mode',
              description: 'Live-following item list with countdown and Next Up panel, but no Go/Back/Start/Stop controls. Safe to share with volunteers.',
              url: urls.readonlyShowUrl,
              badge: 'Read only',
              badgeBg: 'rgba(0,230,118,0.12)',
              badgeColor: '#00E676',
              accent: '#00E676',
            })
          ],
          { label: 'Operator', bg: 'rgba(255,167,38,0.10)', fg: '#FFB74D' }
        ));
      }

      if (urls.prompterUrl) {
        sections.push(_rundownBuildSectionCard(
          'Teleprompter',
          'Full-screen scrolling teleprompter output. Auto-scrolls to follow live cues. Supports mirror mode, font sizing, dark/light themes, and keyboard shortcuts.',
          [
            _rundownBuildOutputCard({
              kicker: 'Output',
              title: 'Teleprompter',
              description: 'High-contrast scrolling script display. Mirrors for teleprompter glass. Auto-follows live cue advances.',
              url: urls.prompterUrl,
              badge: 'New',
              badgeBg: 'rgba(206,147,216,0.12)',
              badgeColor: '#CE93D8',
              accent: '#CE93D8',
            })
          ],
          { label: 'Teleprompter', bg: 'rgba(206,147,216,0.10)', fg: '#CE93D8' }
        ));
      }

      if (publicUrl) {
        sections.push(_rundownBuildSectionCard(
          'Public view modes',
          'Read-only public views built from the same token. Full view is best for desk-side review; compact and large text are better on larger screens.',
          [
            _rundownBuildOutputCard({
              kicker: 'Primary view',
              title: 'Full rundown',
              description: 'All items, columns, attachments, and timing details in one read-only view.',
              url: _rundownBuildModeUrl(publicUrl, '', {}),
              badge: 'Recommended',
              badgeBg: 'rgba(0,230,118,0.12)',
              badgeColor: '#00E676',
              accent: '#00E676',
            }),
            _rundownBuildOutputCard({
              kicker: 'Compact view',
              title: 'Compact rundown',
              description: 'A tighter layout for quick references and smaller operator displays.',
              url: _rundownBuildModeUrl(publicUrl, 'compact', {}),
              badge: 'Fast glance',
              badgeBg: 'rgba(66,165,245,0.10)',
              badgeColor: '#81D4FA',
              accent: '#81D4FA',
            }),
            _rundownBuildOutputCard({
              kicker: 'Large Text view',
              title: 'Large Text',
              description: 'Full-screen, stage-friendly layout that keeps the active item centered.',
              url: _rundownBuildModeUrl(publicUrl, 'prompter', {}),
              badge: 'Stage ready',
              badgeBg: 'rgba(171,71,188,0.10)',
              badgeColor: '#CE93D8',
              accent: '#CE93D8',
            })
          ],
          { label: 'Read only', bg: 'rgba(0,230,118,0.12)', fg: '#00E676' }
        ));
      }

      if (timerUrl) {
        timerSections.push(_rundownBuildSectionCard(
          'Timer modes',
          'The same token powers every countdown view. Use the default timer for speakers, detailed mode for production screens, and stage display mode for high-visibility countdowns.',
          [
            _rundownBuildOutputCard({
              kicker: 'Default timer',
              title: 'Countdown timer',
              description: 'The lightweight speaker countdown display.',
              url: _rundownBuildModeUrl(timerUrl, '', {}),
              badge: 'Default',
              badgeBg: 'rgba(0,230,118,0.12)',
              badgeColor: '#00E676',
              accent: '#00E676',
            }),
            _rundownBuildOutputCard({
              kicker: 'Detailed mode',
              title: 'Detailed timer',
              description: 'A larger layout with more context for production teams.',
              url: _rundownBuildModeUrl(timerUrl, 'stage', {}),
              badge: 'Big display',
              badgeBg: 'rgba(255,167,38,0.10)',
              badgeColor: '#FFB74D',
              accent: '#FFB74D',
            }),
            _rundownBuildOutputCard({
              kicker: 'High visibility',
              title: 'Stage Display timer',
              description: 'A highly readable timer for fast-moving live service environments.',
              url: _rundownBuildModeUrl(timerUrl, 'confidence', {}),
              badge: 'Stage Display',
              badgeBg: 'rgba(66,165,245,0.10)',
              badgeColor: '#81D4FA',
              accent: '#81D4FA',
            })
          ],
          { label: 'Timers', bg: 'rgba(66,165,245,0.10)', fg: '#81D4FA' }
        ));
      }

      // Production displays: teleprompter, confidence monitor, studio clock
      var productionSections = [];
      if (publicUrl) {
        productionSections.push(_rundownBuildSectionCard(
          'Production displays',
          'Specialized full-screen views for stage, green room, and studio environments. Each runs from the same share token.',
          [
            _rundownBuildOutputCard({
              kicker: 'Presenter aid',
              title: 'Teleprompter',
              description: 'Full-screen scrolling view showing the current item title, notes, and script in large readable text. Ideal for confidence monitors facing presenters.',
              url: _rundownBuildModeUrl(publicUrl, 'teleprompter', {}),
              badge: 'Stage',
              badgeBg: 'rgba(171,71,188,0.10)',
              badgeColor: '#CE93D8',
              accent: '#CE93D8',
            }),
            _rundownBuildOutputCard({
              kicker: 'Green room',
              title: 'Confidence Monitor',
              description: 'Displays the current and next item with countdown, designed for backstage or green room screens so talent knows what is coming.',
              url: _rundownBuildModeUrl(publicUrl, 'confidence', {}),
              badge: 'Backstage',
              badgeBg: 'rgba(0,230,118,0.12)',
              badgeColor: '#00E676',
              accent: '#00E676',
            }),
            _rundownBuildOutputCard({
              kicker: 'Studio utility',
              title: 'Studio Clock',
              description: 'Large wall-clock display with current time, service elapsed time, and current cue countdown. Perfect for control rooms.',
              url: _rundownBuildModeUrl(publicUrl, 'clock', {}),
              badge: 'Utility',
              badgeBg: 'rgba(255,167,38,0.10)',
              badgeColor: '#FFB74D',
              accent: '#FFB74D',
            })
          ],
          { label: 'Production', bg: 'rgba(171,71,188,0.10)', fg: '#CE93D8' }
        ));
      }

      if (outputSuite) {
        outputSuite.innerHTML = sections.concat(timerSections).concat(productionSections).join('');
      }

      if (_rundownSelectedPlan && _rundownSelectedPlan.source !== 'pco' && Array.isArray(_rundownColumns)) {
        for (var i = 0; i < _rundownColumns.length; i++) {
          var column = _rundownColumns[i];
          if (!column || !column.id) continue;
          var operatorUrl = _rundownBuildOperatorOutputUrl(publicUrl || '', column.id);
          if (!operatorUrl) continue;
          hasOperatorLinks = true;
          operatorItems.push(
            '<div style="padding:12px 14px;border-radius:12px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07)">'
              + '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px">'
                + '<div style="min-width:0;flex:1">'
                  + '<div style="font-size:11px;text-transform:uppercase;letter-spacing:0.8px;color:#00E676;font-weight:800;margin-bottom:4px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escapeHtml(column.name || column.id) + '</div>'
                  + '<div style="font-size:12px;color:#8B9DAF;line-height:1.45">Filtered feed for this custom column.</div>'
                + '</div>'
                + '<span style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;padding:2px 8px;border-radius:10px;background:rgba(0,230,118,0.12);color:#00E676">Column</span>'
              + '</div>'
              + '<div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:10px">'
                + '<button class="btn-primary" style="font-size:12px;padding:6px 14px" data-rundown-output-open="' + escapeHtml(operatorUrl) + '">Open</button>'
                + '<button class="btn-secondary" style="font-size:12px;padding:6px 14px" data-share-copy-url="' + escapeHtml(operatorUrl) + '" data-copy-default-label="Copy Link">Copy</button>'
              + '</div>'
              + '<div style="margin-top:8px;font-family:ui-monospace,monospace;font-size:11px;color:#556270;word-break:break-all;line-height:1.4">' + escapeHtml(operatorUrl) + '</div>'
            + '</div>'
          );
        }
      }

      // Build "Share with Team" text message templates for each column
      var teamShareItems = [];
      var planTitle = (_rundownSelectedPlan && _rundownSelectedPlan.title) ? _rundownSelectedPlan.title : 'the rundown';
      if (_rundownSelectedPlan && _rundownSelectedPlan.source !== 'pco' && Array.isArray(_rundownColumns)) {
        for (var t = 0; t < _rundownColumns.length; t++) {
          var col = _rundownColumns[t];
          if (!col || !col.id) continue;
          var colUrl = _rundownBuildOperatorOutputUrl(publicUrl || '', col.id);
          if (!colUrl) continue;
          var msgText = 'Hey! Here\u2019s your ' + (col.name || col.id) + ' feed for ' + planTitle + ':\n' + colUrl + '\n\nThis link auto-updates and follows the live cue.';
          teamShareItems.push(
            '<div style="padding:10px 12px;border-radius:10px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.06)">'
              + '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:6px">'
                + '<div style="font-size:12px;font-weight:700;color:#F0F2F4">' + escapeHtml(col.name || col.id) + '</div>'
                + '<button class="btn-secondary" style="font-size:11px;padding:4px 10px" data-share-copy-url="' + escapeHtml(colUrl) + '" data-copy-default-label="Copy Link">Copy Link</button>'
              + '</div>'
              + '<div style="font-size:11px;color:#8B9DAF;line-height:1.5;white-space:pre-line;background:rgba(255,255,255,0.03);padding:8px 10px;border-radius:8px;border:1px solid rgba(255,255,255,0.05)">' + escapeHtml(msgText) + '</div>'
              + '<button class="btn-secondary" style="font-size:11px;padding:4px 10px;margin-top:6px" data-share-copy-url="' + escapeHtml(msgText) + '" data-copy-default-label="Copy Message">Copy Message</button>'
            + '</div>'
          );
        }
      }
      // Also add a generic read-only show link message
      if (urls.readonlyShowUrl) {
        var roMsg = 'Hey! Follow along with ' + planTitle + ' live:\n' + urls.readonlyShowUrl + '\n\nYou\u2019ll see the current cue, countdown, and what\u2019s next.';
        teamShareItems.unshift(
          '<div style="padding:10px 12px;border-radius:10px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.06)">'
            + '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:6px">'
              + '<div style="font-size:12px;font-weight:700;color:#F0F2F4">Live Follow-Along (Read Only)</div>'
              + '<button class="btn-secondary" style="font-size:11px;padding:4px 10px" data-share-copy-url="' + escapeHtml(urls.readonlyShowUrl) + '" data-copy-default-label="Copy Link">Copy Link</button>'
            + '</div>'
            + '<div style="font-size:11px;color:#8B9DAF;line-height:1.5;white-space:pre-line;background:rgba(255,255,255,0.03);padding:8px 10px;border-radius:8px;border:1px solid rgba(255,255,255,0.05)">' + escapeHtml(roMsg) + '</div>'
            + '<button class="btn-secondary" style="font-size:11px;padding:4px 10px;margin-top:6px" data-share-copy-url="' + escapeHtml(roMsg) + '" data-copy-default-label="Copy Message">Copy Message</button>'
          + '</div>'
        );
      }
      var teamShareWrap = document.getElementById('rundown-share-team-wrap');
      var teamShareList = document.getElementById('rundown-share-team-links');
      if (teamShareList) teamShareList.innerHTML = teamShareItems.join('');
      if (teamShareWrap) teamShareWrap.style.display = teamShareItems.length ? '' : 'none';

      if (operatorLinks) operatorLinks.innerHTML = operatorItems.join('');
      if (operatorWrap) {
        operatorWrap.style.display = hasOperatorLinks ? '' : 'none';
      }

      if (expiryEl && share && share.expiresAt) {
        var exp = new Date(share.expiresAt);
        expiryEl.textContent = 'Shared link expires ' + exp.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
      }
    }

    function _rundownEnsureShare(planId) {
      return api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/share').then(function(data) {
        if (data && data.share) return data.share;
        return api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/share');
      });
    }

    function _updateSharedBadge(hasShare) {
      var badge = document.getElementById('rundown-shared-badge');
      if (badge) badge.style.display = hasShare ? '' : 'none';
    }

    function rundownShare() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      var planId = _rundownSelectedPlan.id;
      var backdrop = document.getElementById('modal-rundown-share');
      var loadingEl = document.getElementById('rundown-share-loading');
      var contentEl = document.getElementById('rundown-share-content');
      var errorEl = document.getElementById('rundown-share-error');
      if (!backdrop) return;
      if (loadingEl) loadingEl.style.display = '';
      if (contentEl) contentEl.style.display = 'none';
      if (errorEl) errorEl.style.display = 'none';
      backdrop.classList.add('open');

      _rundownEnsureShare(planId).then(function(share) {
        _rundownShareData = share;
        if (loadingEl) loadingEl.style.display = 'none';
        _rundownRenderShareLinks(share);
        if (contentEl) contentEl.style.display = '';
        _updateSharedBadge(true);
      }).catch(function(e) {
        if (loadingEl) loadingEl.style.display = 'none';
        if (errorEl) { errorEl.textContent = 'Failed: ' + (e.message || 'Unknown error'); errorEl.style.display = ''; }
      });
    }

    function rundownOpenShowMode() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      var openShow = function(share) {
        _rundownShareData = share;
        var urls = _rundownResolveShareUrls(share || {});
        if (urls.showUrl) _rundownOpenUrl(urls.showUrl);
        _updateSharedBadge(true);
      };
      if (_rundownShareData && _rundownShareData.share_token) {
        openShow(_rundownShareData);
        return;
      }
      var planId = _rundownSelectedPlan.id;
      _rundownEnsureShare(planId).then(openShow).catch(function(e) { toast('Failed to open show mode: ' + e.message, true); });
    }

    function rundownOpenPublicView() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      var openView = function(share) {
        _rundownShareData = share;
        var urls = _rundownResolveShareUrls(share || {});
        if (urls.publicUrl) _rundownOpenUrl(urls.publicUrl);
        _updateSharedBadge(true);
      };
      if (_rundownShareData && _rundownShareData.share_token) {
        openView(_rundownShareData);
        return;
      }
      var planId = _rundownSelectedPlan.id;
      _rundownEnsureShare(planId).then(openView).catch(function(e) { toast('Failed to open public view: ' + e.message, true); });
    }

    function rundownLaunchDemoSet() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      var openWindows = function(share) {
        _rundownShareData = share;
        var setup = _rundownBuildDemoSetup(share);
        [setup.publicUrl || setup.compactUrl, setup.prompterUrl || setup.publicUrl, setup.stageUrl || setup.timerUrl].filter(Boolean).forEach(function(url) {
          _rundownOpenUrl(url);
        });
        _updateSharedBadge(true);
        toast('Opened sample setup');
      };
      if (_rundownShareData && _rundownShareData.share_token) {
        openWindows(_rundownShareData);
        return;
      }
      _rundownEnsureShare(_rundownSelectedPlan.id).then(openWindows).catch(function(e) { toast('Failed to launch demo set: ' + e.message, true); });
    }

    function rundownCopyDemoSetup(buttonEl) {
      var setup = _rundownBuildDemoSetup(_rundownShareData || {});
      if (!setup.note) return;
      _rundownCopyTextToClipboard(setup.note, buttonEl, 'Copy Setup Notes');
    }

    function rundownCopyCollaboratorSetup(buttonEl) {
      var selfKey = _rundownSessionId || '';
      var selfName = _rundownPresenceDisplayName || _rundownDefaultStationName();
      var note = [
        'Tally device setup',
        '',
        '1. Open the rundown on the operator device.',
        '2. Open Team Access.',
        '3. Set the device name and device key.',
        '4. Save the device, then give it the right role:',
        '   Owner manages access',
        '   Editor can run and update the service',
        '   Viewer stays read only',
        '',
        'This device:',
        'Name: ' + selfName,
        'Key: ' + (selfKey || 'not set'),
      ].join('\n');
      _rundownCopyTextToClipboard(note, buttonEl, 'Copy Setup Notes');
    }

    function rundownCopyShareLink() {
      var urls = _rundownResolveShareUrls(_rundownShareData || {});
      var url = _rundownBuildModeUrl(urls.publicUrl, '', {});
      if (!url) return;
      _rundownCopyTextToClipboard(url, null, 'Copy Link');
    }

    function rundownCopyTimerLink() {
      var urls = _rundownResolveShareUrls(_rundownShareData || {});
      var url = _rundownBuildModeUrl(urls.timerUrl, '', {});
      if (!url) return;
      _rundownCopyTextToClipboard(url, null, 'Copy Link');
    }

    function rundownRevokeShare() {
      if (!_rundownSelectedPlan) return;
      var planId = _rundownSelectedPlan.id;
      styledConfirm('Revoke Access', 'Anyone with the current link will lose access. You can create a new link later.').then(function(ok) {
        if (!ok) return;
        api('DELETE', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/share').then(function() {
          _rundownShareData = null;
          _updateSharedBadge(false);
          var backdrop = document.getElementById('modal-rundown-share');
          if (backdrop) backdrop.classList.remove('open');
          toast('Share link revoked');
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    (function() {
      var closeBtn = document.getElementById('rundown-share-modal-close');
      var backdrop = document.getElementById('modal-rundown-share');
      var launchDemoBtn = document.getElementById('rundown-share-launch-demo-btn');
      var copyDemoBtn = document.getElementById('rundown-share-copy-demo-btn');
      var revokeBtn = document.getElementById('rundown-share-revoke-btn');
      var contentEl = document.getElementById('rundown-share-content');
      if (closeBtn) closeBtn.addEventListener('click', function() { if (backdrop) backdrop.classList.remove('open'); });
      if (backdrop) backdrop.addEventListener('click', function(e) { if (e.target === backdrop) backdrop.classList.remove('open'); });
      if (launchDemoBtn) launchDemoBtn.addEventListener('click', rundownLaunchDemoSet);
      if (copyDemoBtn) copyDemoBtn.addEventListener('click', function() { rundownCopyDemoSetup(copyDemoBtn); });
      if (revokeBtn) revokeBtn.addEventListener('click', function() { if (typeof rundownRevokeShare === 'function') rundownRevokeShare(); });
      if (contentEl && !contentEl._rundownShareCopyDelegateBound) {
        contentEl._rundownShareCopyDelegateBound = true;
        contentEl.addEventListener('click', function(e) {
          var openBtn = e.target && e.target.closest ? e.target.closest('[data-rundown-output-open]') : null;
          if (openBtn) {
            var openUrl = openBtn.dataset.rundownOutputOpen || '';
            if (openUrl) _rundownOpenUrl(openUrl);
            return;
          }
          var btn = e.target && e.target.closest ? e.target.closest('[data-share-copy-url]') : null;
          if (!btn) return;
          var url = btn.dataset.shareCopyUrl || '';
          if (!url) return;
          _rundownCopyTextToClipboard(url, btn, btn.dataset.copyDefaultLabel || 'Copy');
        });
      }
    })();

    (function() {
      var closeBtn = document.getElementById('rundown-collaborators-modal-close');
      var backdrop = document.getElementById('modal-rundown-collaborators');
      var saveStationBtn = document.getElementById('rundown-station-save');
      var copyStationBtn = document.getElementById('rundown-station-copy-key');
      var copySetupBtn = document.getElementById('rundown-collaborators-copy-note');
      var addCollaboratorBtn = document.getElementById('rundown-collaborator-add');
      if (closeBtn) closeBtn.addEventListener('click', _rundownCloseCollaborators);
      if (backdrop) backdrop.addEventListener('click', function(e) {
        if (e.target === backdrop) _rundownCloseCollaborators();
      });
      if (saveStationBtn) saveStationBtn.addEventListener('click', rundownSaveStationIdentity);
      if (copyStationBtn) copyStationBtn.addEventListener('click', function() {
        rundownCopyStationKey(copyStationBtn);
      });
      if (copySetupBtn) copySetupBtn.addEventListener('click', function() {
        rundownCopyCollaboratorSetup(copySetupBtn);
      });
      if (addCollaboratorBtn) addCollaboratorBtn.addEventListener('click', rundownAddCollaborator);
    })();

    // ── Start Live ────────────────────────────────────────────────────────────

    function rundownStartLive() {
      if (!_rundownSelectedPlan) return;
      var source = _rundownSelectedPlan.source || 'manual';
      var roomId = _rundownSelectedPlan.roomId || _selectedRoomId || '';
      api('POST', '/api/churches/' + CHURCH_ID + '/live-rundown/start', {
        planId: _rundownSelectedPlan.id,
        source: source,
        callerName: 'TD',
        roomId: roomId,
      }).then(function(data) {
        _rundownState = data;
        _rundownStatsByRoom[data.roomId || ''] = data;
        showRundownView('active');
        renderRundownActive(data);
        toast('Rundown started');
      }).catch(function(e) { toast('Failed to start: ' + e.message, true); });
    }

    function rundownEndSession() {
      var roomId = _rundownState ? (_rundownState.roomId || '') : (_selectedRoomId || '');
      styledConfirm('End Session', 'End the live rundown session?').then(function(ok) {
        if (!ok) return;
        api('POST', '/api/churches/' + CHURCH_ID + '/live-rundown/end', { roomId: roomId }).then(function() {
          delete _rundownStatsByRoom[roomId];
          _rundownState = null;
          toast('Session ended');
          loadRundownManager();
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    // ── Phase 9: Edit lock indicators (9.1) ──────────────────────────────────

    function _renderRundownEditLockIndicators() {
      var rows = document.querySelectorAll('#rundown-editor-items tr[data-item-id]');
      rows.forEach(function(row) {
        var itemId = row.getAttribute('data-item-id');
        var lockEl = row.querySelector('.rundown-edit-lock');
        var lock = _rundownEditLocks[itemId];
        if (lock && lock.sessionId !== _rundownSessionId && (Date.now() - lock.lockedAt) < 60000) {
          if (!lockEl) {
            lockEl = document.createElement('span');
            lockEl.className = 'rundown-edit-lock';
            lockEl.style.cssText = 'display:inline-block;font-size:10px;color:#FFD740;background:rgba(255,215,64,0.12);padding:2px 6px;border-radius:4px;margin-left:6px;white-space:nowrap';
            var titleCell = row.querySelector('td:nth-child(2)');
            if (titleCell) titleCell.appendChild(lockEl);
          }
          lockEl.textContent = 'Editing: ' + (lock.displayName || 'Someone');
          lockEl.style.display = '';
        } else if (lockEl) {
          lockEl.style.display = 'none';
        }
      });
    }

    function _rundownAcquireEditLock(itemId) {
      if (!_rundownSelectedPlan) return Promise.resolve({ locked: false });
      return api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + itemId + '/lock', {
        sessionId: _rundownSessionId, displayName: _rundownPresenceDisplayName || 'TD'
      });
    }

    function _rundownReleaseEditLock(itemId) {
      if (!_rundownSelectedPlan) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + itemId + '/unlock', {
        sessionId: _rundownSessionId
      }).catch(function() {});
    }

    // ── Phase 9: Plan locking (9.3) ────────────────────────────────────────

    function rundownLockPlan() {
      if (!_rundownSelectedPlan) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/lock', {
        sessionId: _rundownSessionId, displayName: _rundownPresenceDisplayName || 'TD'
      }).then(function(plan) {
        _rundownSelectedPlan = plan;
        renderRundownEditor(plan);
        toast('Plan locked for show');
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function rundownUnlockPlan() {
      if (!_rundownSelectedPlan) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/unlock', {
        sessionId: _rundownSessionId, displayName: _rundownPresenceDisplayName || 'TD'
      }).then(function(plan) {
        _rundownSelectedPlan = plan;
        renderRundownEditor(plan);
        toast('Plan unlocked');
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function _isPlanLocked() {
      return _rundownSelectedPlan && _rundownSelectedPlan.lockedBy &&
        _rundownSelectedPlan.lockedBy !== _rundownSessionId;
    }

    // ── Phase 9: Revision history (9.2) ────────────────────────────────────

    function rundownShowRevisionHistory() {
      if (!_rundownSelectedPlan) return;
      api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/revisions').then(function(data) {
        var revisions = data.revisions || [];
        _showRevisionPanel(revisions);
      }).catch(function(e) { toast('Failed to load history: ' + e.message, true); });
    }

    function _showRevisionPanel(revisions) {
      var existing = document.getElementById('rundown-revision-panel');
      if (existing) existing.remove();
      var overlay = document.createElement('div');
      overlay.id = 'rundown-revision-panel';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px)';
      var html = '<div style="background:#0a1610;border:1px solid #0d3320;border-radius:16px;padding:24px;max-width:700px;width:95%;max-height:80vh;overflow-y:auto">'
        + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">'
        + '<div style="font-size:16px;font-weight:700;color:#F0F2F4">Revision History</div>'
        + '<button id="close-revision-panel" class="btn-secondary" style="font-size:12px;padding:4px 12px">Close</button></div>';
      if (!revisions.length) {
        html += '<div style="text-align:center;padding:40px;color:#8B9DAF;font-size:13px">No revisions yet. Edits are automatically tracked.</div>';
      } else {
        html += '<div style="display:flex;flex-direction:column;gap:8px">';
        revisions.forEach(function(rev) {
          var snap = rev.snapshot || {};
          var diff = rev.diff || {};
          var changedFields = Object.keys(diff).filter(function(k) { return k !== 'sessionId' && k !== 'displayName' && k !== 'userName'; });
          var time = new Date(rev.changedAt);
          var timeStr = time.toLocaleString();
          html += '<div style="background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07);border-radius:10px;padding:12px">'
            + '<div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">'
            + '<div>'
            + '<span style="font-size:13px;font-weight:700;color:#F0F2F4">' + escapeHtml(snap.title || 'Item') + '</span>'
            + '<span style="font-size:11px;color:#8B9DAF;margin-left:8px">Rev #' + rev.revisionNumber + '</span>'
            + '</div>'
            + '<div style="font-size:11px;color:#8B9DAF">' + escapeHtml(rev.changedBy || 'Unknown') + ' · ' + escapeHtml(timeStr) + '</div>'
            + '</div>';
          if (changedFields.length > 0) {
            html += '<div style="margin-top:8px;font-size:12px;color:#556270">Changed: ' + changedFields.map(function(f) { return '<span style="color:#81D4FA">' + escapeHtml(f) + '</span>'; }).join(', ') + '</div>';
          }
          html += '<button class="btn-secondary" data-action="rundownRevertRevision" data-revision-id="' + rev.id + '" style="margin-top:8px;font-size:11px;padding:4px 10px">Revert to this</button>';
          html += '</div>';
        });
        html += '</div>';
      }
      html += '</div>';
      overlay.innerHTML = html;
      document.body.appendChild(overlay);
      document.getElementById('close-revision-panel').addEventListener('click', function() { overlay.remove(); });
      overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
    }

    function rundownRevertRevision(revisionId) {
      if (!_rundownSelectedPlan) return;
      styledConfirm('Revert Plan', 'Revert this plan to revision #' + revisionId + '? This will replace the current version.').then(function(ok) {
        if (!ok) return;
        api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/revisions/' + revisionId + '/revert', {
          sessionId: _rundownSessionId
        }).then(function(plan) {
          _rundownSelectedPlan = plan;
          renderRundownEditor(plan);
          toast('Item reverted');
          var panel = document.getElementById('rundown-revision-panel');
          if (panel) panel.remove();
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    // Phase 11: Ctrl+Z / Cmd+Z for undo, Ctrl+Shift+Z / Cmd+Shift+Z for redo
    document.addEventListener('keydown', function(e) {
      var editorVisible = _rundownSelectedPlan && document.getElementById('rundown-editor') && document.getElementById('rundown-editor').style.display !== 'none';
      if (!editorVisible) return;
      var isEditing = document.activeElement && (document.activeElement.tagName === 'INPUT' || document.activeElement.tagName === 'TEXTAREA' || document.activeElement.tagName === 'SELECT' || document.activeElement.isContentEditable);

      if ((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) {
        e.preventDefault();
        if (_rundownUndoStack.length > 0) _rundownUndo();
        else rundownShowRevisionHistory();
        return;
      }
      if ((e.ctrlKey || e.metaKey) && (e.key === 'Z' || (e.key === 'z' && e.shiftKey))) {
        e.preventDefault();
        _rundownRedo();
        return;
      }

      // Quick-add keyboard shortcuts (only when not editing a field)
      if (isEditing) return;
      if (e.key === 'a' || e.key === 'A') {
        if (!e.ctrlKey && !e.metaKey) {
          e.preventDefault();
          rundownAddItemInline();
        }
      } else if (e.key === 'i' || e.key === 'I') {
        if (!e.ctrlKey && !e.metaKey) {
          e.preventDefault();
          _rundownInsertItemAfterSelected();
        }
      }
    });

    // ── Phase 9: Rehearsal mode (9.4) ──────────────────────────────────────

    function rundownStartRehearsal() {
      if (!_rundownSelectedPlan) return;
      styledConfirm('Start Rehearsal', 'Start a timed rehearsal run? This will track actual time per item for comparison.').then(function(ok) {
        if (!ok) return;
        api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/rehearsal/start', {
          sessionId: _rundownSessionId
        }).then(function(run) {
          _rundownActiveRehearsalRun = run;
          _rundownRehearsalCurrentIndex = 0;
          _rundownRehearsalTimings = [];
          var items = (_rundownSelectedPlan.items || []).filter(function(it) { return it.itemType !== 'section'; });
          _rundownRehearsalItemStart = Date.now();
          toast('Rehearsal #' + run.runNumber + ' started');
          _renderRehearsalBar();
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    function _renderRehearsalBar() {
      var bar = document.getElementById('rundown-rehearsal-bar');
      if (!_rundownActiveRehearsalRun) {
        if (bar) bar.style.display = 'none';
        return;
      }
      if (!bar) {
        bar = document.createElement('div');
        bar.id = 'rundown-rehearsal-bar';
        var startArea = document.getElementById('rundown-start-show-area');
        if (startArea) startArea.parentNode.insertBefore(bar, startArea);
        else return;
      }
      bar.style.display = '';
      var items = (_rundownSelectedPlan.items || []).filter(function(it) { return it.itemType !== 'section'; });
      var currentItem = items[_rundownRehearsalCurrentIndex];
      var elapsed = _rundownRehearsalItemStart ? Math.round((Date.now() - _rundownRehearsalItemStart) / 1000) : 0;
      var planned = currentItem ? (currentItem.lengthSeconds || 0) : 0;
      var isOver = planned > 0 && elapsed > planned;
      bar.innerHTML = '<div style="background:rgba(66,165,245,0.08);border:1px solid rgba(66,165,245,0.2);border-radius:10px;padding:12px 16px;margin-bottom:12px">'
        + '<div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px">'
        + '<div style="display:flex;align-items:center;gap:10px">'
        + '<span style="background:#42A5F5;color:#060D08;font-size:10px;font-weight:800;padding:3px 8px;border-radius:4px;text-transform:uppercase;letter-spacing:1px">Rehearsal</span>'
        + '<span style="font-size:13px;font-weight:700;color:#F0F2F4">Run #' + _rundownActiveRehearsalRun.runNumber + '</span>'
        + '<span style="font-size:12px;color:#8B9DAF">Item ' + (_rundownRehearsalCurrentIndex + 1) + '/' + items.length + '</span>'
        + '</div>'
        + '<div style="display:flex;align-items:center;gap:10px">'
        + '<span style="font-family:ui-monospace,monospace;font-size:14px;font-weight:700;color:' + (isOver ? '#FF5252' : '#F0F2F4') + '">' + _fmtDuration(elapsed) + (planned > 0 ? ' / ' + _fmtDuration(planned) : '') + '</span>'
        + '<button class="btn-secondary" data-action="rundownRehearsalAdvance" style="font-size:12px;padding:5px 14px;font-weight:700">Next</button>'
        + '<button class="btn-secondary" data-action="rundownRehearsalEnd" style="font-size:12px;padding:5px 14px;color:#FF5252">End</button>'
        + '</div></div></div>';
      // Highlight current item
      var allRows = document.querySelectorAll('#rundown-editor-items tr[data-item-id]');
      var playableIdx = 0;
      allRows.forEach(function(row) {
        var itemId = row.getAttribute('data-item-id');
        var it = (_rundownSelectedPlan.items || []).find(function(x) { return x.id === itemId; });
        if (it && it.itemType !== 'section') {
          if (playableIdx === _rundownRehearsalCurrentIndex) {
            row.style.background = 'rgba(66,165,245,0.08)';
          } else {
            row.style.background = '';
          }
          playableIdx++;
        }
      });
    }

    var _rehearsalTickTimer = null;
    function _startRehearsalTick() {
      _stopRehearsalTick();
      _rehearsalTickTimer = setInterval(function() { _renderRehearsalBar(); }, 1000);
    }
    function _stopRehearsalTick() {
      if (_rehearsalTickTimer) { clearInterval(_rehearsalTickTimer); _rehearsalTickTimer = null; }
    }

    function rundownRehearsalAdvance() {
      if (!_rundownActiveRehearsalRun || !_rundownSelectedPlan) return;
      var items = (_rundownSelectedPlan.items || []).filter(function(it) { return it.itemType !== 'section'; });
      var currentItem = items[_rundownRehearsalCurrentIndex];
      var elapsed = _rundownRehearsalItemStart ? (Date.now() - _rundownRehearsalItemStart) : 0;
      _rundownRehearsalTimings.push({
        itemId: currentItem ? currentItem.id : '',
        title: currentItem ? currentItem.title : '',
        plannedDuration: currentItem ? (currentItem.lengthSeconds || 0) * 1000 : 0,
        actualDuration: elapsed,
      });
      _rundownRehearsalCurrentIndex++;
      if (_rundownRehearsalCurrentIndex >= items.length) {
        rundownEndRehearsal();
        return;
      }
      _rundownRehearsalItemStart = Date.now();
      _renderRehearsalBar();
    }

    function rundownEndRehearsal() {
      if (!_rundownActiveRehearsalRun || !_rundownSelectedPlan) return;
      // Record timing for current item if not already recorded
      var items = (_rundownSelectedPlan.items || []).filter(function(it) { return it.itemType !== 'section'; });
      if (_rundownRehearsalCurrentIndex < items.length) {
        var currentItem = items[_rundownRehearsalCurrentIndex];
        var elapsed = _rundownRehearsalItemStart ? (Date.now() - _rundownRehearsalItemStart) : 0;
        _rundownRehearsalTimings.push({
          itemId: currentItem ? currentItem.id : '',
          title: currentItem ? currentItem.title : '',
          plannedDuration: currentItem ? (currentItem.lengthSeconds || 0) * 1000 : 0,
          actualDuration: elapsed,
        });
      }
      _stopRehearsalTick();
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/rehearsal/' + _rundownActiveRehearsalRun.id + '/end', {
        sessionId: _rundownSessionId, itemTimings: _rundownRehearsalTimings
      }).then(function(run) {
        _rundownActiveRehearsalRun = null;
        _rundownRehearsalTimings = [];
        _rundownRehearsalCurrentIndex = 0;
        _rundownRehearsalItemStart = null;
        _renderRehearsalBar();
        // Re-render items (remove highlighting)
        if (_rundownSelectedPlan) renderRundownEditorItems(_rundownSelectedPlan.items || []);
        _showRehearsalSummary(run);
        // Reload plan to get updated status
        api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id).then(function(plan) {
          _rundownSelectedPlan = plan;
          renderRundownEditor(plan);
        }).catch(function() {});
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function _showRehearsalSummary(run) {
      var existing = document.getElementById('rundown-rehearsal-summary');
      if (existing) existing.remove();
      var overlay = document.createElement('div');
      overlay.id = 'rundown-rehearsal-summary';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px)';
      var timings = run.itemTimings || [];
      var totalPlanned = run.totalPlannedMs || 0;
      var totalActual = run.totalActualMs || timings.reduce(function(s, t) { return s + (t.actualDuration || 0); }, 0);
      var variance = totalActual - totalPlanned;
      var overItems = timings.filter(function(t) { return t.actualDuration > t.plannedDuration && t.plannedDuration > 0; });
      var underItems = timings.filter(function(t) { return t.actualDuration < t.plannedDuration && t.plannedDuration > 0; });
      var html = '<div style="background:#0a1610;border:1px solid #0d3320;border-radius:16px;padding:24px;max-width:600px;width:95%;max-height:80vh;overflow-y:auto">'
        + '<div style="font-size:16px;font-weight:700;color:#F0F2F4;margin-bottom:16px">Rehearsal #' + (run.runNumber || '?') + ' Summary</div>'
        + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:16px">'
        + '<div style="background:rgba(255,255,255,0.04);border-radius:8px;padding:12px;text-align:center"><div style="font-size:10px;color:#8B9DAF;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px">Planned</div><div style="font-size:16px;font-weight:800;font-family:ui-monospace,monospace">' + _fmtDurationMs(totalPlanned) + '</div></div>'
        + '<div style="background:rgba(255,255,255,0.04);border-radius:8px;padding:12px;text-align:center"><div style="font-size:10px;color:#8B9DAF;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px">Actual</div><div style="font-size:16px;font-weight:800;font-family:ui-monospace,monospace">' + _fmtDurationMs(totalActual) + '</div></div>'
        + '<div style="background:rgba(255,255,255,0.04);border-radius:8px;padding:12px;text-align:center"><div style="font-size:10px;color:#8B9DAF;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px">Variance</div><div style="font-size:16px;font-weight:800;font-family:ui-monospace,monospace;color:' + (variance > 0 ? '#FF5252' : variance < 0 ? '#00E676' : '#F0F2F4') + '">' + (variance > 0 ? '+' : '') + _fmtDurationMs(variance) + '</div></div>'
        + '</div>';
      if (timings.length > 0) {
        html += '<table style="width:100%;border-collapse:collapse;font-size:12px">'
          + '<thead><tr><th style="text-align:left;padding:6px 8px;font-size:10px;text-transform:uppercase;color:#8B9DAF;border-bottom:1px solid rgba(255,255,255,0.08)">Item</th>'
          + '<th style="padding:6px 8px;font-size:10px;text-transform:uppercase;color:#8B9DAF;border-bottom:1px solid rgba(255,255,255,0.08)">Planned</th>'
          + '<th style="padding:6px 8px;font-size:10px;text-transform:uppercase;color:#8B9DAF;border-bottom:1px solid rgba(255,255,255,0.08)">Actual</th>'
          + '<th style="padding:6px 8px;font-size:10px;text-transform:uppercase;color:#8B9DAF;border-bottom:1px solid rgba(255,255,255,0.08)">Variance</th></tr></thead><tbody>';
        timings.forEach(function(t) {
          var v = (t.actualDuration || 0) - (t.plannedDuration || 0);
          var isOver = v > 0 && (t.plannedDuration || 0) > 0;
          html += '<tr style="' + (isOver ? 'background:rgba(255,82,82,0.06)' : '') + '">'
            + '<td style="padding:6px 8px;border-bottom:1px solid rgba(255,255,255,0.04)">' + escapeHtml(t.title || 'Item') + '</td>'
            + '<td style="padding:6px 8px;border-bottom:1px solid rgba(255,255,255,0.04);font-family:ui-monospace,monospace;text-align:center">' + _fmtDurationMs(t.plannedDuration) + '</td>'
            + '<td style="padding:6px 8px;border-bottom:1px solid rgba(255,255,255,0.04);font-family:ui-monospace,monospace;text-align:center">' + _fmtDurationMs(t.actualDuration) + '</td>'
            + '<td style="padding:6px 8px;border-bottom:1px solid rgba(255,255,255,0.04);font-family:ui-monospace,monospace;text-align:center;color:' + (v > 0 ? '#FF5252' : v < 0 ? '#00E676' : '#F0F2F4') + '">' + (v > 0 ? '+' : '') + _fmtDurationMs(v) + '</td></tr>';
        });
        html += '</tbody></table>';
      }
      if (overItems.length > 0) {
        html += '<div style="margin-top:12px;font-size:12px;color:#FF8A80">' + overItems.length + ' item' + (overItems.length !== 1 ? 's' : '') + ' ran over time.</div>';
      }
      html += '<div style="text-align:center;margin-top:16px"><button id="close-rehearsal-summary" class="btn-primary" style="font-size:13px;padding:8px 20px">Done</button></div></div>';
      overlay.innerHTML = html;
      document.body.appendChild(overlay);
      document.getElementById('close-rehearsal-summary').addEventListener('click', function() { overlay.remove(); });
      overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
    }

    function _fmtDuration(seconds) {
      var s = Math.abs(Math.round(seconds));
      var m = Math.floor(s / 60);
      s = s % 60;
      return m + ':' + String(s).padStart(2, '0');
    }

    function _fmtDurationMs(ms) {
      if (ms == null) return '--:--';
      var neg = ms < 0;
      var s = Math.floor(Math.abs(ms) / 1000);
      var m = Math.floor(s / 60);
      s = s % 60;
      return (neg ? '-' : '') + m + ':' + String(s).padStart(2, '0');
    }

    // ── Phase 9: Post-show reports (9.5) ───────────────────────────────────

    function rundownShowReports() {
      if (!_rundownSelectedPlan) return;
      api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/reports').then(function(data) {
        var reports = data.reports || [];
        _showReportsPanel(reports);
      }).catch(function(e) { toast('Failed to load reports: ' + e.message, true); });
    }

    function _showReportsPanel(reports) {
      var existing = document.getElementById('rundown-reports-panel');
      if (existing) existing.remove();
      var overlay = document.createElement('div');
      overlay.id = 'rundown-reports-panel';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px)';
      var html = '<div style="background:#0a1610;border:1px solid #0d3320;border-radius:16px;padding:24px;max-width:600px;width:95%;max-height:80vh;overflow-y:auto">'
        + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">'
        + '<div style="font-size:16px;font-weight:700;color:#F0F2F4">Show Reports</div>'
        + '<button id="close-reports-panel" class="btn-secondary" style="font-size:12px;padding:4px 12px">Close</button></div>';
      if (!reports.length) {
        html += '<div style="text-align:center;padding:40px;color:#8B9DAF;font-size:13px">No show reports yet. Reports are generated automatically when a live session ends.</div>';
      } else {
        html += '<div style="display:flex;flex-direction:column;gap:8px">';
        reports.forEach(function(report) {
          var totalVariance = (report.totalActualMs || 0) - (report.totalPlannedMs || 0);
          var d = new Date(report.sessionStartedAt);
          html += '<div style="background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07);border-radius:10px;padding:12px">'
            + '<div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">'
            + '<div>'
            + '<div style="font-size:13px;font-weight:700;color:#F0F2F4">' + d.toLocaleDateString() + ' ' + d.toLocaleTimeString() + '</div>'
            + '<div style="font-size:12px;color:#8B9DAF;margin-top:4px">'
            + 'Planned: ' + _fmtDurationMs(report.totalPlannedMs)
            + ' · Actual: ' + _fmtDurationMs(report.totalActualMs)
            + ' · Variance: <span style="color:' + (totalVariance > 0 ? '#FF5252' : totalVariance < 0 ? '#00E676' : '#F0F2F4') + '">' + (totalVariance > 0 ? '+' : '') + _fmtDurationMs(totalVariance) + '</span>'
            + '</div></div>'
            + '<div style="display:flex;gap:6px">';
          if (report.shareToken) {
            html += '<button class="btn-secondary" data-action="rundownCopyReportLink" data-report-token="' + escapeHtml(report.shareToken) + '" style="font-size:11px;padding:4px 10px">Copy Link</button>';
          }
          html += '</div></div></div>';
        });
        html += '</div>';
      }
      html += '</div>';
      overlay.innerHTML = html;
      document.body.appendChild(overlay);
      document.getElementById('close-reports-panel').addEventListener('click', function() { overlay.remove(); });
      overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
    }

    function rundownCopyReportLink(token) {
      var url = window.location.origin + '/rundown/report/' + token;
      navigator.clipboard.writeText(url).then(function() { toast('Report link copied'); }).catch(function() { toast('Failed to copy', true); });
    }

    // ── Phase 9: Rehearsal comparison ──────────────────────────────────────

    function rundownShowRehearsals() {
      if (!_rundownSelectedPlan) return;
      api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/rehearsals').then(function(data) {
        var runs = data.rehearsals || [];
        _showRehearsalsPanel(runs);
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function _showRehearsalsPanel(runs) {
      var existing = document.getElementById('rundown-rehearsals-panel');
      if (existing) existing.remove();
      var overlay = document.createElement('div');
      overlay.id = 'rundown-rehearsals-panel';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px)';
      var html = '<div style="background:#0a1610;border:1px solid #0d3320;border-radius:16px;padding:24px;max-width:600px;width:95%;max-height:80vh;overflow-y:auto">'
        + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">'
        + '<div style="font-size:16px;font-weight:700;color:#F0F2F4">Rehearsal Runs</div>'
        + '<button id="close-rehearsals-panel" class="btn-secondary" style="font-size:12px;padding:4px 12px">Close</button></div>';
      if (!runs.length) {
        html += '<div style="text-align:center;padding:40px;color:#8B9DAF;font-size:13px">No rehearsal runs yet. Click "Rehearsal" to start one.</div>';
      } else {
        html += '<div style="display:flex;flex-direction:column;gap:8px">';
        runs.forEach(function(run) {
          var totalVariance = (run.totalActualMs || 0) - (run.totalPlannedMs || 0);
          var d = new Date(run.startedAt);
          html += '<div style="background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07);border-radius:10px;padding:12px;cursor:pointer" onclick="(function(){})();">'
            + '<div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">'
            + '<div>'
            + '<div style="font-size:13px;font-weight:700;color:#F0F2F4">Run #' + run.runNumber + ' · ' + d.toLocaleDateString() + '</div>'
            + '<div style="font-size:12px;color:#8B9DAF;margin-top:4px">'
            + 'Planned: ' + _fmtDurationMs(run.totalPlannedMs)
            + ' · Actual: ' + _fmtDurationMs(run.totalActualMs)
            + ' · <span style="color:' + (totalVariance > 0 ? '#FF5252' : totalVariance < 0 ? '#00E676' : '#F0F2F4') + '">' + (totalVariance > 0 ? '+' : '') + _fmtDurationMs(totalVariance) + '</span>'
            + '</div></div></div></div>';
        });
        html += '</div>';
      }
      html += '</div>';
      overlay.innerHTML = html;
      document.body.appendChild(overlay);
      document.getElementById('close-rehearsals-panel').addEventListener('click', function() { overlay.remove(); });
      overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
    }

    // ═══════════════════════════════════════════════════════════════════════════
    //  PHASE 11 (v3): WORKFLOW POWER FEATURES
    // ═══════════════════════════════════════════════════════════════════════════

    // ── 1. Per-Item Checklists ──────────────────────────────────────────────

    function _loadChecklistsForPlan() {
      if (!_rundownSelectedPlan) return;
      api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/checklists').then(function(data) {
        _rundownChecklistData = {};
        (data.checklists || []).forEach(function(c) {
          if (!_rundownChecklistData[c.itemId]) _rundownChecklistData[c.itemId] = [];
          _rundownChecklistData[c.itemId].push(c);
        });
        renderRundownEditorItems(_rundownSelectedPlan.items || []);
      }).catch(function() {});
    }

    function _getChecklistSummary(itemId) {
      var checks = _rundownChecklistData[itemId] || [];
      if (checks.length === 0) return null;
      var done = checks.filter(function(c) { return c.checked; }).length;
      return { done: done, total: checks.length, pct: Math.round((done / checks.length) * 100) };
    }

    function _renderChecklistPanel(itemId) {
      var existing = document.querySelector('.rundown-checklist-row[data-checklist-for="' + itemId + '"]');
      if (existing) existing.remove();
      if (!_rundownChecklistExpanded[itemId]) return;
      var checks = _rundownChecklistData[itemId] || [];
      var itemRow = document.querySelector('tr[data-item-id="' + itemId + '"]:not(.rundown-director-notes-row):not(.rundown-checklist-row)');
      if (!itemRow) return;
      var colCount = itemRow.children.length;
      var tr = document.createElement('tr');
      tr.className = 'rundown-checklist-row';
      tr.setAttribute('data-checklist-for', itemId);
      tr.style.cssText = 'background:rgba(0,230,118,0.03);border-bottom:1px solid rgba(255,255,255,0.04)';
      var td = document.createElement('td');
      td.setAttribute('colspan', colCount);
      td.style.cssText = 'padding:6px 12px 8px 78px';
      var html = '<div class="checklist-panel" style="max-width:400px">';
      checks.forEach(function(ck) {
        html += '<div class="checklist-item" style="display:flex;align-items:center;gap:8px;padding:3px 0" data-check-id="' + ck.id + '">';
        html += '<input type="checkbox" ' + (ck.checked ? 'checked' : '') + ' class="checklist-toggle" data-check-id="' + ck.id + '" data-item-id="' + itemId + '" style="accent-color:#00E676;cursor:pointer">';
        html += '<span class="checklist-label" data-check-id="' + ck.id + '" data-item-id="' + itemId + '" style="cursor:text;flex:1;font-size:12px;color:' + (ck.checked ? '#556270' : '#F0F2F4') + ';' + (ck.checked ? 'text-decoration:line-through' : '') + '">' + escapeHtml(ck.label) + '</span>';
        html += '<span class="checklist-delete" data-check-id="' + ck.id + '" data-item-id="' + itemId + '" style="cursor:pointer;color:#556270;font-size:11px" title="Remove">' + SVG.xMark + '</span>';
        html += '</div>';
      });
      html += '<div style="display:flex;gap:6px;margin-top:4px">';
      html += '<input type="text" class="checklist-add-input" data-item-id="' + itemId + '" placeholder="Add checklist item..." style="flex:1;background:rgba(255,255,255,0.06);color:#F0F2F4;border:1px solid rgba(255,255,255,0.1);border-radius:4px;padding:4px 8px;font-size:12px">';
      html += '</div>';
      html += '</div>';
      td.innerHTML = html;
      tr.appendChild(td);

      // Insert after the item row (and after director notes row if visible)
      var dirRow = document.querySelector('.rundown-director-notes-row[data-item-id="' + itemId + '"]');
      var insertAfter = dirRow || itemRow;
      insertAfter.parentNode.insertBefore(tr, insertAfter.nextSibling);

      // Attach events
      tr.querySelectorAll('.checklist-toggle').forEach(function(cb) {
        cb.addEventListener('change', function() {
          var checkId = cb.getAttribute('data-check-id');
          var iId = cb.getAttribute('data-item-id');
          api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + iId + '/checklists/' + checkId, { checked: cb.checked }).then(function() {
            var ck = (_rundownChecklistData[iId] || []).find(function(c) { return c.id === checkId; });
            if (ck) ck.checked = cb.checked;
            _renderChecklistPanel(iId);
            _updateChecklistBadge(iId);
          }).catch(function(e) { toast('Failed: ' + e.message, true); });
        });
      });
      tr.querySelectorAll('.checklist-delete').forEach(function(btn) {
        btn.addEventListener('click', function() {
          var checkId = btn.getAttribute('data-check-id');
          var iId = btn.getAttribute('data-item-id');
          api('DELETE', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + iId + '/checklists/' + checkId).then(function() {
            _rundownChecklistData[iId] = (_rundownChecklistData[iId] || []).filter(function(c) { return c.id !== checkId; });
            _renderChecklistPanel(iId);
            _updateChecklistBadge(iId);
          }).catch(function(e) { toast('Failed: ' + e.message, true); });
        });
      });
      tr.querySelectorAll('.checklist-label').forEach(function(lbl) {
        lbl.addEventListener('dblclick', function() {
          var checkId = lbl.getAttribute('data-check-id');
          var iId = lbl.getAttribute('data-item-id');
          var ck = (_rundownChecklistData[iId] || []).find(function(c) { return c.id === checkId; });
          if (!ck) return;
          var input = document.createElement('input');
          input.type = 'text';
          input.value = ck.label;
          input.style.cssText = 'flex:1;background:rgba(255,255,255,0.06);color:#F0F2F4;border:1px solid rgba(0,230,118,0.3);border-radius:4px;padding:2px 6px;font-size:12px;outline:none';
          lbl.replaceWith(input);
          input.focus();
          function save() {
            var val = input.value.trim();
            if (val && val !== ck.label) {
              ck.label = val;
              api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + iId + '/checklists/' + checkId, { label: val });
            }
            _renderChecklistPanel(iId);
          }
          input.addEventListener('blur', save);
          input.addEventListener('keydown', function(e) { if (e.key === 'Enter') input.blur(); if (e.key === 'Escape') { _renderChecklistPanel(iId); } });
        });
      });
      var addInput = tr.querySelector('.checklist-add-input');
      if (addInput) {
        addInput.addEventListener('keydown', function(e) {
          if (e.key === 'Enter') {
            var label = addInput.value.trim();
            if (!label) return;
            addInput.value = '';
            api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + itemId + '/checklists', { label: label }).then(function(ck) {
              if (!_rundownChecklistData[itemId]) _rundownChecklistData[itemId] = [];
              _rundownChecklistData[itemId].push(ck);
              _renderChecklistPanel(itemId);
              _updateChecklistBadge(itemId);
              setTimeout(function() {
                var newInput = document.querySelector('.checklist-add-input[data-item-id="' + itemId + '"]');
                if (newInput) newInput.focus();
              }, 50);
            }).catch(function(e) { toast('Failed: ' + e.message, true); });
          }
        });
      }
    }

    function _updateChecklistBadge(itemId) {
      var badge = document.querySelector('.checklist-badge[data-item-id="' + itemId + '"]');
      if (!badge) return;
      var summary = _getChecklistSummary(itemId);
      if (summary) {
        badge.innerHTML = '<span style="font-size:10px;color:' + (summary.done === summary.total ? '#00E676' : '#8B9DAF') + '">' + summary.done + '/' + summary.total + ' ' + SVG.check + '</span>'
          + '<div style="height:2px;background:rgba(255,255,255,0.08);border-radius:1px;margin-top:1px"><div style="height:100%;background:' + (summary.done === summary.total ? '#00E676' : '#42A5F5') + ';border-radius:1px;width:' + summary.pct + '%;transition:width 0.3s"></div></div>';
      } else {
        badge.innerHTML = '';
      }
    }

    // ── 2. PDF Export ───────────────────────────────────────────────────────

    function rundownExportPDF(format) {
      if (!_rundownSelectedPlan) return;
      var url = '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/export/pdf?format=' + (format || 'tech');
      window.open(url, '_blank');
      toast('PDF export started');
    }

    // ── 3. CSV Import/Export ────────────────────────────────────────────────

    function rundownExportCSV() {
      if (!_rundownSelectedPlan) return;
      var url = '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/export/csv';
      window.open(url, '_blank');
      toast('CSV export started');
    }

    function rundownImportCSV() {
      if (!_rundownSelectedPlan) return;
      var input = document.createElement('input');
      input.type = 'file';
      input.accept = '.csv,text/csv';
      input.addEventListener('change', function() {
        var file = input.files[0];
        if (!file) return;
        var reader = new FileReader();
        reader.onload = function(e) {
          var csvData = e.target.result;
          // Preview first
          api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/import/csv', { csvData: csvData, preview: true }).then(function(data) {
            styledConfirm('Import CSV', 'Import ' + data.count + ' items from "' + file.name + '"?').then(function(ok) {
              if (!ok) return;
              api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/import/csv', { csvData: csvData }).then(function(plan) {
                _rundownSelectedPlan = plan;
                renderRundownEditor(plan);
                toast('Imported ' + data.count + ' items');
              }).catch(function(e) { toast('Import failed: ' + e.message, true); });
            });
          }).catch(function(e) { toast('Failed to parse CSV: ' + e.message, true); });
        };
        reader.readAsText(file);
      });
      input.click();
    }

    // ── 4. Undo/Redo System ─────────────────────────────────────────────────

    function _rundownPushUndo(entry) {
      // entry: { type, desc, undoFn, redoFn }
      _rundownUndoStack.push(entry);
      if (_rundownUndoStack.length > 20) _rundownUndoStack.shift();
      _rundownRedoStack = [];
      _updateUndoRedoButtons();
    }

    function _rundownUndo() {
      if (_rundownUndoStack.length === 0) return;
      var entry = _rundownUndoStack.pop();
      _rundownRedoStack.push(entry);
      toast('Undid: ' + entry.desc);
      entry.undoFn().then(function() {
        _updateUndoRedoButtons();
      }).catch(function(e) { toast('Undo failed: ' + e.message, true); });
    }

    function _rundownRedo() {
      if (_rundownRedoStack.length === 0) return;
      var entry = _rundownRedoStack.pop();
      _rundownUndoStack.push(entry);
      toast('Redid: ' + entry.desc);
      entry.redoFn().then(function() {
        _updateUndoRedoButtons();
      }).catch(function(e) { toast('Redo failed: ' + e.message, true); });
    }

    function _updateUndoRedoButtons() {
      var undoBtn = document.getElementById('btn-rundown-undo');
      var redoBtn = document.getElementById('btn-rundown-redo');
      if (undoBtn) undoBtn.disabled = _rundownUndoStack.length === 0;
      if (redoBtn) redoBtn.disabled = _rundownRedoStack.length === 0;
    }

    function _refreshRundownPlan() {
      if (!_rundownSelectedPlan) return Promise.resolve();
      return api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id).then(function(plan) {
        _rundownSelectedPlan = plan;
        renderRundownEditor(plan);
        var idx = _rundownPlans.findIndex(function(p) { return p.id === plan.id; });
        if (idx >= 0) { _rundownPlans[idx].itemCount = plan.items.length; renderRundownDashboard(); }
      });
    }

    // Wrap existing item operations to push onto undo stack
    var _origRundownDeleteItem = rundownDeleteItem;
    rundownDeleteItem = function(itemId) {
      if (!_rundownSelectedPlan) return;
      var item = (_rundownSelectedPlan.items || []).find(function(x) { return x.id === itemId; });
      if (!item) return _origRundownDeleteItem(itemId);
      styledConfirm('Remove Item', 'Remove this item from the rundown?').then(function(ok) {
        if (!ok) return;
        var savedItem = JSON.parse(JSON.stringify(item));
        api('DELETE', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + itemId).then(function(plan) {
          _rundownSelectedPlan = plan;
          renderRundownEditor(plan);
          var idx = _rundownPlans.findIndex(function(p) { return p.id === plan.id; });
          if (idx >= 0) { _rundownPlans[idx].itemCount = plan.items.length; renderRundownDashboard(); }
          _rundownPushUndo({
            type: 'deleteItem',
            desc: 'Delete "' + savedItem.title + '"',
            undoFn: function() {
              return api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items', {
                title: savedItem.title, itemType: savedItem.itemType, lengthSeconds: savedItem.lengthSeconds,
                notes: savedItem.notes, assignee: savedItem.assignee, startType: savedItem.startType,
                hardStartTime: savedItem.hardStartTime, autoAdvance: savedItem.autoAdvance, directorNotes: savedItem.directorNotes,
              }).then(function() { return _refreshRundownPlan(); });
            },
            redoFn: function() {
              // Can't re-delete the exact same item (new ID from undo), so just refresh
              return _refreshRundownPlan();
            },
          });
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    };

    // ── 5. Duplicate Item/Section ───────────────────────────────────────────

    function rundownDuplicateItem(itemId) {
      if (!_rundownSelectedPlan) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items/' + itemId + '/duplicate').then(function(plan) {
        _rundownSelectedPlan = plan;
        renderRundownEditor(plan);
        var idx = _rundownPlans.findIndex(function(p) { return p.id === plan.id; });
        if (idx >= 0) { _rundownPlans[idx].itemCount = plan.items.length; renderRundownDashboard(); }
        toast('Item duplicated');
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function rundownDuplicateSection(sectionId) {
      if (!_rundownSelectedPlan) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/sections/' + sectionId + '/duplicate').then(function(plan) {
        _rundownSelectedPlan = plan;
        renderRundownEditor(plan);
        toast('Section duplicated');
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    // ── 6. Quick-Add from Keyboard ──────────────────────────────────────────

    function _rundownInsertItemAfterSelected() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      var planId = _rundownSelectedPlan.id;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/items', {
        title: 'New Item', itemType: 'other', lengthSeconds: 0, notes: '', assignee: '',
      }).then(function(newItem) {
        if (_rundownSelectedItemId) {
          // Reorder: move new item after selected
          var items = _rundownSelectedPlan.items || [];
          var selIdx = items.findIndex(function(it) { return it.id === _rundownSelectedItemId; });
          if (selIdx >= 0) {
            var ids = items.map(function(it) { return it.id; });
            var newIdx = ids.indexOf(newItem.id);
            if (newIdx >= 0) ids.splice(newIdx, 1);
            ids.splice(selIdx + 1, 0, newItem.id);
            api('PUT', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + planId + '/reorder', { itemIds: ids }).then(function() {
              return _refreshRundownPlan();
            }).then(function() {
              _startEditingNewItem(newItem.id);
            });
            return;
          }
        }
        _refreshRundownPlan().then(function() { _startEditingNewItem(newItem.id); });
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function _startEditingNewItem(itemId) {
      _rundownSelectedItemId = itemId;
      setTimeout(function() {
        var titleSpan = document.querySelector('.rundown-inline-edit[data-field="title"][data-item-id="' + itemId + '"]');
        if (titleSpan) titleSpan.click();
      }, 100);
    }

