    function rundownShowBuiltinTemplates() {
      var existing = document.getElementById('rundown-builtin-templates-panel');
      if (existing) existing.remove();
      var overlay = document.createElement('div');
      overlay.id = 'rundown-builtin-templates-panel';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px)';
      var html = '<div style="background:#0a1610;border:1px solid #0d3320;border-radius:16px;padding:24px;max-width:700px;width:95%;max-height:80vh;overflow-y:auto">'
        + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">'
        + '<div style="font-size:16px;font-weight:700;color:#F0F2F4">Start from a Template</div>'
        + '<button id="close-builtin-templates" class="btn-secondary" style="font-size:12px;padding:4px 12px">Close</button></div>'
        + '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:12px">';
      BUILTIN_TEMPLATES.forEach(function(tmpl, idx) {
        var totalSec = tmpl.items.reduce(function(s, i) { return s + (i.lengthSeconds || 0); }, 0);
        var totalMin = Math.round(totalSec / 60);
        html += '<div class="card" style="padding:14px;cursor:pointer;border:1px solid rgba(255,255,255,0.08);transition:border-color 0.15s" data-builtin-template-idx="' + idx + '" onmouseenter="this.style.borderColor=\'rgba(0,230,118,0.4)\'" onmouseleave="this.style.borderColor=\'rgba(255,255,255,0.08)\'">'
          + '<div style="font-size:14px;font-weight:700;color:#F0F2F4;margin-bottom:4px">' + escapeHtml(tmpl.name) + '</div>'
          + '<div style="font-size:12px;color:#8B9DAF">' + tmpl.items.length + ' items · ~' + totalMin + ' min</div>'
          + '<div style="margin-top:8px;font-size:11px;color:#556270;line-height:1.5">' + tmpl.items.slice(0, 4).map(function(i) { return escapeHtml(i.title); }).join(', ') + (tmpl.items.length > 4 ? '...' : '') + '</div>'
          + '</div>';
      });
      html += '</div></div>';
      overlay.innerHTML = html;
      document.body.appendChild(overlay);
      document.getElementById('close-builtin-templates').addEventListener('click', function() { overlay.remove(); });
      overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
      // Handle template card clicks
      overlay.querySelectorAll('[data-builtin-template-idx]').forEach(function(card) {
        card.addEventListener('click', function() {
          var idx = parseInt(card.getAttribute('data-builtin-template-idx'), 10);
          var tmpl = BUILTIN_TEMPLATES[idx];
          if (!tmpl) return;
          overlay.remove();
          _createRundownFromBuiltinTemplate(tmpl);
        });
      });
    }

    function _createRundownFromBuiltinTemplate(tmpl) {
      _openRundownPlanModal('create', { title: tmpl.name, date: new Date().toISOString().slice(0, 10) }).then(function(result) {
        if (!result) return;
        api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans', { title: result.title, serviceDate: result.date, roomId: result.roomId || '' }).then(function(plan) {
          // Add all template items sequentially
          var chain = Promise.resolve();
          tmpl.items.forEach(function(item, i) {
            chain = chain.then(function() {
              return api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + plan.id + '/items', {
                title: item.title,
                itemType: item.itemType,
                lengthSeconds: item.lengthSeconds || 0,
                notes: item.notes || '',
                assignee: item.assignee || '',
              });
            });
          });
          chain.then(function() {
            toast('Rundown created from "' + tmpl.name + '" template');
            _rundownSelectedPlanId = plan.id;
            loadRundownManager();
            setTimeout(function() { rundownSelectPlan(plan.id, 'manual'); }, 300);
          }).catch(function(e) { toast('Failed: ' + e.message, true); });
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    function _renderComparison(planA, planB) {
      var container = document.getElementById('compare-results');
      if (!container) return;
      var itemsA = (planA.items || []).filter(function(i) { return i.itemType !== 'section'; });
      var itemsB = (planB.items || []).filter(function(i) { return i.itemType !== 'section'; });

      // Simple diff: match by title
      var titleMapB = {};
      itemsB.forEach(function(it) { titleMapB[it.title] = it; });
      var titleMapA = {};
      itemsA.forEach(function(it) { titleMapA[it.title] = it; });

      var html = '<table style="width:100%;border-collapse:collapse;font-size:12px">';
      html += '<thead><tr style="border-bottom:1px solid rgba(255,255,255,0.08);font-size:10px;text-transform:uppercase;letter-spacing:0.5px;color:#556270;font-weight:700">';
      html += '<th style="padding:8px 6px;text-align:left">Item</th>';
      html += '<th style="padding:8px 6px;text-align:center;width:80px">Duration A</th>';
      html += '<th style="padding:8px 6px;text-align:center;width:80px">Duration B</th>';
      html += '<th style="padding:8px 6px;text-align:left">Changes</th>';
      html += '</tr></thead><tbody>';

      // Items in A
      var shown = {};
      itemsA.forEach(function(a) {
        var b = titleMapB[a.title];
        shown[a.title] = true;
        var changes = [];
        var rowColor = 'transparent';
        if (!b) {
          rowColor = 'rgba(239,68,68,0.08)'; // removed
          changes.push('<span style="color:#FF5252">Removed from B</span>');
        } else {
          if (a.lengthSeconds !== b.lengthSeconds) {
            var diff = b.lengthSeconds - a.lengthSeconds;
            changes.push('<span style="color:#FFB74D">Duration ' + (diff > 0 ? '+' : '') + Math.floor(diff / 60) + ':' + String(Math.abs(diff) % 60).padStart(2, '0') + '</span>');
            rowColor = 'rgba(255,183,77,0.06)';
          }
          if ((a.notes || '') !== (b.notes || '')) changes.push('<span style="color:#FFB74D">Notes changed</span>');
          if ((a.assignee || '') !== (b.assignee || '')) changes.push('<span style="color:#FFB74D">Assignee: ' + escapeHtml(a.assignee || '--') + ' → ' + escapeHtml(b.assignee || '--') + '</span>');
          if (a.itemType !== b.itemType) changes.push('<span style="color:#FFB74D">Type: ' + a.itemType + ' → ' + b.itemType + '</span>');
        }
        if (changes.length === 0 && b) changes.push('<span style="color:#556270">No changes</span>');
        var color = RUNDOWN_TYPE_COLORS[a.itemType] || '#95a5a6';
        html += '<tr style="border-bottom:1px solid rgba(255,255,255,0.04);background:' + rowColor + '">';
        html += '<td style="padding:6px;border-left:3px solid ' + color + '"><span style="font-weight:600;color:#F0F2F4">' + escapeHtml(a.title) + '</span></td>';
        html += '<td style="padding:6px;text-align:center;font-family:monospace;color:#8B9DAF">' + _rundownFormatMMSS(a.lengthSeconds) + '</td>';
        html += '<td style="padding:6px;text-align:center;font-family:monospace;color:#8B9DAF">' + (b ? _rundownFormatMMSS(b.lengthSeconds) : '--') + '</td>';
        html += '<td style="padding:6px">' + changes.join(', ') + '</td>';
        html += '</tr>';
      });

      // Items only in B (added)
      itemsB.forEach(function(b) {
        if (shown[b.title]) return;
        var color = RUNDOWN_TYPE_COLORS[b.itemType] || '#95a5a6';
        html += '<tr style="border-bottom:1px solid rgba(255,255,255,0.04);background:rgba(0,230,118,0.08)">';
        html += '<td style="padding:6px;border-left:3px solid ' + color + '"><span style="font-weight:600;color:#F0F2F4">' + escapeHtml(b.title) + '</span></td>';
        html += '<td style="padding:6px;text-align:center;color:#556270">--</td>';
        html += '<td style="padding:6px;text-align:center;font-family:monospace;color:#8B9DAF">' + _rundownFormatMMSS(b.lengthSeconds) + '</td>';
        html += '<td style="padding:6px"><span style="color:#00E676">Added in B</span></td>';
        html += '</tr>';
      });

      html += '</tbody></table>';

      // Summary
      var totalA = itemsA.reduce(function(s, i) { return s + (i.lengthSeconds || 0); }, 0);
      var totalB = itemsB.reduce(function(s, i) { return s + (i.lengthSeconds || 0); }, 0);
      html += '<div style="margin-top:12px;display:flex;gap:20px;font-size:12px;color:#8B9DAF">';
      html += '<span>A total: <strong style="color:#F0F2F4">' + _rundownFormatMMSS(totalA) + '</strong> (' + itemsA.length + ' items)</span>';
      html += '<span>B total: <strong style="color:#F0F2F4">' + _rundownFormatMMSS(totalB) + '</strong> (' + itemsB.length + ' items)</span>';
      var diff = totalB - totalA;
      html += '<span>Diff: <strong style="color:' + (diff > 0 ? '#FF5252' : diff < 0 ? '#00E676' : '#F0F2F4') + '">' + (diff > 0 ? '+' : '') + _rundownFormatMMSS(diff) + '</strong></span>';
      html += '</div>';

      container.innerHTML = html;
    }

    // ── Script Editor Panel ─────────────────────────────────────────────────────

    function rundownOpenScriptEditor(itemId) {
      if (!_rundownSelectedPlan) return;
      var item = (_rundownSelectedPlan.items || []).find(function(x) { return x.id === itemId; });
      if (!item) return;
      var existing = document.getElementById('rundown-script-editor-panel');
      if (existing) existing.remove();
      var overlay = document.createElement('div');
      overlay.id = 'rundown-script-editor-panel';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px)';
      var html = '<div style="background:#0a1610;border:1px solid #0d3320;border-radius:16px;padding:24px;max-width:800px;width:95%;max-height:85vh;display:flex;flex-direction:column">'
        + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;flex-shrink:0">'
        + '<div style="font-size:16px;font-weight:700;color:#F0F2F4">Script — ' + escapeHtml(item.title) + '</div>'
        + '<div style="display:flex;gap:8px">'
        + '<button id="script-editor-save" class="btn-primary" style="font-size:12px;padding:6px 16px">Save</button>'
        + '<button id="script-editor-close" class="btn-secondary" style="font-size:12px;padding:4px 12px">Close</button>'
        + '</div></div>'
        + '<textarea id="script-editor-textarea" style="flex:1;min-height:300px;background:rgba(255,255,255,0.04);color:#F0F2F4;border:1px solid rgba(255,255,255,0.1);border-radius:8px;padding:16px;font-size:14px;line-height:1.8;font-family:inherit;resize:none;outline:none" placeholder="Paste or type the full script for this item...">' + escapeHtml(item.notes || '') + '</textarea>'
        + '</div>';
      overlay.innerHTML = html;
      document.body.appendChild(overlay);
      var textarea = document.getElementById('script-editor-textarea');
      textarea.focus();
      document.getElementById('script-editor-save').addEventListener('click', function() {
        _rundownInlineSave(itemId, { notes: textarea.value });
        overlay.remove();
        toast('Script saved');
      });
      document.getElementById('script-editor-close').addEventListener('click', function() { overlay.remove(); });
      overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
    }

    // ── Dashboard View Toggles (Calendar, Analytics) ──────────────────────────

    var _rundownDashboardView = 'list'; // list | calendar | analytics

    function rundownSetDashboardView(view) {
      _rundownDashboardView = view;
      var dash = document.getElementById('rundown-dashboard');
      var viewBtns = document.querySelectorAll('.rundown-view-toggle-btn');
      viewBtns.forEach(function(b) {
        b.style.color = b.getAttribute('data-view') === view ? '#00E676' : '#8B9DAF';
        b.style.borderColor = b.getAttribute('data-view') === view ? 'rgba(0,230,118,0.4)' : 'rgba(255,255,255,0.1)';
      });
      if (view === 'list') {
        renderRundownDashboard();
      } else if (view === 'calendar') {
        _renderRundownCalendarView(dash);
      }
    }

    function _renderRundownCalendarView(container) {
      if (!container) return;
      var plans = _rundownPlans || [];
      var byDate = {};
      plans.forEach(function(p) {
        var d = p.serviceDate || 'Unscheduled';
        if (!byDate[d]) byDate[d] = [];
        byDate[d].push(p);
      });
      var dates = Object.keys(byDate).sort().reverse();
      var html = '<div style="display:flex;flex-direction:column;gap:16px">';
      dates.forEach(function(d) {
        var dateLabel = d;
        if (d !== 'Unscheduled') {
          try { dateLabel = new Date(d + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' }); } catch(e) {}
        }
        html += '<div>';
        html += '<div style="font-size:13px;font-weight:700;color:#8B9DAF;margin-bottom:8px;text-transform:uppercase;letter-spacing:0.5px">' + escapeHtml(dateLabel) + '</div>';
        html += '<div style="display:flex;flex-direction:column;gap:4px">';
        byDate[d].forEach(function(p) {
          var statusColor = p.status === 'live' ? '#00E676' : p.status === 'show_ready' ? '#FFB74D' : '#556270';
          html += '<div class="card" style="padding:10px 14px;cursor:pointer;display:flex;align-items:center;gap:12px" data-action="rundownSelectPlan" data-plan-id="' + p.id + '">';
          html += '<div style="width:4px;height:24px;border-radius:2px;background:' + statusColor + '"></div>';
          html += '<div style="flex:1;min-width:0"><div style="font-size:13px;font-weight:600;color:#F0F2F4;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escapeHtml(p.title) + '</div></div>';
          html += '<div style="font-size:11px;color:#556270">' + (p.itemCount || 0) + ' items</div>';
          html += '</div>';
        });
        html += '</div></div>';
      });
      html += '</div>';
      container.innerHTML = html;
    }

    // ── Right-click context menu ─────────────────────────────────────────────────

    function _attachRundownContextMenu(container) {
      if (!container) return;
      container.addEventListener('contextmenu', function(e) {
        var row = e.target.closest('tr[data-item-id]');
        if (!row) return;
        e.preventDefault();
        var itemId = row.getAttribute('data-item-id');
        _showRundownContextMenu(e.clientX, e.clientY, itemId);
      });
    }

    function _showRundownContextMenu(x, y, itemId) {
      var existing = document.getElementById('rundown-context-menu');
      if (existing) existing.remove();
      var menu = document.createElement('div');
      menu.id = 'rundown-context-menu';
      menu.style.cssText = 'position:fixed;z-index:9999;background:#111916;border:1px solid rgba(255,255,255,0.15);border-radius:8px;padding:4px;box-shadow:0 8px 24px rgba(0,0,0,0.5);min-width:160px';
      menu.style.left = x + 'px';
      menu.style.top = y + 'px';
      var actions = [
        { label: 'Edit Item', action: function() { rundownEditItem(itemId); } },
        { label: 'Duplicate', action: function() { _duplicateRundownItem(itemId); } },
        { label: 'Open Script', action: function() { rundownOpenScriptEditor(itemId); } },
        { label: 'Move Up', action: function() { rundownMoveItem(itemId, 'up'); } },
        { label: 'Move Down', action: function() { rundownMoveItem(itemId, 'down'); } },
        { divider: true },
        { label: 'Delete', action: function() { rundownDeleteItem(itemId); }, danger: true },
      ];
      actions.forEach(function(a) {
        if (a.divider) {
          var div = document.createElement('div');
          div.style.cssText = 'height:1px;background:rgba(255,255,255,0.08);margin:4px 0';
          menu.appendChild(div);
          return;
        }
        var btn = document.createElement('div');
        btn.textContent = a.label;
        btn.style.cssText = 'padding:6px 12px;font-size:12px;color:' + (a.danger ? '#FF5252' : '#F0F2F4') + ';cursor:pointer;border-radius:4px';
        btn.addEventListener('mouseenter', function() { btn.style.background = 'rgba(255,255,255,0.06)'; });
        btn.addEventListener('mouseleave', function() { btn.style.background = 'none'; });
        btn.addEventListener('click', function() { menu.remove(); document.removeEventListener('click', closeMenu); a.action(); });
        menu.appendChild(btn);
      });
      document.body.appendChild(menu);
      function closeMenu() { menu.remove(); document.removeEventListener('click', closeMenu); }
      setTimeout(function() { document.addEventListener('click', closeMenu); }, 10);
    }

    function _duplicateRundownItem(itemId) {
      if (!_rundownSelectedPlan) return;
      var item = (_rundownSelectedPlan.items || []).find(function(x) { return x.id === itemId; });
      if (!item) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/items', {
        title: item.title + ' (Copy)',
        itemType: item.itemType,
        lengthSeconds: item.lengthSeconds || 0,
        notes: item.notes || '',
        assignee: item.assignee || '',
      }).then(function() {
        api('GET', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id).then(function(plan) {
          _rundownSelectedPlan = plan;
          renderRundownEditor(plan);
          toast('Item duplicated');
        });
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    // ── Checklist indicators on items (local-state overlay removed; using API-backed _renderChecklistPanel) ──

    // ── AI Document Import ──────────────────────────────────────────────────────

    function rundownImportFromDocument() {
      var existing = document.getElementById('rundown-ai-import-modal');
      if (existing) existing.remove();
      var overlay = document.createElement('div');
      overlay.id = 'rundown-ai-import-modal';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px)';
      var html = '<div style="background:#0a1610;border:1px solid #0d3320;border-radius:16px;padding:24px;max-width:700px;width:95%;max-height:85vh;overflow-y:auto">'
        + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">'
        + '<div style="display:flex;align-items:center;gap:8px"><div style="font-size:16px;font-weight:700;color:#F0F2F4">' + SVG.sparkle + ' Import from Document</div></div>'
        + '<button id="ai-import-close" class="btn-secondary" style="font-size:12px;padding:4px 12px">Close</button></div>'
        + '<div style="font-size:13px;color:#8B9DAF;margin-bottom:16px;line-height:1.5">Upload a PDF, image (photo of a bulletin), or text file and AI will auto-generate a rundown from it.</div>'
        + '<div id="ai-import-dropzone" style="border:2px dashed rgba(255,255,255,0.15);border-radius:12px;padding:40px 20px;text-align:center;cursor:pointer;transition:border-color 0.15s">'
        + '<svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.5" style="color:#556270;margin-bottom:8px"><path stroke-linecap="round" stroke-linejoin="round" d="M3 16.5v2.25A2.25 2.25 0 0 0 5.25 21h13.5A2.25 2.25 0 0 0 21 18.75V16.5m-13.5-9L12 3m0 0 4.5 4.5M12 3v13.5"/></svg>'
        + '<div style="font-size:14px;font-weight:600;color:#F0F2F4;margin-bottom:4px">Drop file here or click to browse</div>'
        + '<div style="font-size:12px;color:#556270">PDF, PNG, JPG, TXT (max 10MB)</div>'
        + '<input type="file" id="ai-import-file-input" accept=".pdf,.png,.jpg,.jpeg,.txt,.docx" style="display:none">'
        + '</div>'
        + '<div id="ai-import-status" style="display:none;text-align:center;padding:24px">'
        + '<div class="spinner" style="margin:0 auto 12px;width:32px;height:32px;border:3px solid rgba(255,255,255,0.1);border-top-color:#00E676;border-radius:50%;animation:spin 0.8s linear infinite"></div>'
        + '<div style="font-size:13px;color:#8B9DAF">Analyzing document with AI...</div>'
        + '</div>'
        + '<div id="ai-import-preview" style="display:none"></div>'
        + '</div>';
      overlay.innerHTML = html;
      document.body.appendChild(overlay);
      // Dropzone events
      var dropzone = document.getElementById('ai-import-dropzone');
      var fileInput = document.getElementById('ai-import-file-input');
      dropzone.addEventListener('click', function() { fileInput.click(); });
      dropzone.addEventListener('dragover', function(e) { e.preventDefault(); dropzone.style.borderColor = 'rgba(0,230,118,0.5)'; });
      dropzone.addEventListener('dragleave', function() { dropzone.style.borderColor = 'rgba(255,255,255,0.15)'; });
      dropzone.addEventListener('drop', function(e) { e.preventDefault(); dropzone.style.borderColor = 'rgba(255,255,255,0.15)'; if (e.dataTransfer.files.length) _processAiImportFile(e.dataTransfer.files[0]); });
      fileInput.addEventListener('change', function() { if (fileInput.files.length) _processAiImportFile(fileInput.files[0]); });
      document.getElementById('ai-import-close').addEventListener('click', function() { overlay.remove(); });
      overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
    }

    function _processAiImportFile(file) {
      var dropzone = document.getElementById('ai-import-dropzone');
      var status = document.getElementById('ai-import-status');
      var preview = document.getElementById('ai-import-preview');
      if (dropzone) dropzone.style.display = 'none';
      if (status) status.style.display = '';
      if (preview) preview.style.display = 'none';
      var formData = new FormData();
      formData.append('file', file);
      fetch('/api/churches/' + CHURCH_ID + '/rundown-plans/import/ai', {
        method: 'POST',
        headers: { 'x-csrf-token': getCsrfToken() },
        credentials: 'include',
        body: formData,
      }).then(function(r) { return r.json().then(function(d) { return { ok: r.ok, data: d }; }); })
      .then(function(result) {
        if (status) status.style.display = 'none';
        if (!result.ok) { toast(result.data.error || 'Import failed', true); if (dropzone) dropzone.style.display = ''; return; }
        _renderAiImportPreview(result.data.items || [], result.data.suggestedTitle || 'Imported Service');
      }).catch(function(e) {
        if (status) status.style.display = 'none';
        if (dropzone) dropzone.style.display = '';
        toast('Import failed: ' + e.message, true);
      });
    }

    function _renderAiImportPreview(items, suggestedTitle) {
      var preview = document.getElementById('ai-import-preview');
      if (!preview) return;
      var html = '<div style="margin-top:16px">';
      html += '<div style="font-size:14px;font-weight:700;color:#F0F2F4;margin-bottom:8px">Parsed ' + items.length + ' items</div>';
      html += '<div style="margin-bottom:12px"><input type="text" id="ai-import-title" value="' + escapeHtml(suggestedTitle) + '" style="width:100%;background:rgba(255,255,255,0.06);color:#F0F2F4;border:1px solid rgba(255,255,255,0.1);border-radius:6px;padding:8px 12px;font-size:14px;font-weight:600;outline:none"></div>';
      html += '<div style="max-height:300px;overflow-y:auto;display:flex;flex-direction:column;gap:4px">';
      items.forEach(function(item, i) {
        var typeColor = RUNDOWN_TYPE_COLORS[item.itemType] || RUNDOWN_TYPE_COLORS.other;
        html += '<div class="card" style="padding:8px 12px;border-left:3px solid ' + typeColor + ';display:flex;align-items:center;gap:8px">';
        html += '<span style="font-size:11px;color:#556270;width:20px;text-align:center">' + (i + 1) + '</span>';
        html += '<input type="text" value="' + escapeHtml(item.title) + '" data-ai-item-idx="' + i + '" data-field="title" style="flex:1;background:transparent;color:#F0F2F4;border:none;font-size:13px;outline:none;min-width:0">';
        html += '<span style="font-size:10px;color:' + typeColor + ';background:rgba(255,255,255,0.06);padding:2px 6px;border-radius:3px">' + escapeHtml(RUNDOWN_TYPE_LABELS[item.itemType] || item.itemType) + '</span>';
        html += '<span style="font-size:11px;color:#8B9DAF;font-family:ui-monospace,monospace">' + _rundownFormatMMSS(item.lengthSeconds || item.duration || 0) + '</span>';
        if (item.assignee) html += '<span style="font-size:11px;color:#556270">' + escapeHtml(item.assignee) + '</span>';
        html += '</div>';
      });
      html += '</div>';
      html += '<div style="display:flex;gap:8px;margin-top:16px;justify-content:flex-end">';
      html += '<button id="ai-import-cancel" class="btn-secondary" style="font-size:13px;padding:8px 16px">Cancel</button>';
      html += '<button id="ai-import-create" class="btn-primary" style="font-size:13px;padding:8px 20px;font-weight:700">Create Rundown</button>';
      html += '</div></div>';
      preview.innerHTML = html;
      preview.style.display = '';
      document.getElementById('ai-import-cancel').addEventListener('click', function() {
        var modal = document.getElementById('rundown-ai-import-modal');
        if (modal) modal.remove();
      });
      document.getElementById('ai-import-create').addEventListener('click', function() {
        var title = document.getElementById('ai-import-title').value.trim() || 'Imported Service';
        // Read edited titles back
        preview.querySelectorAll('input[data-ai-item-idx]').forEach(function(inp) {
          var idx = parseInt(inp.getAttribute('data-ai-item-idx'), 10);
          if (items[idx] && inp.getAttribute('data-field') === 'title') items[idx].title = inp.value.trim();
        });
        var modal = document.getElementById('rundown-ai-import-modal');
        if (modal) modal.remove();
        _createRundownFromAiItems(title, items);
      });
    }

    function _createRundownFromAiItems(title, items) {
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans', { title: title, serviceDate: new Date().toISOString().slice(0, 10) }).then(function(plan) {
        var chain = Promise.resolve();
        items.forEach(function(item) {
          chain = chain.then(function() {
            return api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + plan.id + '/items', {
              title: item.title,
              itemType: item.itemType || 'other',
              lengthSeconds: item.lengthSeconds || item.duration || 0,
              notes: item.notes || '',
              assignee: item.assignee || '',
            });
          });
        });
        chain.then(function() {
          toast('Rundown imported: ' + title);
          _rundownSelectedPlanId = plan.id;
          loadRundownManager();
          setTimeout(function() { rundownSelectPlan(plan.id, 'manual'); }, 300);
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    // ── Timer Display ──────────────────────────────────────────────────────────

    function openTimerDisplay() {
      if (!_rundownSelectedPlan) return;
      var openTimer = function(share) {
        _rundownShareData = share;
        var urls = _rundownResolveShareUrls(share || {});
        if (urls.timerUrl) _rundownOpenUrl(urls.timerUrl);
        _updateSharedBadge(true);
      };
      if (_rundownShareData && _rundownShareData.share_token) {
        openTimer(_rundownShareData);
        return;
      }
      var planId = _rundownSelectedPlan.id;
      _rundownEnsureShare(planId).then(openTimer).catch(function(e) { toast('Failed to open timer: ' + e.message, true); });
    }

    // Live Mode, Public View, Timer View buttons now use data-action delegation
    // (rundownOpenShowMode, rundownOpenPublicView, rundownOpenTimerDisplay)
    // Mobile status select sync
    var statusSelMobile = document.getElementById('rundown-editor-status-select-mobile');
    var statusSelDesktop = document.getElementById('rundown-editor-status-select');
    if (statusSelMobile) {
      statusSelMobile.addEventListener('change', function() {
        if (statusSelDesktop) statusSelDesktop.value = statusSelMobile.value;
        statusSelMobile.dispatchEvent(new Event('input', { bubbles: true }));
      });
    }
    // 3.2: Overflow menu toggle
    (function() {
      var overflowBtn = document.getElementById('toolbar-overflow-btn');
      var overflowMenu = document.getElementById('toolbar-overflow-menu');
      var overflowBackdrop = document.getElementById('toolbar-overflow-backdrop');
      if (!overflowBtn || !overflowMenu) return;
      function toggleOverflow(force) {
        var isOpen = typeof force === 'boolean' ? force : !overflowMenu.classList.contains('open');
        overflowMenu.classList.toggle('open', isOpen);
        if (overflowBackdrop) overflowBackdrop.classList.toggle('open', isOpen);
      }
      overflowBtn.addEventListener('click', function() { toggleOverflow(); });
      if (overflowBackdrop) overflowBackdrop.addEventListener('click', function() { toggleOverflow(false); });
      // Close on action
      overflowMenu.addEventListener('click', function(e) {
        if (e.target.tagName === 'BUTTON') setTimeout(function() { toggleOverflow(false); }, 100);
      });
    })();
    // Phase 11: Export dropdown toggle
    (function() {
      var exportBtn = document.getElementById('btn-rundown-export');
      var exportMenu = document.getElementById('rundown-export-menu');
      if (!exportBtn || !exportMenu) return;
      exportBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        var isOpen = exportMenu.style.display === 'none';
        exportMenu.style.display = isOpen ? 'block' : 'none';
        if (isOpen) {
          function closeExport() { exportMenu.style.display = 'none'; document.removeEventListener('click', closeExport); }
          setTimeout(function() { document.addEventListener('click', closeExport); }, 10);
        }
      });
      exportMenu.querySelectorAll('[data-action]').forEach(function(item) {
        item.addEventListener('mouseenter', function() { item.style.background = 'rgba(255,255,255,0.06)'; });
        item.addEventListener('mouseleave', function() { item.style.background = 'none'; });
      });
    })();
    var btnLiveTimer = document.getElementById('btn-rundown-live-timer');
    if (btnLiveTimer) btnLiveTimer.addEventListener('click', function() {
      // Use the active session's plan or the selected plan
      var plan = _rundownState ? { id: _rundownState.planId } : _rundownSelectedPlan;
      if (!plan) return;
      _rundownEnsureShare(plan.id).then(function(share) {
        _rundownShareData = share;
        var urls = _rundownResolveShareUrls(share || {});
        if (urls.timerUrl) _rundownOpenUrl(urls.timerUrl);
        _updateSharedBadge(true);
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    });

    function rundownAdvance() {
      var roomId = _rundownState ? (_rundownState.roomId || '') : (_selectedRoomId || '');
      api('POST', '/api/churches/' + CHURCH_ID + '/live-rundown/advance', { roomId: roomId }).then(function(data) {
        if (data) { _rundownState = data; renderRundownActive(data); }
      }).catch(function(e) { toast(e.message, true); });
    }

    function rundownBack() {
      var roomId = _rundownState ? (_rundownState.roomId || '') : (_selectedRoomId || '');
      api('POST', '/api/churches/' + CHURCH_ID + '/live-rundown/back', { roomId: roomId }).then(function(data) {
        if (data) { _rundownState = data; renderRundownActive(data); }
      }).catch(function(e) { toast(e.message, true); });
    }

    // ── LIVE SHOW MODE (per-plan cueing in editor) ───────────────────────────
    var _liveShowState = null;     // { isLive, currentCueIndex, startedAt, currentCueStartedAt, planId }
    var _liveShowTimer = null;     // setInterval ref for countdown tick
    var _liveAutoAdvanceTimer = null; // timeout ref for auto-advance

    function liveShowStart() {
      if (!_rundownSelectedPlan) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/live/start').then(function(data) {
        _liveShowState = data;
        _rundownSelectedPlan = data.plan || _rundownSelectedPlan;
        // 4.7: Auto-transition status to Live
        _rundownAutoTransitionToLive(_rundownSelectedPlan.id);
        renderRundownEditor(_rundownSelectedPlan);
        _startLiveShowTimer();
        toast('Live started');
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function liveShowStop() {
      if (!_rundownSelectedPlan || !_liveShowState) return;
      styledConfirm('End Live', 'End live mode?').then(function(ok) {
        if (!ok) return;
        api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/live/stop').then(function() {
          _stopLiveShowTimer();
          _liveShowState = null;
          renderRundownEditor(_rundownSelectedPlan);
          toast('Live ended');
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    function liveShowGo() {
      if (!_rundownSelectedPlan || !_liveShowState) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/live/go').then(function(data) {
        _liveShowState = data;
        _rundownSelectedPlan = data.plan || _rundownSelectedPlan;
        renderRundownEditorItems(_rundownSelectedPlan.items || []);
        _resetAutoAdvanceTimer();
      }).catch(function(e) { toast(e.message, true); });
    }

    function liveShowBack() {
      if (!_rundownSelectedPlan || !_liveShowState) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/live/back').then(function(data) {
        _liveShowState = data;
        _rundownSelectedPlan = data.plan || _rundownSelectedPlan;
        renderRundownEditorItems(_rundownSelectedPlan.items || []);
        _resetAutoAdvanceTimer();
      }).catch(function(e) { toast(e.message, true); });
    }

    function liveShowGoto(index) {
      if (!_rundownSelectedPlan || !_liveShowState) return;
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/live/goto/' + index).then(function(data) {
        _liveShowState = data;
        _rundownSelectedPlan = data.plan || _rundownSelectedPlan;
        renderRundownEditorItems(_rundownSelectedPlan.items || []);
        _resetAutoAdvanceTimer();
      }).catch(function(e) { toast(e.message, true); });
    }

    function liveShowPause() {
      if (!_rundownSelectedPlan || !_liveShowState) return;
      var isPaused = _liveShowState.isPaused;
      var endpoint = isPaused ? '/live/resume' : '/live/pause';
      api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + endpoint).then(function(data) {
        _liveShowState = data;
        _rundownSelectedPlan = data.plan || _rundownSelectedPlan;
        renderRundownEditor(_rundownSelectedPlan);
        toast(isPaused ? 'Resumed' : 'Paused');
      }).catch(function(e) { toast('Failed: ' + e.message, true); });
    }

    function _startLiveShowTimer() {
      _stopLiveShowTimer();
      _liveShowTimer = setInterval(function() {
        if (!_liveShowState || !_liveShowState.isLive) { _stopLiveShowTimer(); return; }
        _updateLiveTimerDisplay();
        _checkAutoAdvance();
      }, 250);
    }

    function _stopLiveShowTimer() {
      if (_liveShowTimer) { clearInterval(_liveShowTimer); _liveShowTimer = null; }
      if (_liveAutoAdvanceTimer) { clearTimeout(_liveAutoAdvanceTimer); _liveAutoAdvanceTimer = null; }
    }

    function _resetAutoAdvanceTimer() {
      if (_liveAutoAdvanceTimer) { clearTimeout(_liveAutoAdvanceTimer); _liveAutoAdvanceTimer = null; }
    }

    function _checkAutoAdvance() {
      if (!_liveShowState || !_rundownSelectedPlan) return;
      var items = _rundownSelectedPlan.items || [];
      var idx = _liveShowState.currentCueIndex;
      if (idx < 0 || idx >= items.length) return;
      var item = items[idx];
      if (!item.autoAdvance || !item.lengthSeconds) return;
      var elapsed = (Date.now() - _liveShowState.currentCueStartedAt) / 1000;
      if (elapsed >= item.lengthSeconds) {
        // Auto-advance to next cue
        liveShowGo();
      }
    }

    function _updateLiveTimerDisplay() {
      if (!_liveShowState || !_rundownSelectedPlan) return;
      var items = _rundownSelectedPlan.items || [];
      var idx = _liveShowState.currentCueIndex;
      if (idx < 0 || idx >= items.length) return;
      var item = items[idx];
      // When paused, freeze elapsed at the stored value
      var elapsed;
      if (_liveShowState.isPaused) {
        elapsed = Math.floor(_liveShowState.pausedElapsed || 0);
      } else {
        elapsed = Math.floor((Date.now() - _liveShowState.currentCueStartedAt) / 1000);
      }
      var remaining = Math.max(0, (item.lengthSeconds || 0) - elapsed);
      var isOvertime = elapsed > (item.lengthSeconds || 0) && item.lengthSeconds > 0;
      var overtimeSec = isOvertime ? elapsed - item.lengthSeconds : 0;
      var pct = item.lengthSeconds > 0 ? Math.min(1, elapsed / item.lengthSeconds) : 0;

      // Update timer display in active cue row
      var timerEl = document.getElementById('live-cue-timer');
      if (timerEl) {
        if (item.lengthSeconds > 0) {
          if (isOvertime) {
            timerEl.textContent = '+' + _rundownFormatMMSS(overtimeSec);
            timerEl.style.color = '#FF5252';
          } else {
            timerEl.textContent = _rundownFormatMMSS(remaining);
            if (pct > 0.9) timerEl.style.color = '#FF5252';
            else if (pct > 0.5) timerEl.style.color = '#FFB74D';
            else timerEl.style.color = '#00E676';
          }
        } else {
          timerEl.textContent = _rundownFormatMMSS(elapsed);
          timerEl.style.color = '#8B9DAF';
        }
      }

      // Update elapsed display
      var elapsedEl = document.getElementById('live-cue-elapsed');
      if (elapsedEl) elapsedEl.textContent = _rundownFormatMMSS(elapsed);

      // Update show elapsed
      var showEl = document.getElementById('live-show-elapsed');
      if (showEl && _liveShowState.startedAt) {
        var showElapsed = Math.floor((Date.now() - _liveShowState.startedAt) / 1000);
        var sh = Math.floor(showElapsed / 3600);
        var sm = Math.floor((showElapsed % 3600) / 60);
        var ss = showElapsed % 60;
        showEl.textContent = (sh > 0 ? sh + ':' : '') + (sm < 10 && sh > 0 ? '0' : '') + sm + ':' + (ss < 10 ? '0' : '') + ss;
      }
      _updateRundownHardStartBar();
    }

    // ── Keyboard shortcuts for live show mode ─────────────────────────────────
    document.addEventListener('keydown', function(e) {
      if (!_liveShowState || !_liveShowState.isLive) return;
      // Don't capture if user is typing in an input/textarea/select
      var tag = (e.target.tagName || '').toLowerCase();
      if (tag === 'input' || tag === 'textarea' || tag === 'select') return;
      // Only capture on the rundown page
      var rundownPage = document.getElementById('page-rundown');
      if (!rundownPage || !rundownPage.classList.contains('active')) return;

      if (e.key === 'p' || e.key === 'P') {
        e.preventDefault();
        liveShowPause();
      } else if (e.key === ' ' || e.key === 'ArrowRight') {
        e.preventDefault();
        liveShowGo();
      } else if (e.key === 'ArrowLeft') {
        e.preventDefault();
        liveShowBack();
      } else if (e.key === 'Escape') {
        e.preventDefault();
        liveShowStop();
      }
    });

    // ── Templates ─────────────────────────────────────────────────────────────

    function rundownShowTemplates() {
      showRundownView('templates');
      api('GET', '/api/churches/' + CHURCH_ID + '/rundown-templates').then(function(data) {
        var templates = (data && data.templates) || [];
        var container = document.getElementById('rundown-templates-list');
        if (!container) return;
        if (templates.length === 0) {
          container.innerHTML = '<div style="color:#556270;text-align:center;padding:20px;font-size:13px">No templates saved yet. Open a rundown and click "Save as Template".</div>';
          return;
        }
        var html = '';
        for (var i = 0; i < templates.length; i++) {
          var t = templates[i];
          html += '<div style="display:flex;align-items:center;justify-content:space-between;padding:10px 12px;border-radius:8px;border:1px solid rgba(255,255,255,0.06);background:rgba(255,255,255,0.02)">';
          html += '<div style="min-width:0;flex:1">';
          html += '<div style="font-size:14px;font-weight:600;color:#F0F2F4">' + escapeHtml(t.templateName || t.title) + '</div>';
          html += '<div style="font-size:12px;color:#556270;margin-top:2px">' + (t.items ? t.items.length : 0) + ' items</div>';
          html += '</div>';
          html += '<div style="display:flex;gap:6px">';
          html += '<button class="btn-primary" data-action="rundownCreateFromTemplate" data-template-id="' + t.id + '" style="font-size:12px;padding:4px 10px">Use Template</button>';
          html += '<button class="btn-secondary" data-action="rundownDeleteTemplate" data-template-id="' + t.id + '" style="font-size:12px;padding:4px 10px;color:#FF5252">Delete</button>';
          html += '</div>';
          html += '</div>';
        }
        container.innerHTML = html;
      }).catch(function() {});
    }

    function rundownHideTemplates() {
      loadRundownManager();
    }

    function rundownPrintPlan() {
      var plan = _rundownSelectedPlan;
      if (!plan || !Array.isArray(plan.items)) return;
      var churchName = (document.getElementById('sidebar-church-name') || {}).textContent || '';
      var roomName = plan.roomId && _rundownRoomMap[plan.roomId] ? _rundownRoomMap[plan.roomId] : '';
      var startTime = _rundownStartTime || '09:00';

      // Compute timing
      var currentTime = startTime;
      var timingData = [];
      var totalSeconds = 0;
      for (var i = 0; i < plan.items.length; i++) {
        var item = plan.items[i];
        var dur = item.lengthSeconds || 0;
        if (item.startType === 'hard' && item.hardStartTime) {
          currentTime = item.hardStartTime;
        }
        timingData.push({ start: currentTime, end: _rundownTimeAdd(currentTime, dur) });
        totalSeconds += dur;
        currentTime = _rundownTimeAdd(currentTime, dur);
      }

      var totalH = Math.floor(totalSeconds / 3600);
      var totalM = Math.floor((totalSeconds % 3600) / 60);
      var totalStr = (totalH > 0 ? totalH + 'h ' : '') + totalM + 'm';

      // Format service date
      var dateStr = '';
      if (plan.serviceDate) {
        var d = new Date(plan.serviceDate + 'T00:00:00');
        dateStr = d.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
      }

      // Build column headers
      var hasColumns = _rundownColumns.length > 0;
      var colHeaders = '';
      for (var ci = 0; ci < _rundownColumns.length; ci++) {
        colHeaders += '<th>' + escapeHtml(_rundownColumns[ci].name) + '</th>';
      }

      // Build rows
      var rows = '';
      for (var i = 0; i < plan.items.length; i++) {
        var item = plan.items[i];
        var isSection = item.itemType === 'section';
        var typeLabel = RUNDOWN_TYPE_LABELS[item.itemType] || item.itemType || '';
        var dur = item.lengthSeconds || 0;
        var durStr = dur > 0 ? _rundownFormatMMSS(dur) : '';
        var td = timingData[i];
        var notes = item.notes || '';
        // Strip HTML tags for clean text
        var tmp = document.createElement('div');
        tmp.innerHTML = notes;
        var notesText = tmp.textContent || tmp.innerText || '';

        if (isSection) {
          var sColor = item.color || '#6b7280';
          var colspan = 6 + _rundownColumns.length;
          rows += '<tr class="section-row" style="border-left:4px solid ' + sColor + '"><td colspan="' + colspan + '">' + escapeHtml(item.title || '') + '</td></tr>';
          continue;
        }

        var printColor = item.color || RUNDOWN_TYPE_COLORS[item.itemType] || '#95a5a6';
        rows += '<tr style="border-left:4px solid ' + printColor + '">';
        rows += '<td class="num">' + (i + 1) + '</td>';
        rows += '<td class="title">' + escapeHtml(item.title || '') + '</td>';
        rows += '<td>' + escapeHtml(typeLabel) + '</td>';
        rows += '<td>' + escapeHtml(item.assignee || '') + '</td>';
        for (var ci = 0; ci < _rundownColumns.length; ci++) {
          var colVal = _rundownColumnValues[item.id + '_' + _rundownColumns[ci].id] || '';
          rows += '<td>' + escapeHtml(String(colVal)) + '</td>';
        }
        rows += '<td class="mono">' + durStr + '</td>';
        rows += '<td class="mono">' + (td ? td.start : '') + '</td>';
        if (notesText.trim()) {
          rows += '</tr><tr class="notes-row"><td></td><td colspan="' + (4 + _rundownColumns.length + 1) + '" class="notes">' + escapeHtml(notesText) + '</td></tr>';
        } else {
          rows += '</tr>';
        }
      }

      var html = '<!DOCTYPE html><html><head><meta charset="utf-8"><title>' + escapeHtml(plan.title || 'Rundown') + '</title>' +
        '<style>' +
        '*, *::before, *::after { box-sizing: border-box; }' +
        'body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; color: #111; margin: 0; padding: 24px 32px; font-size: 12px; }' +
        '.header { margin-bottom: 20px; border-bottom: 2px solid #111; padding-bottom: 12px; }' +
        '.church-name { font-size: 18px; font-weight: 700; margin-bottom: 2px; }' +
        '.plan-title { font-size: 22px; font-weight: 700; margin-bottom: 4px; }' +
        '.meta { font-size: 12px; color: #555; display: flex; gap: 16px; flex-wrap: wrap; }' +
        'table { width: 100%; border-collapse: collapse; margin-top: 8px; }' +
        'thead th { text-align: left; font-size: 10px; text-transform: uppercase; letter-spacing: 0.5px; color: #555; border-bottom: 1px solid #ccc; padding: 6px 8px; white-space: nowrap; }' +
        'tbody td { padding: 5px 8px; border-bottom: 1px solid #e5e5e5; vertical-align: top; }' +
        'td.num { width: 28px; text-align: center; color: #999; }' +
        'td.title { font-weight: 600; }' +
        'td.mono, th.mono { font-family: "SF Mono", SFMono-Regular, ui-monospace, monospace; font-size: 11px; }' +
        'td.notes { font-size: 11px; color: #555; padding-top: 0; padding-bottom: 8px; font-style: italic; }' +
        'tr.notes-row td { border-bottom: 1px solid #e5e5e5; }' +
        'tr.section-row td { font-weight: 700; font-size: 13px; text-transform: uppercase; letter-spacing: 0.5px; background: #f3f3f3; padding: 8px; border-bottom: 1px solid #ccc; }' +
        '.footer { margin-top: 16px; font-size: 10px; color: #999; display: flex; justify-content: space-between; }' +
        '@media print {' +
        '  body { padding: 0; }' +
        '  @page { size: auto; margin: 16mm 12mm; }' +
        '  .no-print { display: none !important; }' +
        '}' +
        '</style></head><body>' +
        '<div class="header">' +
        (churchName ? '<div class="church-name">' + escapeHtml(churchName) + '</div>' : '') +
        '<div class="plan-title">' + escapeHtml(plan.title || 'Untitled Plan') + '</div>' +
        '<div class="meta">' +
        (dateStr ? '<span>' + escapeHtml(dateStr) + '</span>' : '') +
        (roomName ? '<span>' + escapeHtml(roomName) + '</span>' : '') +
        '<span>Start: ' + startTime + '</span>' +
        '<span>Duration: ' + totalStr + '</span>' +
        '<span>' + plan.items.length + ' items</span>' +
        '</div></div>' +
        '<button class="no-print" data-action="printPage" style="margin-bottom:12px;padding:6px 16px;font-size:13px;cursor:pointer">Print</button>' +
        '<table><thead><tr>' +
        '<th>#</th><th>Title</th><th>Type</th><th>Who</th>' +
        colHeaders +
        '<th class="mono">Duration</th><th class="mono">Start</th>' +
        '</tr></thead><tbody>' + rows + '</tbody></table>' +
        '<div class="footer"><span>Printed from TallyConnect</span><span></span></div>' +
        '</body></html>';

      var printWin = window.open('', '_blank');
      if (printWin) {
        printWin.document.write(html);
        printWin.document.close();
        printWin.focus();
        setTimeout(function() { printWin.print(); }, 400);
      }
    }

    function rundownSaveTemplate() {
      if (!_rundownSelectedPlan || _rundownSelectedPlan.source === 'pco') return;
      styledPrompt('Save Template', 'Template name', _rundownSelectedPlan.title).then(function(name) {
        if (!name || !name.trim()) return;
        api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans/' + _rundownSelectedPlan.id + '/save-template', { templateName: name.trim() }).then(function() {
          toast('Template saved');
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    function rundownCreateFromTemplate(templateId) {
      _openRundownPlanModal('create', { title: 'Sunday Service', date: new Date().toISOString().slice(0, 10) }).then(function(result) {
        if (!result) return;
        api('POST', '/api/churches/' + CHURCH_ID + '/rundown-templates/' + templateId + '/create', {
          title: result.title,
          serviceDate: result.date || null,
        }).then(function(plan) {
          toast('Rundown created from template');
          _rundownSelectedPlanId = plan.id;
          loadRundownManager();
          setTimeout(function() { rundownSelectPlan(plan.id, 'manual'); }, 300);
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    function rundownDeleteTemplate(templateId) {
      styledConfirm('Delete Template', 'Delete this template?').then(function(ok) {
        if (!ok) return;
        api('DELETE', '/api/churches/' + CHURCH_ID + '/rundown-templates/' + templateId).then(function() {
          toast('Template deleted');
          rundownShowTemplates();
        }).catch(function(e) { toast('Failed: ' + e.message, true); });
      });
    }

    function loadCompanionActionsCache(planId) {
      _companionActionsPlanId = planId;
      api('GET', '/api/churches/' + CHURCH_ID + '/live-rundown/actions/' + encodeURIComponent(planId)).then(function(data) {
        _companionActionsCache = data || {};
        // Re-render items list if rundown page is active
        if (_rundownState && document.getElementById('page-rundown').classList.contains('active')) {
          renderRundownItems(_rundownState);
        }
      }).catch(function() { _companionActionsCache = {}; });
    }

    function renderRundownInactive() {
      showRundownView('manager');
      loadRundownManager();
    }

    function renderRundownActive(state) {
      var noSession = document.getElementById('rundown-no-session');
      var active = document.getElementById('rundown-active');
      if (noSession) noSession.style.display = 'none';
      if (active) active.style.display = '';

      // Plan title + meta
      var titleEl = document.getElementById('rundown-plan-title');
      var callerEl = document.getElementById('rundown-caller');
      var elapsedEl = document.getElementById('rundown-elapsed');
      var progressEl = document.getElementById('rundown-progress');
      if (titleEl) titleEl.textContent = state.planTitle || 'Service';
      if (callerEl) callerEl.textContent = 'TD: ' + (state.callerName || 'Unknown');
      if (elapsedEl) elapsedEl.textContent = formatRundownDuration(state.totalElapsed || 0) + ' elapsed';
      if (progressEl) progressEl.textContent = (state.currentIndex + 1) + ' / ' + state.totalItems;

      // Progress bar
      updateRundownProgressBar(state);

      // Auto-advance toggle state
      updateAutoAdvanceToggle(state);

      // Countdown hero
      var ci = state.currentItem;
      var heroEl = document.getElementById('rundown-countdown-hero');
      var currentTitle = document.getElementById('rundown-current-title');
      var timerEl = document.getElementById('rundown-timer');
      var timerLabel = document.getElementById('rundown-timer-label');
      if (currentTitle) currentTitle.textContent = ci ? ci.title : '';
      if (ci && ci.remainingSeconds !== null && ci.remainingSeconds !== undefined) {
        if (ci.isOvertime) {
          if (timerEl) { timerEl.textContent = '+' + formatRundownTimer(ci.overtimeSeconds); timerEl.style.color = '#FF5252'; }
          if (timerLabel) timerLabel.textContent = 'OVERTIME';
          if (heroEl) heroEl.style.borderColor = 'rgba(239,68,68,0.4)';
        } else if (ci.isWarning) {
          if (timerEl) { timerEl.textContent = formatRundownTimer(ci.remainingSeconds); timerEl.style.color = '#FFA726'; }
          if (timerLabel) timerLabel.textContent = 'REMAINING';
          if (heroEl) heroEl.style.borderColor = 'rgba(255,167,38,0.4)';
        } else {
          if (timerEl) { timerEl.textContent = formatRundownTimer(ci.remainingSeconds); timerEl.style.color = '#00E676'; }
          if (timerLabel) timerLabel.textContent = 'REMAINING';
          if (heroEl) heroEl.style.borderColor = '';
        }
      } else {
        if (timerEl) { timerEl.textContent = formatRundownTimer(ci ? ci.elapsedSeconds : 0); timerEl.style.color = '#8B9DAF'; }
        if (timerLabel) timerLabel.textContent = 'ELAPSED';
        if (heroEl) heroEl.style.borderColor = '';
      }

      // Schedule delta badge — enhanced with severity colors
      var deltaEl = document.getElementById('rundown-schedule-delta');
      if (deltaEl && state.scheduleDelta) {
        deltaEl.style.display = '';
        var absSec = Math.abs(state.scheduleDelta.seconds);
        var deltaMin = Math.round(absSec / 60);
        if (state.scheduleDelta.isOnTime) {
          deltaEl.textContent = 'On Time';
          deltaEl.style.background = 'rgba(0,230,118,0.1)'; deltaEl.style.color = '#00E676';
        } else if (state.scheduleDelta.isAhead) {
          deltaEl.textContent = '+' + deltaMin + ' min ahead';
          deltaEl.style.background = 'rgba(33,150,243,0.1)'; deltaEl.style.color = '#42A5F5';
        } else if (absSec < 120) {
          // Slightly behind (<2 min) — yellow/warning
          deltaEl.textContent = '-' + deltaMin + ' min behind';
          deltaEl.style.background = 'rgba(255,183,77,0.1)'; deltaEl.style.color = '#FFB74D';
        } else {
          // Significantly behind (>=2 min) — red
          deltaEl.textContent = '-' + deltaMin + ' min behind';
          deltaEl.style.background = 'rgba(239,68,68,0.1)'; deltaEl.style.color = '#FF5252';
        }
      }

      // Item list
      renderRundownItems(state);

      // Team panel
      renderRundownTeam(state.team || []);
    }

    function getRundownItemIcon(itemType, isCurrent) {
      var title = (itemType || '').toLowerCase();
      if (title === 'song') return SVG.music;
      if (title === 'media') return SVG.playMedia;
      if (title === 'sermon' || title === 'message') return SVG.microphone;
      if (title === 'prayer') return SVG.prayer;
      if (title === 'announcement') return SVG.chat;
      if (title === 'transition') return SVG.shuffle;
      if (title === 'welcome') return SVG.sparkle;
      if (title === 'offering') return SVG.diamond;
      if (title === 'communion') return SVG.record;
      if (title === 'scripture') return SVG.docItem;
      if (title === 'section') return SVG.arrowRight;
      return SVG.docItem;
    }

    function renderRundownItems(state) {
      var container = document.getElementById('rundown-items-list');
      if (!container) return;
      var items = state.items || [];
      var now = state.timestamp || Date.now();
      var html = '';
      for (var i = 0; i < items.length; i++) {
        var item = items[i];
        var isCurrent = item.status === 'current';
        var isCompleted = item.status === 'completed';
        var isHeader = item.itemType === 'header';

        if (isHeader) {
          html += '<div style="padding:8px 12px;font-size:11px;text-transform:uppercase;letter-spacing:1px;font-weight:700;color:#00E676;margin-top:8px">' + escapeHtml(item.title) + '</div>';
          continue;
        }

        var bg = isCurrent ? 'rgba(0,230,118,0.08)' : isCompleted ? 'rgba(0,0,0,0.15)' : 'transparent';
        var border = isCurrent ? '1px solid rgba(0,230,118,0.3)' : '1px solid transparent';
        var opacity = isCompleted ? '0.6' : '1';
        var leftBar = isCurrent ? 'border-left:4px solid #00E676;' : 'border-left:4px solid transparent;';
        var pad = isCurrent ? 'padding:14px 12px' : 'padding:10px 12px';

        html += '<div data-rundown-idx="' + i + '" style="display:flex;align-items:flex-start;' + pad + ';border-radius:8px;background:' + bg + ';border:' + border + ';opacity:' + opacity + ';' + leftBar + 'transition:all 0.3s">';

        // Index number
        html += '<div style="width:28px;font-size:12px;color:' + (isCurrent ? '#00E676' : '#556270') + ';font-weight:700;flex-shrink:0;padding-top:2px">' + (i + 1) + '</div>';

        // Item type icon
        var iconColor = isCurrent ? '#00E676' : (RUNDOWN_TYPE_COLORS[item.itemType] || '#556270');
        html += '<div style="width:20px;flex-shrink:0;text-align:center;margin-right:8px;color:' + iconColor + ';padding-top:2px">';
        html += getRundownItemIcon(item.itemType, isCurrent);
        html += '</div>';

        // Title + meta + notes
        html += '<div style="flex:1;min-width:0">';
        var titleSize = isCurrent ? '16px' : '14px';
        html += '<div style="font-size:' + titleSize + ';font-weight:' + (isCurrent ? '700' : '500') + ';color:' + (isCurrent ? '#F0F2F4' : isCompleted ? '#8B9DAF' : '#B0BEC5') + ';overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + escapeHtml(item.title) + '</div>';
        if (item.songTitle && item.songTitle !== item.title) {
          html += '<div style="font-size:11px;color:#556270;margin-top:1px">' + escapeHtml(item.songTitle) + '</div>';
        }
        if (item.arrangementKey) {
          html += '<span style="font-size:10px;color:#42A5F5;background:rgba(66,165,245,0.1);padding:1px 5px;border-radius:3px;margin-top:2px;display:inline-block">Key: ' + escapeHtml(item.arrangementKey) + '</span> ';
        }
        // Notes (may contain safe HTML from rich text editor)
        var notes = item.notes || [];
        for (var n = 0; n < notes.length; n++) {
          if (notes[n]) {
            // If note contains HTML tags, render as-is (already sanitized server-side); otherwise escape
            var noteHasHtml = /<[a-z][\s\S]*>/i.test(notes[n]);
            html += '<div style="font-size:11px;color:#8B9DAF;margin-top:3px;line-height:1.3;font-style:italic">' + (noteHasHtml ? notes[n] : escapeHtml(notes[n])) + '</div>';
          }
        }
        html += '</div>';

        // Duration / per-item countdown
        html += '<div style="flex-shrink:0;text-align:right;margin-left:8px;padding-top:2px">';
        if (isCompleted && item.actualDuration != null) {
          var planned = item.lengthSeconds || 0;
          var delta = Math.round(item.actualDuration - planned);
          html += '<div style="font-size:12px;color:#556270">' + formatRundownTimer(Math.round(item.actualDuration)) + '</div>';
          if (planned > 0 && Math.abs(delta) >= 5) {
            var dColor = delta > 0 ? '#FF5252' : '#42A5F5';
            html += '<div style="font-size:10px;color:' + dColor + '">' + (delta > 0 ? '+' : '') + delta + 's</div>';
          }
        } else if (isCurrent && state.currentItem) {
          // Current item: show live countdown
          if (state.currentItem.remainingSeconds !== null && state.currentItem.remainingSeconds !== undefined) {
            var timerColor = state.currentItem.isOvertime ? '#FF5252' : state.currentItem.isWarning ? '#FFA726' : '#00E676';
            var timerText = state.currentItem.isOvertime ? '+' + formatRundownTimer(state.currentItem.overtimeSeconds) : formatRundownTimer(state.currentItem.remainingSeconds);
            html += '<div data-item-timer="' + i + '" style="font-size:14px;font-weight:700;color:' + timerColor + ';font-family:\'SF Mono\',SFMono-Regular,ui-monospace,monospace">' + timerText + '</div>';
          } else {
            html += '<div data-item-timer="' + i + '" style="font-size:12px;color:#8B9DAF;font-family:\'SF Mono\',SFMono-Regular,ui-monospace,monospace">' + formatRundownTimer(state.currentItem.elapsedSeconds) + '</div>';
          }
        } else if (item.status === 'upcoming' && item.lengthSeconds > 0) {
          // Upcoming items: show estimated countdown from now to their estimated start + duration
          var itemEndMs = item.estimatedStartMs + (item.lengthSeconds * 1000);
          var secsUntilEnd = Math.max(0, Math.round((itemEndMs - now) / 1000));
          html += '<div data-item-timer="' + i + '" style="font-size:12px;color:#556270;font-family:\'SF Mono\',SFMono-Regular,ui-monospace,monospace">' + formatRundownTimer(item.lengthSeconds) + '</div>';
          // Show estimated start time offset
          var secsUntilStart = Math.max(0, Math.round((item.estimatedStartMs - now) / 1000));
          if (secsUntilStart > 0) {
            html += '<div style="font-size:10px;color:#556270">in ' + formatRundownDuration(secsUntilStart) + '</div>';
          }
        } else if (item.lengthSeconds > 0) {
          html += '<div style="font-size:12px;color:#556270">' + formatRundownTimer(item.lengthSeconds) + '</div>';
        }
        html += '</div>';

        // Companion actions gear icon
        var hasActions = _companionActionsCache[item.id] && _companionActionsCache[item.id].length > 0;
        var gearColor = hasActions ? '#00E676' : '#556270';
        var gearTitle = hasActions ? 'Edit Companion actions (' + _companionActionsCache[item.id].length + ')' : 'Configure Companion actions';
        var safeItemId = item.id.replace(/'/g, "\\'");
        var safeTitle = item.title.replace(/'/g, "\\'");
        html += '<button data-action="openCompanionActionsModal" data-item-id="' + safeItemId + '" data-item-title="' + safeTitle + '" title="' + gearTitle + '" style="flex-shrink:0;margin-left:6px;background:none;border:none;cursor:pointer;padding:4px;color:' + gearColor + ';opacity:0.8;line-height:0">';
        html += SVG.gear;
        html += '</button>';

        html += '</div>';
      }
      container.innerHTML = html;

      // Auto-scroll to current item
      if (state.currentIndex >= 0 && _rundownLiveTracking) {
        var currentEl = container.querySelector('[data-rundown-idx="' + state.currentIndex + '"]');
        if (currentEl) {
          currentEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
      }
    }

    function formatRundownTimer(seconds) {
      if (seconds == null || seconds < 0) seconds = 0;
      var m = Math.floor(seconds / 60);
      var s = seconds % 60;
      return String(m).padStart(2, '0') + ':' + String(s).padStart(2, '0');
    }

    function formatRundownDuration(seconds) {
      if (seconds < 60) return seconds + 's';
      var m = Math.floor(seconds / 60);
      var s = seconds % 60;
      return s > 0 ? m + 'm ' + s + 's' : m + 'm';
    }

    function updateRundownProgressBar(state) {
      var bar = document.getElementById('rundown-progress-bar');
      if (!bar) return;
      var totalItems = state.totalItems || 1;
      // Count completed items + fractional progress on current
      var completedCount = 0;
      var items = state.items || [];
      for (var i = 0; i < items.length; i++) {
        if (items[i].status === 'completed') completedCount++;
      }
      // Add partial progress for current item
      var ci = state.currentItem;
      var currentFraction = 0;
      if (ci && ci.lengthSeconds > 0) {
        currentFraction = Math.min(1, (ci.elapsedSeconds || 0) / ci.lengthSeconds);
      } else if (ci) {
        currentFraction = 0.5; // No duration: show half-way
      }
      var pct = Math.min(100, ((completedCount + currentFraction) / totalItems) * 100);
      bar.style.width = pct + '%';
    }

    function updateAutoAdvanceToggle(state) {
      var toggle = document.getElementById('rundown-auto-advance-toggle');
      if (!toggle) return;
      var knob = toggle.firstElementChild;
      if (state.autoAdvance) {
        toggle.style.background = 'rgba(0,230,118,0.3)';
        if (knob) { knob.style.left = '18px'; knob.style.background = '#00E676'; }
      } else {
        toggle.style.background = 'rgba(255,255,255,0.1)';
        if (knob) { knob.style.left = '2px'; knob.style.background = '#556270'; }
      }
      // Auto-advanced notice
      var notice = document.getElementById('rundown-auto-advanced-notice');
      if (notice && state.autoAdvancedFrom) {
        notice.style.display = '';
        notice.textContent = 'Auto-advanced from: ' + state.autoAdvancedFrom;
        // Fade out after 5 seconds
        clearTimeout(notice._fadeTimer);
        notice._fadeTimer = setTimeout(function() { notice.style.display = 'none'; }, 5000);
      }
    }

    // Global function for toggle handler (also handled via data-action delegation)
    window.toggleAutoAdvance = function() {
      if (!_rundownState) return;
      var newVal = !_rundownState.autoAdvance;
      var roomId = _rundownState.roomId || '';
      api('POST', '/api/churches/' + CHURCH_ID + '/live-rundown/auto-advance', { enabled: newVal, roomId: roomId }).then(function(data) {
        if (data) {
          _rundownState = data;
          updateAutoAdvanceToggle(data);
        }
      });
    };

    function renderRundownTeam(team) {
      var panel = document.getElementById('rundown-team-panel');
      var list = document.getElementById('rundown-team-list');
      if (!panel || !list) return;
      if (!team || team.length === 0) { panel.style.display = 'none'; return; }
      panel.style.display = '';

      // Group by team name
      var groups = {};
      for (var i = 0; i < team.length; i++) {
        var m = team[i];
        var group = m.teamName || 'Other';
        if (!groups[group]) groups[group] = [];
        groups[group].push(m);
      }

      var html = '';
      var groupNames = Object.keys(groups);
      for (var g = 0; g < groupNames.length; g++) {
        var gName = groupNames[g];
        var members = groups[gName];
        html += '<div style="margin-bottom:8px">';
        html += '<div style="font-size:11px;color:#556270;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px">' + escapeHtml(gName) + '</div>';
        for (var j = 0; j < members.length; j++) {
          var member = members[j];
          var statusColor = member.status === 'C' ? '#00E676' : member.status === 'D' ? '#FF5252' : '#556270';
          html += '<div style="display:flex;align-items:center;gap:6px;padding:3px 0">';
          html += '<div style="width:6px;height:6px;border-radius:50%;background:' + statusColor + ';flex-shrink:0"></div>';
          html += '<span style="font-size:13px;color:#B0BEC5">' + escapeHtml(member.name) + '</span>';
          if (member.position) {
            html += '<span style="font-size:11px;color:#556270">' + escapeHtml(member.position) + '</span>';
          }
          html += '</div>';
        }
        html += '</div>';
      }
      list.innerHTML = html;
    }

    // Handle rundown WebSocket messages from SSE stream
    function handleRundownSSE(data) {
      var msgRoomId = data.roomId || '';
      var myRoomId = _selectedRoomId || '';

      if (data.type === 'rundown_state' || data.type === 'rundown_position') {
        // Track all room sessions
        _rundownStatsByRoom[msgRoomId] = data;
        // Only update UI if this is our room
        if (msgRoomId === myRoomId) {
          _rundownState = data;
          // Load companion actions cache when a new plan session starts
          if (data.planId && data.planId !== _companionActionsPlanId) {
            loadCompanionActionsCache(data.planId);
          }
          if (document.getElementById('page-rundown').classList.contains('active')) {
            showRundownView('active');
            renderRundownActive(data);
          }
        }
        // Update sidebar indicator — show if any room is live
        var indicator = document.getElementById('td-session-indicator');
        if (indicator) {
          var liveCount = Object.keys(_rundownStatsByRoom).length;
          if (liveCount > 1) {
            indicator.style.display = '';
            indicator.textContent = 'LIVE: ' + liveCount + ' rooms';
          } else {
            indicator.style.display = '';
            indicator.textContent = 'LIVE: ' + (data.planTitle || 'Rundown');
          }
        }
      } else if (data.type === 'companion_action_result') {
        if (msgRoomId !== myRoomId) return;
        // Show a brief toast indicating whether actions succeeded
        var allOk = Array.isArray(data.results) && data.results.every(function(r) { return r.success; });
        var failCount = Array.isArray(data.results) ? data.results.filter(function(r) { return !r.success; }).length : 0;
        if (!allOk && failCount > 0) {
          toast('Companion: ' + failCount + ' action(s) failed', true);
        }
      } else if (data.type === 'rundown_tick') {
        if (msgRoomId !== myRoomId) return;
        if (!_rundownState) return;
        // Patch current state with tick data
        if (_rundownState.currentItem) {
          _rundownState.currentItem.elapsedSeconds = data.elapsedSeconds;
          _rundownState.currentItem.remainingSeconds = data.remainingSeconds;
          _rundownState.currentItem.isOvertime = data.isOvertime;
          _rundownState.currentItem.overtimeSeconds = data.overtimeSeconds;
          _rundownState.currentItem.isWarning = data.isWarning;
        }
        _rundownState.scheduleDelta = data.scheduleDelta;
        _rundownState.totalElapsed = data.totalElapsed;
        if (data.isPaused !== undefined) _rundownState.isPaused = data.isPaused;
        if (data.autoAdvance !== undefined) _rundownState.autoAdvance = data.autoAdvance;
        if (data.autoAdvancedFrom) _rundownState.autoAdvancedFrom = data.autoAdvancedFrom;
        if (document.getElementById('page-rundown').classList.contains('active')) {
          // Only update timer + delta, not full re-render (performance)
          updateRundownTimerOnly(_rundownState);
        }
      } else if (data.type === 'rundown_ended') {
        // Remove from tracked sessions
        delete _rundownStatsByRoom[msgRoomId];
        if (msgRoomId === myRoomId) {
          _rundownState = null;
          if (document.getElementById('page-rundown').classList.contains('active')) {
            renderRundownInactive();
          }
        }
        var indicator = document.getElementById('td-session-indicator');
        var remainingLive = Object.keys(_rundownStatsByRoom).length;
        if (indicator) {
          if (remainingLive === 0) {
            indicator.style.display = 'none';
          } else if (remainingLive === 1) {
            var lastState = _rundownStatsByRoom[Object.keys(_rundownStatsByRoom)[0]];
            indicator.textContent = 'LIVE: ' + (lastState.planTitle || 'Rundown');
          } else {
            indicator.textContent = 'LIVE: ' + remainingLive + ' rooms';
          }
        }
      }
    }

    function updateRundownTimerOnly(state) {
      var ci = state.currentItem;
      var timerEl = document.getElementById('rundown-timer');
      var timerLabel = document.getElementById('rundown-timer-label');
      var heroEl = document.getElementById('rundown-countdown-hero');
      var elapsedEl = document.getElementById('rundown-elapsed');
      if (elapsedEl) elapsedEl.textContent = formatRundownDuration(state.totalElapsed || 0) + ' elapsed';
      if (ci && ci.remainingSeconds !== null && ci.remainingSeconds !== undefined) {
        if (ci.isOvertime) {
          if (timerEl) { timerEl.textContent = '+' + formatRundownTimer(ci.overtimeSeconds); timerEl.style.color = '#FF5252'; }
          if (timerLabel) timerLabel.textContent = 'OVERTIME';
          if (heroEl) heroEl.style.borderColor = 'rgba(239,68,68,0.4)';
        } else if (ci.isWarning) {
          if (timerEl) { timerEl.textContent = formatRundownTimer(ci.remainingSeconds); timerEl.style.color = '#FFA726'; }
          if (timerLabel) timerLabel.textContent = 'REMAINING';
          if (heroEl) heroEl.style.borderColor = 'rgba(255,167,38,0.4)';
        } else {
          if (timerEl) { timerEl.textContent = formatRundownTimer(ci.remainingSeconds); timerEl.style.color = '#00E676'; }
          if (timerLabel) timerLabel.textContent = 'REMAINING';
          if (heroEl) heroEl.style.borderColor = '';
        }
      } else {
        if (timerEl) { timerEl.textContent = formatRundownTimer(ci ? ci.elapsedSeconds : 0); timerEl.style.color = '#8B9DAF'; }
        if (timerLabel) timerLabel.textContent = 'ELAPSED';
        if (heroEl) heroEl.style.borderColor = '';
      }

      // Update per-item timer for the current item (DOM patch, no full re-render)
      if (ci && state.currentIndex !== undefined) {
        var itemTimer = document.querySelector('[data-item-timer="' + state.currentIndex + '"]');
        if (itemTimer) {
          if (ci.remainingSeconds !== null && ci.remainingSeconds !== undefined) {
            var timerColor = ci.isOvertime ? '#FF5252' : ci.isWarning ? '#FFA726' : '#00E676';
            var timerText = ci.isOvertime ? '+' + formatRundownTimer(ci.overtimeSeconds) : formatRundownTimer(ci.remainingSeconds);
            itemTimer.textContent = timerText;
            itemTimer.style.color = timerColor;
          } else {
            itemTimer.textContent = formatRundownTimer(ci.elapsedSeconds);
          }
        }
      }

      // Mini timer in controls bar
      var miniTimer = document.getElementById('rundown-mini-timer');
      if (miniTimer && ci) {
        if (ci.remainingSeconds !== null && ci.remainingSeconds !== undefined) {
          if (ci.isOvertime) {
            miniTimer.textContent = '+' + formatRundownTimer(ci.overtimeSeconds);
            miniTimer.style.color = '#FF5252';
          } else if (ci.isWarning) {
            miniTimer.textContent = formatRundownTimer(ci.remainingSeconds);
            miniTimer.style.color = '#FFA726';
          } else {
            miniTimer.textContent = formatRundownTimer(ci.remainingSeconds);
            miniTimer.style.color = '#00E676';
          }
        } else {
          miniTimer.textContent = formatRundownTimer(ci.elapsedSeconds);
          miniTimer.style.color = '#8B9DAF';
        }
      }

      // Progress bar
      updateRundownProgressBar(state);

      // Schedule delta — enhanced severity
      var deltaEl = document.getElementById('rundown-schedule-delta');
      if (deltaEl && state.scheduleDelta) {
        deltaEl.style.display = '';
        var absSec = Math.abs(state.scheduleDelta.seconds);
        var deltaMin = Math.round(absSec / 60);
        if (state.scheduleDelta.isOnTime) {
          deltaEl.textContent = 'On Time';
          deltaEl.style.background = 'rgba(0,230,118,0.1)'; deltaEl.style.color = '#00E676';
        } else if (state.scheduleDelta.isAhead) {
          deltaEl.textContent = '+' + deltaMin + ' min ahead';
          deltaEl.style.background = 'rgba(33,150,243,0.1)'; deltaEl.style.color = '#42A5F5';
        } else if (absSec < 120) {
          deltaEl.textContent = '-' + deltaMin + ' min behind';
          deltaEl.style.background = 'rgba(255,183,77,0.1)'; deltaEl.style.color = '#FFB74D';
        } else {
          deltaEl.textContent = '-' + deltaMin + ' min behind';
          deltaEl.style.background = 'rgba(239,68,68,0.1)'; deltaEl.style.color = '#FF5252';
        }
      }

      // Auto-advance state from tick
      if (state.autoAdvancedFrom) {
        updateAutoAdvanceToggle(state);
      }
    }

    // ── Companion Actions Modal ───────────────────────────────────────────────
    var _companionModalItemId = null;
    var _companionModalItemTitle = null;
    // Working copy of actions being edited in the modal (array of action objects)
    var _companionModalActions = [];

    function openCompanionActionsModal(itemId, itemTitle) {
      _companionModalItemId = itemId;
      _companionModalItemTitle = itemTitle;
      // Clone current cached actions for this item (or start empty)
      _companionModalActions = JSON.parse(JSON.stringify((_companionActionsCache[itemId] || [])));

      var modal = document.getElementById('companion-actions-modal');
      var titleEl = document.getElementById('companion-modal-item-title');
      if (titleEl) titleEl.textContent = itemTitle;
      renderCompanionActionsList();
      if (modal) { modal.style.display = 'flex'; }
    }

    function closeCompanionActionsModal() {
      var modal = document.getElementById('companion-actions-modal');
      if (modal) modal.style.display = 'none';
      _companionModalItemId = null;
      _companionModalActions = [];
    }

    function renderCompanionActionsList() {
      var container = document.getElementById('companion-actions-list');
      if (!container) return;
      if (!_companionModalActions.length) {
        container.innerHTML = '<div style="text-align:center;padding:16px;color:#556270;font-size:13px">No actions configured. Click "+ Add Action" to add one.</div>';
        return;
      }
      var html = '';
      for (var i = 0; i < _companionModalActions.length; i++) {
        var a = _companionModalActions[i];
        html += '<div style="background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);border-radius:8px;padding:12px" data-action-index="' + i + '">';
        // Action type selector
        html += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:10px">';
        html += '<select onchange="companionActionChangeType(' + i + ',this.value)" style="flex:1;padding:6px 8px;background:#0D1117;border:1px solid rgba(255,255,255,0.12);border-radius:6px;color:#F0F2F4;font-size:13px">';
        html += '<option value="button_press"' + (a.type === 'button_press' ? ' selected' : '') + '>Button Press</option>';
        html += '<option value="custom_variable"' + (a.type === 'custom_variable' ? ' selected' : '') + '>Custom Variable</option>';
        html += '</select>';
        html += '<button data-action="companionActionRemove" data-action-index="' + i + '" title="Remove action" style="background:none;border:none;cursor:pointer;color:#FF5252;padding:4px;line-height:0">';
        html += '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" fill="currentColor" width="14" height="14"><path d="M5.28 4.22a.75.75 0 0 0-1.06 1.06L6.94 8l-2.72 2.72a.75.75 0 1 0 1.06 1.06L8 9.06l2.72 2.72a.75.75 0 1 0 1.06-1.06L9.06 8l2.72-2.72a.75.75 0 0 0-1.06-1.06L8 6.94 5.28 4.22Z"/></svg>';
        html += '</button>';
        html += '</div>';

        if (a.type === 'button_press') {
          html += '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px">';
          html += '<label style="font-size:11px;color:#8B9DAF">Page<input type="number" min="1" max="99" value="' + (a.page || 1) + '" onchange="companionActionField(' + i + ',\'page\',+this.value)" style="display:block;margin-top:4px;width:100%;padding:5px 8px;background:#0D1117;border:1px solid rgba(255,255,255,0.12);border-radius:6px;color:#F0F2F4;font-size:13px;box-sizing:border-box"></label>';
          html += '<label style="font-size:11px;color:#8B9DAF">Row<input type="number" min="0" max="99" value="' + (a.row != null ? a.row : 0) + '" onchange="companionActionField(' + i + ',\'row\',+this.value)" style="display:block;margin-top:4px;width:100%;padding:5px 8px;background:#0D1117;border:1px solid rgba(255,255,255,0.12);border-radius:6px;color:#F0F2F4;font-size:13px;box-sizing:border-box"></label>';
          html += '<label style="font-size:11px;color:#8B9DAF">Column<input type="number" min="0" max="99" value="' + (a.col != null ? a.col : 0) + '" onchange="companionActionField(' + i + ',\'col\',+this.value)" style="display:block;margin-top:4px;width:100%;padding:5px 8px;background:#0D1117;border:1px solid rgba(255,255,255,0.12);border-radius:6px;color:#F0F2F4;font-size:13px;box-sizing:border-box"></label>';
          html += '</div>';
          html += '<label style="font-size:11px;color:#8B9DAF;display:block;margin-top:8px">Label (optional)<input type="text" value="' + escapeHtml(a.label || '') + '" placeholder="e.g. Cam 1 Wide" onchange="companionActionField(' + i + ',\'label\',this.value)" style="display:block;margin-top:4px;width:100%;padding:5px 8px;background:#0D1117;border:1px solid rgba(255,255,255,0.12);border-radius:6px;color:#F0F2F4;font-size:13px;box-sizing:border-box"></label>';
        } else if (a.type === 'custom_variable') {
          html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">';
          html += '<label style="font-size:11px;color:#8B9DAF">Variable Name<input type="text" value="' + escapeHtml(a.name || '') + '" placeholder="e.g. current_item" onchange="companionActionField(' + i + ',\'name\',this.value)" style="display:block;margin-top:4px;width:100%;padding:5px 8px;background:#0D1117;border:1px solid rgba(255,255,255,0.12);border-radius:6px;color:#F0F2F4;font-size:13px;box-sizing:border-box"></label>';
          html += '<label style="font-size:11px;color:#8B9DAF">Value<input type="text" value="' + escapeHtml(a.value || '') + '" placeholder="e.g. Welcome" onchange="companionActionField(' + i + ',\'value\',this.value)" style="display:block;margin-top:4px;width:100%;padding:5px 8px;background:#0D1117;border:1px solid rgba(255,255,255,0.12);border-radius:6px;color:#F0F2F4;font-size:13px;box-sizing:border-box"></label>';
          html += '</div>';
        }
        html += '</div>';
      }
      container.innerHTML = html;
    }

    // Called from inline onchange handlers in the modal
    window.companionActionChangeType = function(index, type) {
      if (type === 'button_press') {
        _companionModalActions[index] = { type: 'button_press', page: 1, row: 0, col: 0, label: '' };
      } else {
        _companionModalActions[index] = { type: 'custom_variable', name: '', value: '' };
      }
      renderCompanionActionsList();
    };
    window.companionActionField = function(index, field, value) {
      if (_companionModalActions[index]) _companionModalActions[index][field] = value;
    };
    window.companionActionRemove = function(index) {
      _companionModalActions.splice(index, 1);
      renderCompanionActionsList();
    };
    window.openCompanionActionsModal = openCompanionActionsModal;

    document.getElementById('companion-add-action') && document.getElementById('companion-add-action').addEventListener('click', function() {
      _companionModalActions.push({ type: 'button_press', page: 1, row: 0, col: 0, label: '' });
      renderCompanionActionsList();
    });

    document.getElementById('companion-modal-close') && document.getElementById('companion-modal-close').addEventListener('click', closeCompanionActionsModal);
    document.getElementById('companion-modal-cancel') && document.getElementById('companion-modal-cancel').addEventListener('click', closeCompanionActionsModal);

    document.getElementById('companion-modal-save') && document.getElementById('companion-modal-save').addEventListener('click', function() {
      if (!_companionModalItemId || !_companionActionsPlanId) return;
      var saveBtn = document.getElementById('companion-modal-save');
      saveBtn.disabled = true;
      saveBtn.textContent = 'Saving…';

      var endpoint = '/api/churches/' + CHURCH_ID + '/live-rundown/actions/' +
        encodeURIComponent(_companionActionsPlanId) + '/' + encodeURIComponent(_companionModalItemId);

      if (_companionModalActions.length === 0) {
        api('DELETE', endpoint).then(function() {
          _companionActionsCache[_companionModalItemId] = [];
          closeCompanionActionsModal();
          toast('Companion actions cleared');
          if (_rundownState && document.getElementById('page-rundown').classList.contains('active')) {
            renderRundownItems(_rundownState);
          }
        }).catch(function() {
          toast('Failed to clear actions', true);
        }).finally(function() {
          saveBtn.disabled = false; saveBtn.textContent = 'Save Actions';
        });
      } else {
        api('PUT', endpoint, { actions: _companionModalActions }).then(function() {
          _companionActionsCache[_companionModalItemId] = JSON.parse(JSON.stringify(_companionModalActions));
          closeCompanionActionsModal();
          toast('Companion actions saved');
          if (_rundownState && document.getElementById('page-rundown').classList.contains('active')) {
            renderRundownItems(_rundownState);
          }
        }).catch(function(e) {
          toast('Failed to save: ' + (e && e.message ? e.message : 'error'), true);
        }).finally(function() {
          saveBtn.disabled = false; saveBtn.textContent = 'Save Actions';
        });
      }
    });

    // Close modal when clicking the backdrop
    document.getElementById('companion-actions-modal') && document.getElementById('companion-actions-modal').addEventListener('click', function(e) {
      if (e.target === this) closeCompanionActionsModal();
    });

    // ── Real-time status push via SSE ─────────────────────────────────────────
    // Connect to the server-sent event stream for this church. Live status
    // updates patch overview cards directly so we avoid re-fetching the full
    // portal profile on every device heartbeat.
    (function initPortalStatusStream() {
      var es;
      var reconnectDelay = 3000;

      function connect() {
        if (es) { try { es.close(); } catch {} }
        es = new EventSource('/api/church/stream');

        es.onmessage = function(event) {
          try {
            var data = JSON.parse(event.data);
            if (data.type === 'status_update' || data.type === 'status_snapshot' || data.type === 'connected') {
              // Resolve per-room status using instanceStatus + roomInstanceMap
              var effectiveStatus = data.status;
              var isConnected = data.type === 'connected';
              if (data.instanceStatus && data.roomInstanceMap && _selectedRoomId) {
                var instanceName = data.roomInstanceMap[_selectedRoomId];
                if (instanceName && data.instanceStatus[instanceName]) {
                  effectiveStatus = data.instanceStatus[instanceName];
                  isConnected = true;
                } else {
                  effectiveStatus = { _offline: true };
                  isConnected = false;
                }
              }
              if (effectiveStatus) {
                // Update the status dot on the connection stat card
                var dot = document.getElementById('stat-status-dot');
                var txt = document.getElementById('stat-status-text');
                if (dot && txt) {
                  if (!isConnected) {
                    isConnected = !effectiveStatus._offline && !!(effectiveStatus.connected !== false && (
                      effectiveStatus.atem || effectiveStatus.obs || effectiveStatus.encoder || effectiveStatus.vmix ||
                      effectiveStatus.mixer || effectiveStatus.proPresenter || effectiveStatus.companion
                    ));
                  }
                  dot.style.background = isConnected ? '#00E676' : '#556270';
                  txt.textContent = isConnected ? 'Connected' : 'Offline';
                }
                // Pulse the equipment staleness indicator
                var stale = document.getElementById('equip-staleness');
                if (stale) {
                  stale.textContent = 'Live';
                  stale.style.color = '#00E676';
                }
                // Update lightweight overview cards from SSE without forcing
                // another full /api/church/me load.
                if (document.getElementById('page-overview').classList.contains('active')) {
                  applyOverviewLiveData({
                    connected: isConnected,
                    status: effectiveStatus,
                    lastSeen: data.lastSeen || data.timestamp || null,
                    broadcastHealth: data.broadcastHealth,
                    audio_via_atem: profileData && profileData.audio_via_atem,
                  });
                }
              }
            } else if (data.type === 'instance_disconnected') {
              // Per-room disconnect: if the disconnected room is our selected room, show offline
              if (data.roomIds && data.roomIds.indexOf(_selectedRoomId) !== -1) {
                var dot3 = document.getElementById('stat-status-dot');
                var txt3 = document.getElementById('stat-status-text');
                if (dot3 && txt3) { dot3.style.background = '#556270'; txt3.textContent = 'Offline'; }
              }
            } else if (data.type === 'pco:connected' || data.type === 'pco:disconnected') {
              loadPcoStatus();
            } else if (data.type === 'stream_protection_status') {
              updateStreamProtectionUI(data.streamProtection);
            } else if (data.type === 'viewer_update') {
              var card = document.getElementById('live-viewers-card');
              if (card && data.total !== undefined) {
                card.style.display = '';
                document.getElementById('live-viewers-total').textContent = data.total.toLocaleString();
                var bd = data.breakdown || {};
                var parts = [];
                if (bd.youtube !== undefined) parts.push('<span style="color:#ff0000">YT: ' + bd.youtube + '</span>');
                if (bd.facebook !== undefined) parts.push('<span style="color:#1877f2">FB: ' + bd.facebook + '</span>');
                if (bd.vimeo !== undefined) parts.push('<span style="color:#1ab7ea">Vim: ' + bd.vimeo + '</span>');
                document.getElementById('live-viewers-breakdown').innerHTML = parts.join(' ');
                // Sparkline: append a bar
                var spark = document.getElementById('live-viewers-sparkline');
                if (spark) {
                  if (!window._viewerSparkData) window._viewerSparkData = [];
                  window._viewerSparkData.push(data.total);
                  if (window._viewerSparkData.length > 30) window._viewerSparkData.shift();
                  var max = Math.max.apply(null, window._viewerSparkData) || 1;
                  spark.innerHTML = window._viewerSparkData.map(function(v) {
                    var h = Math.max(2, Math.round((v / max) * 36));
                    return '<div style="flex:1;height:' + h + 'px;background:#00E676;border-radius:2px;min-width:2px"></div>';
                  }).join('');
                }
              }
            } else if (data.type && (data.type.indexOf('rundown_') === 0 || data.type === 'companion_action_result')) {
              // Route collaboration messages separately from live session messages
              if (data.type === 'rundown_item_updated' || data.type === 'rundown_item_added' ||
                  data.type === 'rundown_item_deleted' || data.type === 'rundown_item_reordered' ||
                  data.type === 'rundown_plan_updated' || data.type === 'rundown_presence') {
                handleRundownCollaboration(data);
              } else {
                handleRundownSSE(data);
              }
            } else if (data.type === 'disconnected') {
              var dot2 = document.getElementById('stat-status-dot');
              var txt2 = document.getElementById('stat-status-text');
              if (dot2 && txt2) { dot2.style.background = '#556270'; txt2.textContent = 'Offline'; }
            }
          } catch {}
          reconnectDelay = 3000; // reset backoff on successful message
        };

        es.onerror = function() {
          es.close();
          // Exponential backoff up to 30s
          setTimeout(connect, reconnectDelay);
          reconnectDelay = Math.min(reconnectDelay * 2, 30000);
        };
      }

      connect();

      // Close stream on page hide to avoid zombie SSE connections
      document.addEventListener('visibilitychange', function() {
        if (document.hidden) {
          if (es) { try { es.close(); } catch {} es = null; }
        } else {
          connect();
        }
      });
    })();

// Human-readable label for alert types (used across scopes)
function _portalFriendlyAlertType(alertType) {
  var map = {
    'stream_stopped': 'Stream stopped',
    'atem_disconnected': 'ATEM switcher disconnected',
    'multiple_systems_down': 'Multiple systems went down',
    'recording_failed': 'Recording failed to start',
    'recording_not_started': 'Recording not started',
    'audio_muted': 'Audio is muted',
    'audio_silence': 'No audio signal detected',
    'failover_executed': 'Backup system activated',
    'failover_command_failed': 'Backup system failed to activate',
    'no_td_response': 'No response from tech director',
    'encoder_stream_stopped': 'Encoder stream stopped',
    'atem_stream_stopped': 'ATEM stream stopped',
    'vmix_stream_stopped': 'vMix stream stopped',
    'obs_disconnected': 'OBS disconnected',
    'encoder_disconnected': 'Encoder disconnected',
    'vmix_disconnected': 'vMix disconnected',
    'connection_lost': 'Device connection lost'
  };
  return map[alertType] || (alertType || '').replace(/_/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
}

// ── Commands page ─────────────────────────────────────────────────────────────
var _commandsLoaded = false;
var loadCommandsPage; // assigned inside DOMContentLoaded; callable from showPage
var loadAiTriagePage; // assigned inside DOMContentLoaded; callable from showPage
var loadReports, loadReportsSummary, loadReportsEvents, loadReportsWindows, loadReportsHealth, loadReportsAi;

// ── PHASE 5: Calendar View ──────────────────────────────────────────────────
var _calendarMode = 'week'; // 'week' | 'month'
var _calendarDate = new Date(); // anchor date for navigation

function _calWeekStart(d) {
  var r = new Date(d); r.setDate(r.getDate() - r.getDay() + 1); // Monday
  r.setHours(0,0,0,0); return r;
}

function _calFmt(d) {
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}

function _calMonthName(d) {
  var months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  return months[d.getMonth()] + ' ' + d.getFullYear();
}

function rundownViewList() {
  _setDashboardView('list');
}
function rundownViewCalendar() {
  _setDashboardView('calendar');
}
function _setDashboardView(view) {
  var dash = document.getElementById('rundown-dashboard');
  var cal = document.getElementById('rundown-calendar-view');
  if (dash) dash.style.display = view === 'list' ? '' : 'none';
  if (cal) cal.style.display = view === 'calendar' ? '' : 'none';
  document.querySelectorAll('.rundown-view-btn').forEach(function(b) {
    b.classList.toggle('active', b.dataset.action === 'rundownView' + view.charAt(0).toUpperCase() + view.slice(1));
  });
  if (view === 'calendar') renderRundownCalendar();
}

function renderRundownCalendar() {
  var container = document.getElementById('rundown-calendar-view');
  if (!container) return;
  var plans = _rundownPlans || [];
  var today = _calFmt(new Date());

  // Build plan index by date
  var plansByDate = {};
  for (var i = 0; i < plans.length; i++) {
    var sd = plans[i].serviceDate;
    if (!sd) continue;
    if (!plansByDate[sd]) plansByDate[sd] = [];
    plansByDate[sd].push(plans[i]);
  }

  var html = '<div class="rundown-calendar-nav">';
  html += '<button data-action="rundownCalPrev" aria-label="Previous">&lsaquo;</button>';
  html += '<button data-action="rundownCalToday">Today</button>';
  html += '<button data-action="rundownCalNext" aria-label="Next">&rsaquo;</button>';

  if (_calendarMode === 'week') {
    var ws = _calWeekStart(_calendarDate);
    var we = new Date(ws); we.setDate(we.getDate() + 6);
    html += '<span class="cal-title">' + _calFmt(ws) + ' &mdash; ' + _calFmt(we) + '</span>';
  } else {
    html += '<span class="cal-title">' + _calMonthName(_calendarDate) + '</span>';
  }

  html += '<div class="rundown-calendar-mode">';
  html += '<button data-action="rundownCalModeWeek"' + (_calendarMode === 'week' ? ' class="active"' : '') + '>Week</button>';
  html += '<button data-action="rundownCalModeMonth"' + (_calendarMode === 'month' ? ' class="active"' : '') + '>Month</button>';
  html += '</div></div>';

  // Day headers
  var dayNames = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
  html += '<div class="rundown-cal-grid' + (_calendarMode === 'month' ? ' rundown-cal-month' : '') + '">';
  for (var d = 0; d < 7; d++) {
    html += '<div class="rundown-cal-header">' + dayNames[d] + '</div>';
  }

  // Generate cells
  var cells = [];
  if (_calendarMode === 'week') {
    var start = _calWeekStart(_calendarDate);
    for (var c = 0; c < 7; c++) {
      var cd = new Date(start); cd.setDate(cd.getDate() + c);
      cells.push({ date: cd, inMonth: true });
    }
  } else {
    var first = new Date(_calendarDate.getFullYear(), _calendarDate.getMonth(), 1);
    var startDay = (first.getDay() + 6) % 7; // Monday=0
    var gridStart = new Date(first); gridStart.setDate(gridStart.getDate() - startDay);
    for (var c = 0; c < 42; c++) {
      var cd = new Date(gridStart); cd.setDate(cd.getDate() + c);
      cells.push({ date: cd, inMonth: cd.getMonth() === _calendarDate.getMonth() });
    }
  }

  for (var c = 0; c < cells.length; c++) {
    var cell = cells[c];
    var dateStr = _calFmt(cell.date);
    var isToday = dateStr === today;
    var cls = 'rundown-cal-cell';
    if (isToday) cls += ' today';
    if (!cell.inMonth) cls += ' other-month';
    html += '<div class="' + cls + '" data-action="rundownCalDateClick" data-date="' + dateStr + '">';
    html += '<div class="rundown-cal-date">' + cell.date.getDate() + '</div>';
    var dp = plansByDate[dateStr] || [];
    for (var p = 0; p < dp.length && p < 4; p++) {
      html += '<div class="rundown-cal-plan status-' + (dp[p].status || 'draft') + '" data-action="rundownSelectPlan" data-plan-id="' + dp[p].id + '" data-plan-source="' + (dp[p].source || 'manual') + '" title="' + escapeHtml(dp[p].title) + '">' + escapeHtml(dp[p].title) + '</div>';
    }
    if (dp.length > 4) html += '<div style="font-size:10px;color:#556270">+' + (dp.length - 4) + ' more</div>';
    html += '<span class="rundown-cal-add" data-action="rundownCalNewOnDate" data-date="' + dateStr + '" title="New plan on ' + dateStr + '">+</span>';
    html += '</div>';
  }
  html += '</div>';
  container.innerHTML = html;
}

function rundownCalPrev() {
  if (_calendarMode === 'week') {
    _calendarDate.setDate(_calendarDate.getDate() - 7);
  } else {
    _calendarDate.setMonth(_calendarDate.getMonth() - 1);
  }
  renderRundownCalendar();
}
function rundownCalNext() {
  if (_calendarMode === 'week') {
    _calendarDate.setDate(_calendarDate.getDate() + 7);
  } else {
    _calendarDate.setMonth(_calendarDate.getMonth() + 1);
  }
  renderRundownCalendar();
}
function rundownCalToday() {
  _calendarDate = new Date();
  renderRundownCalendar();
}
function rundownCalModeWeek() {
  _calendarMode = 'week';
  renderRundownCalendar();
}
function rundownCalModeMonth() {
  _calendarMode = 'month';
  renderRundownCalendar();
}
function rundownCalDateClick(dateStr) {
  // Show plans for this date in a simple list or switch to list view filtered
  _rundownSearchQuery = '';
  var search = document.getElementById('rundown-search');
  if (search) search.value = dateStr;
  _rundownSearchQuery = dateStr;
  _setDashboardView('list');
  renderRundownDashboard();
}
function rundownCalNewOnDate(dateStr) {
  // Create a new plan pre-filled with this date
  var title = prompt('Plan title for ' + dateStr + ':');
  if (!title || !title.trim()) return;
  api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans', { title: title.trim(), serviceDate: dateStr, roomId: _selectedRoomId || '' }).then(function(plan) {
    toast('Plan created');
    loadRundownManager();
  }).catch(function(e) { toast(e.message, true); });
}
function rundownCalCopyToDate(planId) {
  var targetDate = prompt('Copy plan to date (YYYY-MM-DD):');
  if (!targetDate || !/^\d{4}-\d{2}-\d{2}$/.test(targetDate)) return;
  // Find the plan, duplicate it
  var plan = _rundownPlans.find(function(p) { return p.id === planId; });
  if (!plan) return;
  api('POST', '/api/churches/' + CHURCH_ID + '/rundown-plans', { title: plan.title + ' (copy)', serviceDate: targetDate, roomId: plan.roomId || '' }).then(function(newPlan) {
    toast('Plan copied to ' + targetDate);
    loadRundownManager();
  }).catch(function(e) { toast(e.message, true); });
}

// ── PHASE 5: Offline Mode enhancements ──────────────────────────────────────
// (Offline mode is primarily handled by the service worker. Here we add
//  connection monitoring and offline banner to the portal.)
var _offlineMode = false;
var _offlineBannerEl = null;

function _initOfflineMonitor() {
  // Create offline banner (hidden by default)
  _offlineBannerEl = document.createElement('div');
  _offlineBannerEl.id = 'offline-banner';
  _offlineBannerEl.setAttribute('role', 'alert');
  _offlineBannerEl.setAttribute('aria-live', 'assertive');
  _offlineBannerEl.style.cssText = 'display:none;position:fixed;top:0;left:0;right:0;z-index:9998;background:#FFB74D;color:#1a1a2e;text-align:center;padding:8px 16px;font-size:13px;font-weight:700;';
  _offlineBannerEl.textContent = 'Offline Mode — Running on cached data';
  document.body.appendChild(_offlineBannerEl);

  window.addEventListener('online', function() {
    _offlineMode = false;
    if (_offlineBannerEl) _offlineBannerEl.style.display = 'none';
  });
  window.addEventListener('offline', function() {
    _offlineMode = true;
    if (_offlineBannerEl) _offlineBannerEl.style.display = '';
  });

  // Register service worker if available
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.register('/rundown-sw.js').catch(function() {});
  }
}

// ── PHASE 5: Accessibility helpers ──────────────────────────────────────────
function _initAccessibility() {
  // Add aria-live region for timer announcements
  var liveRegion = document.createElement('div');
  liveRegion.id = 'rundown-sr-announcer';
  liveRegion.setAttribute('aria-live', 'polite');
  liveRegion.setAttribute('aria-atomic', 'true');
  liveRegion.className = 'sr-only';
  liveRegion.style.cssText = 'position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);border:0';
  document.body.appendChild(liveRegion);

  // Add ARIA roles to key containers
  var toolbar = document.querySelector('.rundown-toolbar');
  if (toolbar) toolbar.setAttribute('role', 'toolbar');
  var dashboard = document.getElementById('rundown-dashboard');
  if (dashboard) dashboard.setAttribute('role', 'list');

  // Ensure all buttons in toolbars have accessible names
  document.querySelectorAll('.rundown-toolbar button:not([aria-label]):not([title])').forEach(function(btn) {
    if (btn.textContent.trim()) btn.setAttribute('aria-label', btn.textContent.trim());
  });

  // Add aria-hidden to decorative SVGs that don't already have it
  document.querySelectorAll('svg:not([aria-label]):not([role])').forEach(function(svg) {
    if (!svg.getAttribute('aria-hidden')) svg.setAttribute('aria-hidden', 'true');
  });
}

// Initialize Phase 5 features on DOMContentLoaded
(function() {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function() {
      _initOfflineMonitor();
      _initAccessibility();
    });
  } else {
    _initOfflineMonitor();
    _initAccessibility();
  }
})();

